  const SW_TARGETS = [
    { sel: '[data-window="win-career"]', line: ["zzz… 47 merged PRs… all mine… well. hers…", "zzz… 47 PR fusionnées… toutes à moi… enfin. à elle…"], scene: swSceneCareer },
    { sel: '[data-window="win-skills"]', line: ["zzz… Python level five… so shiny…", "zzz… Python niveau cinq… ça brille…"], scene: swSceneSkills },
    { sel: '[data-window="win-ama"]', line: ["zzz… ask the bot… it knows… everything about her…", "zzz… demande au bot… il sait… tout sur elle…"], scene: swSceneAma },
    { sel: '[data-window="win-terminal"]', line: ["zzz… sudo… hire… yongshan…", "zzz… sudo… hire… yongshan…"], scene: swSceneTerminal },
    { sel: '#chip-fanwall', line: ["zzz… so many fans… need… more fans…", "zzz… tant de fans… il en faut… plus…"], scene: swSceneFanwall },
    { sel: '[data-window="win-education"]', line: ["zzz… top five percent… of dreams…", "zzz… top cinq pour cent… des rêves…"], scene: swSceneEducation },
    { sel: '#address-form', line: ["zzz… gotta google… something urgent…", "zzz… je dois googler… un truc urgent…"], scene: swSceneSearch },
    { sel: '[data-window="win-pikdex"]', line: ["zzz… roll call… tiny friends…", "zzz… à l'appel… petits amis…"], scene: swScenePikdex }
  ];
  const SW_GAME_LINE = ["zzz… I hear… an arcade… must… participate…", "zzz… j'entends… une borne d'arcade… je dois… participer…"];

  function swVisible(el) {
    if (!el) return false;
    const r = el.getBoundingClientRect();
    return r.width > 0 && r.top > 0 && r.bottom < window.innerHeight;
  }

  /* ---- v102: the NIGHT DESK ----
     a visitor who has never run the arcade IN THE DARK gets the
     nightmare express: after 15 active seconds of dark mode the slime
     sleepwalks over and opens the arcade itself (the first dark run
     then detonates into THE NIGHTMARE at second ten — see gBeginRun).
     after that the night keeps house rhythm: first-time visitors serve
     the 6:59 curfew and then dream; returning visitors are walked into
     a random deep dream at the 2-minute mark, no paperwork. */
  var swForceGame = false;   // one-shot: the next walk aims at the arcade, dice waived
  // v113: deep dreams keep their distance — after ANY dream world visit,
  // AUTO entries wait 15 ACTIVE minutes (parked tabs don't serve time;
  // the `dream <name>` command remains a free door — explicit wish wins)
  // v126: fifteen-minute cooldown — clamp any legacy hour-long ledger on
  // sight AND heal it in storage so returning visitors aren't stuck waiting
  var dreamAcdLeft = Math.min(store.get('yos-dream-acd', 0), 15 * 60 * 1000);
  store.set('yos-dream-acd', dreamAcdLeft);
  var swExpressDive = false; // the express dive auto-presses START on landing
  var nightDarkMs = 0;       // ACTIVE ms spent in the dark (parked tabs don't count)
  var nightStayMs = 0;       // ACTIVE ms this visit, any theme
  var nightExpressFired = false;
  var nightDreamDone = false;
  const NIGHT_RETURNING = !!store.get('yos-return', null);
  store.set('yos-return', 1); // from now on, this browser is family

  function nightExpressFire() {
    if (nightExpressFired) return;
    if (store.get('yos-played-dark', null)) { nightExpressFired = true; return; }
    const gw = document.getElementById('win-game');
    if (gw && !gw.classList.contains('window-closed')) { nightExpressFired = true; return; } // found it themselves
    if (dreamWorld || sleepwalkActive) return; // busy stage — try again next tick
    swForceGame = true;
    swExpressDive = true;
    try { startSleepwalk(); } finally { swForceGame = false; }
    // only a walk that actually left the bed counts as a departure
    if (sleepwalkActive) nightExpressFired = true;
    else swExpressDive = false;
  }
  setInterval(() => {
    if (document.body.classList.contains('terminal-only')) return;
    if (typeof swVisitorEngaged === 'function' && !swVisitorEngaged()) return;
    nightStayMs += 5000;
    if (dreamAcdLeft > 0 && !dreamWorld) { dreamAcdLeft = Math.max(0, dreamAcdLeft - 5000); store.set('yos-dream-acd', dreamAcdLeft); }
    if (resolvedTheme() !== 'dark') return;
    nightDarkMs += 5000;
    // the express: 15 active dark seconds, once, for dark-arcade first-timers
    if (nightDarkMs >= 15000 && !nightExpressFired && !store.get('yos-played-dark', null)) nightExpressFire();
    // the 2-minute dream: returning visitors skip the queue (and the curfew);
    // first-timers only board if no curfew is running (the curfew pipeline
    // delivers their dream with ceremony instead)
    if (nightStayMs >= 120000 && !nightDreamDone && !dreamWorld && !sleepwalkActive
        && dreamAcdLeft <= 0 && !gameActive() && window.innerWidth >= 560) {
      if (swCurfewOn()) {
        if (!NIGHT_RETURNING) return; // let the curfew flow deliver it
        swCurfewLeft = 0; swLiftDone = true; // regulars ride past the checkpoint, quietly
        store.set('yos-sw-curfew-left', 0);
      }
      nightDreamDone = true;
      store.set('yos-dream-cd', 0);
      try { startDreamWalk(); } catch (e) { nightDreamDone = false; }
    }
  }, 5000);

  function startSleepwalk() {
    if (document.body.classList.contains('terminal-only')) return; // the door hates popups
    // sleepwalks also launch from a maximized live room: a sleeping
    // streamer on stage is still a sleeping streamer
    const asleepOnStage = typeof liveOpen !== 'undefined' && liveOpen && pet.sleeping;
    if (sleepwalkActive || resolvedTheme() !== 'dark' || !(ghostHidden() || asleepOnStage)) return;
    // choose destination: 85% the arcade, else a random visible feature —
    // and if a run is already underway, it's the arcade, PERIOD (dark-mode
    // sleepwalks must never yank the player out of their game)
    const gwOpen = (() => { const w = document.getElementById('win-game'); return w && !w.classList.contains('window-closed'); })();
    let target, line, isGame = false, directDive = false, scene = null;
    if (gwOpen) {
      // the game is ALREADY running: no button detours — the dreamer
      // waddles straight to the canvas and dives in as a game entity
      // (legal even under curfew: a dive is a gift, not an ambush —
      // the visitor opened the arcade themselves)
      target = document.getElementById('game-canvas');
      line = SW_GAME_LINE;
      isGame = true;
      directDive = true;
    } else if (!swForceGame && dreamWorldEligible() && Math.random() < 0.9) {
      // v6.6: post-curfew walks are 90% DEEP DREAMS — the whole site
      // becomes the dream. the remaining 10% keeps the on-site mischief
      // (terminal typing, AMA questions, sticky notes…) in rotation
      startDreamWalk();
      return;
    } else if (swForceGame || Math.random() < swGameChance()) {
      target = document.getElementById('chip-game');
      line = SW_GAME_LINE;
      isGame = true;
    } else {
      const options = SW_TARGETS.filter((t) => swVisible(document.querySelector(t.sel)));
      if (!options.length) {
        // nowhere else to haunt. under curfew, gremlin hour or journal
        // rules the walk is politely cancelled — the arcade fallback
        // would break a promise
        if (swCurfewOn() || swTricksterOn() || swAverse) return;
        target = document.getElementById('chip-game'); line = SW_GAME_LINE; isGame = true;
      } else {
        const pickT = options[Math.floor(Math.random() * options.length)];
        target = document.querySelector(pickT.sel); line = pickT.line; scene = pickT.scene || null;
      }
    }
    if (!swVisible(target)) return;
    sleepwalkActive = true;
    achvUnlock('dreamwatcher');

    const habitatRect = (typeof liveOpen !== 'undefined' && liveOpen && slimeBody)
      ? slimeBody.getBoundingClientRect()
      : slimeHabitat.getBoundingClientRect();
    swEl = document.createElement('div');
    swEl.className = 'sleepwalker';
    swEl.setAttribute('aria-hidden', 'true');
    const img = document.createElement('img');
    img.src = (OUTFIT_FRAMES && typeof OUTFIT_FRAMES.sleep === 'string' && OUTFIT_FRAMES.sleep) || 'assets/slime_night_sleep.png'; // current fit, eyes closed (canvas-mode frames can't feed an <img>)
    img.alt = '';
    const bub = document.createElement('div');
    bub.className = 'sw-bubble';
    swEl.appendChild(img);
    swEl.appendChild(bub);
    document.body.appendChild(swEl);
    swMakeTicklish(swEl);

    const from = { x: habitatRect.left + habitatRect.width / 2 - 36, y: habitatRect.top + habitatRect.height / 2 - 32 };
    const tr = target.getBoundingClientRect();
    const to = { x: tr.left + tr.width / 2 - 36, y: Math.max(8, tr.top - 46) };
    swEl.style.left = from.x + 'px';
    swEl.style.top = from.y + 'px';

    bub.textContent = trT(...line);
    swEl.classList.add('sw-talking');
    playTone(262, 'sine', 0.4, 0, 0.03);

    // time-based glide (background-tab safe)
    const t0 = Date.now();
    const walkMs = 3600;
    let tick = 0;
    const el = swEl; // identity badge: if swEl is nulled OR replaced, this walk is over
    const glide = setInterval(() => {
      // woken mid-walk (cancelSleepwalk) or upstaged (a new walk took the
      // sprite var): stop driving — untended, this throws every 40ms and
      // clearInterval is never reached
      if (swEl !== el) { clearInterval(glide); return; }
      const p = Math.min(1, (Date.now() - t0) / walkMs);
      const ease = p * p * (3 - 2 * p);
      swEl.style.left = (from.x + (to.x - from.x) * ease) + 'px';
      swEl.style.top = (from.y + (to.y - from.y) * ease + Math.sin(p * 14) * 5) + 'px';
      // v5.2: a breadcrumb trail of 💤 marks where the dream has been
      if ((tick++ & 7) === 0) swTrailDot(parseFloat(swEl.style.left) + 50 + (Math.random() - 0.5) * 14, parseFloat(swEl.style.top) + 42);
      if (p >= 1) {
        clearInterval(glide);
        swArrive(target, isGame, directDive, scene);
      }
    }, 40);
  }

  // the two anonymous curtain-call timeouts, now on the books: a walk
  // cancelled (or upstaged by the dream ritual) must take them along,
  // or a stale swFinish fires mid-ritual and fades the NEW walker
  var swLingerTimer = null, swDiveTimer = null;
  function swArrive(target, isGame, directDive, scene) {
    // the sleepwalker "clicks" the feature open, still fast asleep —
    // unless it's already open (direct dives skip the doorbell)
    if (!directDive) { try { target.click(); } catch { /* dream logic */ } }
    playTone(392, 'sine', 0.25, 0, 0.04);

    if (isGame && !directDive) {
      // v5.2: an ambush just landed — the arcade goes on dream curfew,
      // and if this was the post-curfew probation ambush, closing the
      // window without playing counts as the visitor's answer
      swStartCurfew();
      if (swPostCurfew) { swPostCurfew = false; swRejectUntil = Date.now() + 25000; }
    }

    if (isGame) {
      // dive into the canvas and transmute into a power-up
      swDiveTimer = setTimeout(() => {
        const cv = document.getElementById('game-canvas');
        const cr = cv ? cv.getBoundingClientRect() : null;
        if (cr && swEl) {
          const from = { x: parseFloat(swEl.style.left), y: parseFloat(swEl.style.top) };
          const to = { x: cr.left + cr.width * 0.3, y: cr.top + cr.height * 0.4 };
          const t0 = Date.now();
          const el = swEl;
          const dive = setInterval(() => {
            if (swEl !== el) { clearInterval(dive); return; } // woken or upstaged mid-dive
            const p = Math.min(1, (Date.now() - t0) / 1400);
            swEl.style.left = (from.x + (to.x - from.x) * p) + 'px';
            swEl.style.top = (from.y + (to.y - from.y) * p) + 'px';
            swEl.style.transform = `scale(${1 - p * 0.6}) rotate(${p * 340}deg)`;
            if (p >= 1) {
              clearInterval(dive);
              gSleepwalkerBlessing();
              swFinish(true);
            }
          }, 40);
        } else { swFinish(false); }
      }, 900);
    } else {
      // v5.2: linger, perform this destination's act (the terminal gets
      // typed into, the bot gets a question…), then dissolve back to bed.
      // scenes may return their own curtain time (the AMA show runs long)
      let hold = scene ? 5600 : 3600;
      if (scene) { try { const h = scene(target); if (typeof h === 'number' && h > 0) hold = h; } catch (e) { /* dream logic */ } }
      // v6.2: the gremlin's merch table grew — sticky notes, crayon
      // graffiti, or the room quietly leaning 0.35° (it will deny it)
      const bonus = Math.random();
      if (bonus < 0.22) { try { swStickyNote(target); } catch (e) { /* glue failure */ } }
      else if (bonus < 0.38) { try { swGraffiti(target); } catch (e) { /* crayon failure */ } }
      else if (bonus < 0.45 && !REDUCED_MOTION && !document.body.classList.contains('sw-tilt')) {
        document.body.classList.add('sw-tilt');
        setTimeout(() => showBubble(trT('…did the room just lean? no? cool. cool cool cool.', '…la pièce vient de pencher, non ? non ? cool. très très cool.'), 4200, true), 2600);
        setTimeout(() => document.body.classList.remove('sw-tilt'), 25000);
      }
      swLingerTimer = setTimeout(() => swFinish(false), hold);
    }
  }

  function swFinish(dove) {
    if (swEl) {
      swEl.classList.add('sw-fading');
      const el = swEl;
      setTimeout(() => el.remove(), 700);
      swEl = null;
    }
    if (dove) playSparkleSound();
    // it wanders back into bed off-screen; sleep continues
    setTimeout(() => {
      sleepwalkActive = false;
      // v6.0: gremlin hour never sleeps twice — walks chain back-to-back
      // until the 7 minutes run dry (deep dreams pause the parade)
      if (swTricksterOn() && resolvedTheme() === 'dark' && ghostHidden() && !dreamActive()) {
        if (sleepwalkTimer) clearTimeout(sleepwalkTimer);
        sleepwalkTimer = setTimeout(() => startSleepwalk(), 2200 + Math.random() * 2400);
      }
    }, 1200);
  }

  function cancelSleepwalk() {
    if (sleepwalkTimer) clearTimeout(sleepwalkTimer);
    if (swLingerTimer) { clearTimeout(swLingerTimer); swLingerTimer = null; }
    if (swDiveTimer) { clearTimeout(swDiveTimer); swDiveTimer = null; }
    if (swEl) { swEl.remove(); swEl = null; }
    sleepwalkActive = false;
  }

  /* =====================================================
     v6.0 — DREAM WORLDS 🌌
     sometimes the dream refuses to stay inside the slime.
     the sleepwalker waddles to the middle of the desktop,
     spins once, and the ENTIRE SITE falls into its dream:
     seven full themed realities (win95, SCP, the slimetrix,
     dream boy, a 1998 homepage, the blue dream of death,
     and a 1970s mainframe), each 10–15 minutes long, each
     narrated from bed with a live countdown, each poppable
     by knocking on the habitat. reload-proof. reversible.
     the slime remembers none of it. the visitor remembers
     all of it.
     ===================================================== */
  var dreamWorld = null;   // { id, w, until, total, timers, nodes, flags }
  var dreamEnding = false;

  function dreamActive() { return !!dreamWorld; }

  function dreamWorldEligible() {
    return !dreamWorld
      && dreamAcdLeft <= 0                                  // 15 ACTIVE minutes between dream worlds
      && resolvedTheme() === 'dark'
      && !document.body.classList.contains('terminal-only') // the door is sacred
      && !swCurfewOn()                                      // curfew = quiet dreams, promised
      && Date.now() >= store.get('yos-dream-cd', 0)         // one takeover per while
      && !gameActive()                                      // never repaint mid-run
      && window.innerWidth >= 560;                          // phones get walks, not furniture
  }

  // ---- dream bookkeeping: every timer and node signs the guestbook ----
  function dT(fn, ms) { const t = setTimeout(fn, ms); if (dreamWorld) dreamWorld.timers.push(t); return t; }
  function dI(fn, ms) { const t = setInterval(fn, ms); if (dreamWorld) dreamWorld.timers.push(t); return t; }
  function dN(el) { if (dreamWorld) dreamWorld.nodes.push(el); return el; }
  function dreamSay(pair, dur) { showBubble(trT(...pair), dur || 3600, true); }
  function dreamMinLeft() { return dreamWorld ? Math.max(1, Math.ceil((dreamWorld.until - Date.now()) / 60000)) : 0; }

  // ---- the dream's own soundtrack (synthesized, like everything here) ----
  function playDreamChime95() { // four soft rising sines — a certain 1995 sunrise, from memory
    [311.13, 466.16, 622.25, 830.61].forEach((f, i) => playTone(f, 'sine', 1.6, i * 0.18, 0.05));
    playTone(1244.51, 'triangle', 0.9, 0.78, 0.035);
  }
  function playDreamAlarm() { [196, 155.56, 196, 155.56].forEach((f, i) => playTone(f, 'sawtooth', 0.42, i * 0.45, 0.04)); }
  function playDreamGB() { playTone(1046.5, 'square', 0.08, 0, 0.05); playTone(2093, 'square', 0.5, 0.12, 0.055); }
  function playDreamSad() { [392, 330, 262].forEach((f, i) => playTone(f, 'sine', 0.5, i * 0.3, 0.05)); }
  function playDreamModem() { // a 56k handshake, abridged and polite
    [1209, 1477, 1209, 941].forEach((f, i) => playTone(f, 'square', 0.12, i * 0.14, 0.026));
    for (let i = 0; i < 8; i++) playTone(700 + Math.random() * 1400, 'sawtooth', 0.05, 0.6 + i * 0.07, 0.018);
    playTone(392, 'sine', 0.5, 1.35, 0.03);
  }
  function playDreamHum() { playTone(110, 'sine', 1.6, 0, 0.035); playTone(220, 'sine', 1.2, 0.3, 0.02); playTone(440, 'sine', 0.5, 1.2, 0.02); }
  function playDreamPop() { playTone(880, 'triangle', 0.08, 0, 0.06); playTone(1318.51, 'triangle', 0.14, 0.07, 0.05); }
  function playDreamPrinter() { for (let i = 0; i < 10; i++) playTone(1800 + (i % 3) * 220, 'square', 0.03, i * 0.055, 0.016); }

  // ---- shared stage furniture ----
  function dreamBadgeRail() {
    let rail = document.getElementById('dream-badges');
    if (!rail) {
      rail = document.createElement('div');
      rail.id = 'dream-badges';
      rail.setAttribute('aria-hidden', 'true');
      document.body.appendChild(rail);
      dN(rail);
    }
    return rail;
  }
  function dreamBadge(text, cls) {
    const b = document.createElement('div');
    b.className = 'dream-badge' + (cls ? ' ' + cls : '');
    b.textContent = text;
    dreamBadgeRail().appendChild(b);
    return b;
  }

  // a classic dialog box, dream-flavored. buttons: [label, cb, keepOpen]
  function dreamDlg(optsOrBuild) {
    if (!dreamWorld) return null;
    // geo showtime: while the repair ballet plays, the stage is CLOSED —
    // no dialog of any kind may interrupt the crew (owner decree v153)
    if (dreamWorld.flags.geoShowtime) return null;
    // v126: pass a BUILDER (() => ({...opts})) and the dialog becomes
    // live-translatable — the builder re-runs its trT calls on a language
    // toggle and the OPEN dialog re-inks itself in place (owner decree:
    // dream popups follow the language switch WITHOUT closing). plain-opts
    // callers still work unchanged.
    const build = typeof optsOrBuild === 'function' ? optsOrBuild : null;
    const opts = build ? build() : optsOrBuild;
    if (!opts.force && (document.querySelectorAll('.dream-dlg').length >= 2 || document.querySelector('.dwc-win') || document.querySelector('.dwm-win'))) return null; // clutter law (the card table counts as a full house)
    const d = document.createElement('div');
    d.className = 'dream-dlg' + (opts.cls ? ' ' + opts.cls : '');
    d.setAttribute('role', 'dialog');
    const bar = document.createElement('div');
    bar.className = 'dream-dlg-bar';
    const tt = document.createElement('span');
    tt.textContent = opts.title || 'dream.exe';
    const xx = document.createElement('button');
    xx.type = 'button';
    xx.className = 'dream-dlg-x';
    xx.textContent = '✕';
    xx.addEventListener('click', () => { playCloseSound(); if (opts.onX) { opts.onX(d); } else d.remove(); });
    bar.appendChild(tt); bar.appendChild(xx);
    d.appendChild(bar);
    const body = document.createElement('div');
    body.className = 'dream-dlg-body';
    (opts.lines || []).forEach((ln) => {
      const p = document.createElement('p');
      p.textContent = ln;
      body.appendChild(p);
    });
    d.appendChild(body);
    if (opts.buttons && opts.buttons.length) {
      const row = document.createElement('div');
      row.className = 'dream-dlg-row';
      opts.buttons.forEach((btn) => {
        const b = document.createElement('button');
        b.type = 'button';
        b.className = 'dream-dlg-btn';
        b.textContent = btn[0];
        b.addEventListener('click', () => { if (btn[1]) btn[1](d); if (!btn[2]) d.remove(); });
        row.appendChild(b);
      });
      d.appendChild(row);
    }
    if (build) {
      d.__rebuild = () => {
        try {
          // a handler that rewrote the dialog mid-scene (BUG battle HP,
          // the dodged send button, the granted-bar ceremony…) sets
          // d.__dirty — replaying the opening script over live state
          // would reset the scene, so a dirty dialog keeps its ink
          if (d.__dirty) return;
          const fresh = build(); // trT re-resolves in the CURRENT language
          tt.textContent = fresh.title || 'dream.exe';
          const ps = body.querySelectorAll('p');
          (fresh.lines || []).forEach((ln, i) => { if (ps[i]) ps[i].textContent = ln; });
          const bs = d.querySelectorAll('.dream-dlg-row .dream-dlg-btn');
          (fresh.buttons || []).forEach((btn, i) => { if (bs[i]) bs[i].textContent = btn[0]; });
        } catch (e) { /* a dialog that can't re-ink keeps its old ink */ }
      };
    }
    const W = Math.min(300, window.innerWidth - 40);
    const x = opts.x != null ? opts.x : 20 + Math.random() * Math.max(40, window.innerWidth - W - 60);
    const y = opts.y != null ? opts.y : 80 + Math.random() * Math.max(40, window.innerHeight * 0.5 - 80);
    d.style.left = Math.round(x) + 'px';
    d.style.top = Math.round(y) + 'px';
    document.body.appendChild(d);
    dN(d);
    return d;
  }

  // a critter crossing the screen (slime cameos, rabbits, punch cards…)
  function dreamCritter(opts) {
    if (!dreamWorld || REDUCED_MOTION) return null;
    const c = document.createElement('div');
    c.className = 'dream-critter' + (opts.cls ? ' ' + opts.cls : '');
    if (opts.img) {
      const im = document.createElement('img');
      im.src = opts.img; im.alt = '';
      c.appendChild(im);
    } else if (opts.emoji) {
      const sp = document.createElement('span');
      sp.className = 'dream-critter-emoji';
      sp.textContent = opts.emoji;
      c.appendChild(sp);
    }
    if (opts.bubble) {
      const bb = document.createElement('div');
      bb.className = 'dream-critter-bubble';
      bb.textContent = trT(...opts.bubble);
      c.appendChild(bb);
    }
    if (opts.label) {
      const lb = document.createElement('div');
      lb.className = 'dream-critter-label';
      lb.textContent = trT(...opts.label);
      c.appendChild(lb);
    }
    const ltr = opts.dir !== 'rtl';
    const y = opts.y != null ? opts.y : window.innerHeight - 150 - Math.random() * 90;
    const x0 = ltr ? -90 : window.innerWidth + 90;
    const x1 = ltr ? window.innerWidth + 90 : -90;
    c.style.top = y + 'px';
    c.style.left = x0 + 'px';
    if (!ltr) c.classList.add('dream-critter-flip');
    if (opts.onClick) {
      c.classList.add('dream-critter-hot');
      c.addEventListener('click', (e) => {
        e.stopPropagation();
        // reactions speak through the bubble — five of six critter spawns
        // pass only a label, so their click lines were silently swallowed.
        // build it on demand; if the handler stays quiet, it self-removes.
        let bb = c.querySelector('.dream-critter-bubble');
        if (!bb) {
          bb = document.createElement('div');
          bb.className = 'dream-critter-bubble';
          c.appendChild(bb);
        }
        opts.onClick(c);
        if (!bb.textContent) bb.remove();
      }, { once: true });
    }
    document.body.appendChild(c);
    dN(c);
    const ms = opts.ms || 14000;
    const t0 = Date.now();
    const iv = dI(() => {
      const p = Math.min(1, (Date.now() - t0) / ms);
      c.style.left = (x0 + (x1 - x0) * p) + 'px';
      if (opts.hop) c.style.top = (y - Math.abs(Math.sin(p * Math.PI * (opts.hop))) * 26) + 'px';
      if (p >= 1) { clearInterval(iv); c.remove(); }
    }, 40);
    return c;
  }

  // the entry flash: one frame of pure dream static, then the new reality
  function dreamFlashIn(w) {
    if (REDUCED_MOTION) return;
    const f = document.createElement('div');
    f.className = 'dream-flash ' + w.cls + '-flash';
    const label = document.createElement('div');
    label.className = 'dream-flash-label';
    label.textContent = w.icon + ' ' + trT(...w.name);
    f.appendChild(label);
    document.body.appendChild(f);
    setTimeout(() => f.remove(), 2100);
  }

