  function dreamShellRun(cmd) {
    if (!dreamWorld) return false;
    const sh = DREAM_SHELL[dreamWorld.id];
    if (!sh) return false;
    const c = sh.cmds[cmd];
    if (!c && (cmd === 'help' || cmd === 'man' || cmd === 'hint' || cmd === 'cheats' || cmd === 'secrets' || cmd === '?')) {
      const h = DS_HELP[dreamWorld.id];
      if (h) dsL(h[0], h[1], 't-accent');
      try { sh.cmds[sh.list].fx(); } catch (e) { /* the catalog jammed */ }
      return true;
    }
    if (!c) { dreamShellDeny(sh, cmd); return true; }
    const first = dsMark(dreamWorld.id, cmd);
    try { c.fx(first); } catch (e) { dsL('…the dream stuttered. say it again.', '…le rêve a bégayé. redis-le.', 't-err'); }
    // v108: the dream NOTICES repetition — run the same word again and the
    // world reacts differently each time, escalating (2nd/3rd/4th+ tiers).
    // the counter lives in localStorage now, not the dream session: nobody
    // types one word 4 times in a single dream, but return visitors climb
    // the ladder naturally, night after night (1998 quietly keeps a cookie)
    try {
      const runsBag = store.get('yos-dream-runs', {});
      const runs = (runsBag[dreamWorld.id] = runsBag[dreamWorld.id] || {});
      runs[cmd] = Math.min(9, (runs[cmd] || 0) + 1);
      store.set('yos-dream-runs', runsBag);
      if (runs[cmd] >= 2) {
        const bank = DS_REPEATS[dreamWorld.id] && DS_REPEATS[dreamWorld.id][cmd];
        if (bank && bank.length) {
          let tier = runs[cmd] - 2;
          if (tier > bank.length - 1) {
            // past the ladder: shuffle the deep tiers, never the same twice
            const last = (dreamWorld.flags.dsLastTier = dreamWorld.flags.dsLastTier || {})[cmd];
            tier = 1 + Math.floor(Math.random() * (bank.length - 1));
            if (tier === last) tier = 1 + (tier % (bank.length - 1));
            dreamWorld.flags.dsLastTier[cmd] = tier;
          }
          const ln = bank[tier];
          setTimeout(() => { if (dreamWorld) dsL(ln[0], ln[1], tier >= 2 ? 't-accent' : 't-dim'); }, 480);
          playTone(280 + Math.min(runs[cmd], 7) * 70, 'square', 0.05, 0, 0.03);
        }
      }
    } catch (e) { /* the echo got lost */ }
    // v85: doing the thing gets it into the dream journal, instantly
    try {
      const dmap = DREAMLOG_CMDMAP[dreamWorld.id];
      if (dmap && dmap[cmd]) dreamlogAdd(dreamWorld.id, dmap[cmd]);
    } catch (e) { /* the journal blinked */ }
    return true;
  }

  // ---- the terminal's own dream onset: a typed banner, per world ----
  // opening the shell mid-dream greets you with a typewriter scene that
  // explains the house rules (the old commands sleep; `help` guides you)
  function dsTypeSeq(lines, opts) {
    const o = opts || {};
    if (REDUCED_MOTION) { lines.forEach((ln) => termLine(trT(ln.t[0], ln.t[1]), ln.cls || 't-accent')); return; }
    let li = 0;
    const nextLine = () => {
      if (!dreamWorld || !termOut) return;
      if (li >= lines.length) return;
      const ln = lines[li++];
      const el = document.createElement('span');
      el.className = 't-line ' + (ln.cls || 't-accent');
      termOut.appendChild(el);
      while (termOut.children.length > 350) termOut.removeChild(termOut.firstChild);
      const text = trT(ln.t[0], ln.t[1]);
      let i = 0;
      const iv = dI(() => {
        if (!el.isConnected) { clearInterval(iv); return; }
        el.textContent += text[i];
        if (i % 4 === 0) playTone((o.freq || 1500) + Math.random() * 200, o.wave || 'square', 0.012, 0, 0.01);
        termOut.scrollTop = termOut.scrollHeight;
        if (++i >= text.length) { clearInterval(iv); dT(nextLine, 260); }
      }, o.ms || 18);
    };
    nextLine();
  }
