  function dreamlogAvail(world) {
    if (!dreamWorld || dreamWorld.id !== world) return 0;
    const elapsed = Math.max(0, dreamWorld.total - (dreamWorld.until - Date.now()));
    return Math.min(DREAMLOG_CATALOG[world].length, 2 + Math.floor(elapsed / 40000));
  }
  function dreamlogAdd(world, id, quiet) {
    const cat = DREAMLOG_CATALOG[world];
    if (!cat) return;
    const m = cat.find((x) => x.id === id);
    if (!m) return;
    const bag = store.get('yos-dreamlog', {});
    bag[world] = bag[world] || {};
    if (bag[world][id]) return;
    bag[world][id] = Date.now();
    store.set('yos-dreamlog', bag);
    if (!quiet) {
      playSparkleSound();
      // full line, marqueed — no more mid-word "contents: f…" cliffhangers
      showToast('📔 ' + trT('logged: ', 'consigné : ') + m.e + ' ' + trT(m.t[0], m.t[1]), { scroll: true });
    }
    const n = cat.filter((x) => bag[world][x.id]).length;
    if (n >= cat.length) {
      achvUnlock('dreamscribe');
      cheatFall(['📔', '✦', '♡'], 14);
      playFanfare();
      const total = Object.keys(DREAMLOG_CATALOG).every((w) => {
        const b = bag[w] || {};
        return DREAMLOG_CATALOG[w].every((x) => b[x.id]);
      });
      if (total) achvUnlock('dreamtome');
    }
    dreamlogRender();
  }
  // each world collects with its own gesture — this builds the row for
  // an entry that is AVAILABLE but not yet caught/declassified/taped/etc.
  function dreamlogAvailRow(wid, row, m) {
    const txt = trT(m.t[0], m.t[1]);
    if (wid === 'win95') {
      row.innerHTML = '<span class="dl-e">▮</span><span class="dl-t">' + trT('UNTITLED — unsaved changes (press F5 below)', 'SANS TITRE — modifications non enregistrées (F5 ci-dessous)') + '</span>';
    } else if (wid === 'scp') {
      row.innerHTML = '<span class="dl-e">▓</span><span class="dl-t dl-bars">████ ██████ ███ ██████████ ████</span><button type="button" class="dl-btn">' + trT('DECLASSIFY', 'DÉCLASSIFIER') + '</button>';
      row.querySelector('.dl-btn').addEventListener('click', () => {
        playTone(78, 'sawtooth', 0.14, 0, 0.08);
        row.classList.add('dl-reveal');
        row.querySelector('.dl-t').textContent = txt;
        dT(() => dreamlogAdd(wid, m.id), 600);
      });
    } else if (wid === 'matrix') {
      const t = document.createElement('span');
      t.className = 'dl-t dl-scramble';
      row.innerHTML = '<span class="dl-e">▓</span>';
      row.appendChild(t);
      const CH = 'ｱｲｳｴｵ01♡$#%&*';
      const iv = dI(() => {
        if (!t.isConnected) { clearInterval(iv); return; }
        t.textContent = txt.split('').map((c) => (c === ' ' || Math.random() < 0.22) ? c : CH[Math.floor(Math.random() * CH.length)]).join('');
      }, 90);
      row.addEventListener('click', () => {
        if (row.classList.contains('dl-focusing')) return;
        row.classList.add('dl-focusing');
        playTone(300, 'sine', 0.4, 0, 0.04);
        dT(() => { clearInterval(iv); t.textContent = txt; swSparkleAt(row.getBoundingClientRect().left + 30, row.getBoundingClientRect().top + 8, 3); dreamlogAdd(wid, m.id); }, 1000);
      });
    } else if (wid === 'geo') {
      row.innerHTML = '<span class="dl-e">✎</span><span class="dl-t dl-geo-soon">' + trT('a dream resident is walking up the driveway…', 'un habitant du rêve remonte l\'allée…') + '</span>';
    } else if (wid === 'bsod') {
      row.innerHTML = '<span class="dl-e">:(</span><span class="dl-t">' + m.id + '.dmp — ' + trT('integrity 23%', 'intégrité 23 %') + '</span><button type="button" class="dl-btn">' + trT('REPAIR', 'RÉPARER') + '</button><span class="dl-repairbar"><i></i></span>';
      row.querySelector('.dl-btn').addEventListener('click', () => {
        if (row.classList.contains('dl-repairing')) return;
        row.classList.add('dl-repairing');
        playTone(520, 'triangle', 0.2, 0, 0.04);
        dT(() => dreamlogAdd(wid, m.id), 1400);
      });
    } else if (wid === 'amber') {
      row.classList.add('dl-slip');
      row.innerHTML = '<span class="dl-e">🖨</span><span class="dl-t">' + trT('a slip pokes out of the printer — click to tape it in', 'un bordereau dépasse de l\'imprimante — clique pour le scotcher') + '</span>';
      row.addEventListener('click', () => {
        if (row.classList.contains('dl-taping')) return;
        row.classList.add('dl-taping');
        playDreamPrinter();
        dT(() => dreamlogAdd(wid, m.id), 700);
      });
    }
  }

  /* ==================================================================
     v104: the BONUS CARTRIDGE 🎮 — dex complete? the tall grass grows
     an arcade. 35 WarioWare-sized microgames on a strict 4-green DMG
     screen, one random cartridge per visit ([▶] shuffles, [A] replays).
     wins collect on a shelf; all 35 crowns you DREAM BOY CHAMPION.
     ================================================================== */
  const AR_G = ['#0f380f', '#306230', '#8bac0f', '#9bbc0f']; // the only four colors in this cathedral
  const AR_W = 160, AR_H = 96;
  var arGlyphCache = {};
  // any emoji, quantized onto the DMG palette (dark ink on light field)
  function arGlyph(glyph, size) {
    const key = glyph + '/' + size;
    if (arGlyphCache[key]) return arGlyphCache[key];
    const c = document.createElement('canvas');
    c.width = size; c.height = size;
    const x = c.getContext('2d');
    x.font = Math.round(size * 0.9) + "px 'Segoe UI Emoji', 'Apple Color Emoji', 'Jersey 25', monospace";
    x.textAlign = 'center';
    x.textBaseline = 'middle';
    x.fillStyle = AR_G[0];
    x.fillText(glyph, size / 2, size / 2 + 1);
    try {
      const d = x.getImageData(0, 0, size, size);
      const px = d.data;
      for (let i = 0; i < px.length; i += 4) {
        if (px[i + 3] < 60) { px[i + 3] = 0; continue; }
        const t = (0.2126 * px[i] + 0.7152 * px[i + 1] + 0.0722 * px[i + 2]) / 255;
        const g = AR_G[Math.min(2, Math.round(t * 3))]; // sprites keep to the 3 darker greens
        px[i] = parseInt(g.slice(1, 3), 16); px[i + 1] = parseInt(g.slice(3, 5), 16); px[i + 2] = parseInt(g.slice(5, 7), 16);
        px[i + 3] = 255;
      }
      x.putImageData(d, 0, 0);
    } catch (e) { /* tainted? the raw glyph still reads */ }
    arGlyphCache[key] = c;
    return c;
  }
  function arDrawGlyph(g2, glyph, cx, cy, size) {
    g2.drawImage(arGlyph(glyph, size || 14), Math.round(cx - (size || 14) / 2), Math.round(cy - (size || 14) / 2));
  }
  function arText(g2, txt, x, y, shade, size) {
    g2.fillStyle = AR_G[shade == null ? 0 : shade];
    g2.font = (size || 8) + "px 'Jersey 25', 'VT323', monospace";
    g2.fillText(txt, x, y);
  }
  // word-wrap for the tiny screen: long prompts used to run off the bezel
  function arTextWrap(g2, txt, x, y, shade, size, maxW, lineH) {
    g2.fillStyle = AR_G[shade == null ? 0 : shade];
    g2.font = (size || 8) + "px 'Jersey 25', 'VT323', monospace";
    const words = String(txt).split(' ');
    let line = '', yy = y;
    words.forEach((w) => {
      const probe = line ? line + ' ' + w : w;
      if (g2.measureText(probe).width > (maxW || 140) && line) {
        g2.fillText(line, x, yy);
        yy += (lineH || size + 3 || 11);
        line = w;
      } else line = probe;
    });
    if (line) g2.fillText(line, x, yy);
    return yy; // baseline of the last line, for stacking below
  }
  // per-mechanic control cards — the tutorial the cartridges never shipped
  const AR_HOWTO = {
    timing: ['[A] = stop it right in the zone', '[A] = arrête-le pile dans la zone'],
    catch: ['[◄][►] move · catch good, dodge bad', '[◄][►] bouge · attrape le bon, évite le reste'],
    dodge: ['[◄][►] dodge EVERYTHING', '[◄][►] esquive TOUT'],
    flappy: ['[A] = flap up · gravity does the rest', '[A] = bats des ailes · la gravité fait le reste'],
    mash: ['mash [A] as fast as you can!!', 'martèle [A] aussi vite que possible !!'],
    memory: ['watch the code · replay it: [◄][A][►]', 'regarde le code · rejoue-le : [◄][A][►]'],
    whack: ['[◄]=left · [A]=middle · [►]=right hole', '[◄]=gauche · [A]=milieu · [►]=trou droit'],
    snipe: ['the crosshair drifts · [A] = fire', 'le viseur dérive · [A] = tire'],
    redlight: ['HOLD [A] to sneak · freeze when watched', 'MAINTIENS [A] pour avancer · fige sous le regard'],
    pong: ['[◄][►] move the paddle', '[◄][►] déplace la raquette'],
    race: ['[A] = jump the obstacles', '[A] = saute les obstacles'],
    defuse: ['[A] exactly at 0.0 — not before', '[A] pile à 0.0 — pas avant'],
    tetris: ['[◄][►] move · [A] rotate the piece', '[◄][►] déplace · [A] tourne la pièce'],
    snake: ['[◄] turn left · [►] turn right', '[◄] tourne à gauche · [►] à droite'],
    breakout: ['[◄][►] paddle · [A] serve the ball', '[◄][►] raquette · [A] sers la balle'],
    shooter: ['[◄][►] move · [A] = pew pew', '[◄][►] bouge · [A] = piou piou'],
    rhythm: ['press the lane as the note hits the line: [◄][A][►]', 'appuie sur la voie quand la note touche la ligne : [◄][A][►]'],
    frogger: ['[A] hop forward · [◄][►] sidestep', '[A] saute en avant · [◄][►] pas de côté'],
    lander: ['HOLD [A] = burn up · [◄][►] tilt · land SOFT on ▼', 'MAINTIENS [A] = poussée · [◄][►] incline · atterris DOUCEMENT sur ▼'],
    asteroids: ['[◄][►] rotate · HOLD [A] thrust · it fires itself', '[◄][►] pivote · MAINTIENS [A] poussée · ça tire tout seul'],
    missile: ['[◄][►] aim · [A] pop the interceptor', '[◄][►] vise · [A] déclenche l\'interception'],
    centipede: ['[◄][►] move · HOLD [A] to spray', '[◄][►] bouge · MAINTIENS [A] pour arroser'],
    pongvs: ['[◄][►] paddle · first to 3 wins', '[◄][►] raquette · premier à 3 gagne'],
    tapper: ['send boba down their lane: [◄]=top [A]=mid [►]=low', 'envoie le boba sur leur voie : [◄]=haut [A]=milieu [►]=bas']
  };

  /* ---- the 24 mechanic templates. each: init(s,p) / tick(s,p,inp) / draw(s,p,g2)
     s.win / s.lose end the round; s.t counts frames (60/s). ---- */
  const AR_TPLS = {
    timing: {
      init(s, p) { s.round = 0; s.x = 10; s.dir = 1; s.flash = 0; },
      tick(s, p, inp) {
        const v = 1.1 + p.speed * 0.55;
        s.x += s.dir * v; if (s.x > AR_W - 10 || s.x < 10) s.dir *= -1;
        if (s.flash > 0) s.flash--;
        if (inp.a) {
          if (Math.abs(s.x - AR_W / 2) < (p.zone || 14) / 2 + 3) { s.round++; s.flash = 12; playTone(880 + s.round * 120, 'square', 0.08, 0, 0.04); if (s.round >= (p.rounds || 3)) s.win = true; }
          else s.lose = true;
        }
      },
      draw(s, p, g2) {
        g2.strokeStyle = AR_G[1]; g2.lineWidth = 2;
        g2.strokeRect(AR_W / 2 - (p.zone || 14) / 2, 34, (p.zone || 14), 28);
        if (s.flash) { g2.fillStyle = AR_G[2]; g2.fillRect(AR_W / 2 - (p.zone || 14) / 2, 34, (p.zone || 14), 28); }
        arDrawGlyph(g2, p.glyph, s.x, 48, 16);
        arText(g2, (s.round) + '/' + (p.rounds || 3), 143, 10);
      }
    },
    catch: {
      init(s, p) { s.px = AR_W / 2; s.items = []; s.got = 0; s.spawn = 34; /* breath before the first drop */ },
      tick(s, p, inp) {
        if (inp.left) s.px = Math.max(10, s.px - 2.4);
        if (inp.right) s.px = Math.min(AR_W - 10, s.px + 2.4);
        if (--s.spawn <= 0) { s.spawn = Math.max(26, 52 - p.speed * 8); s.items.push({ x: 12 + Math.random() * (AR_W - 24), y: -8, bad: Math.random() < (p.badRatio || 0.3) }); }
        s.items.forEach((it) => { it.y += 0.8 + p.speed * 0.5; });
        s.items = s.items.filter((it) => {
          if (it.y > 70 && Math.abs(it.x - s.px) < 11) {
            if (it.bad) { s.lose = true; } else { s.got++; playTone(980 + s.got * 60, 'square', 0.06, 0, 0.03); if (s.got >= p.need) s.win = true; }
            return false;
          }
          return it.y < AR_H + 8;
        });
        if (s.t > 60 * 18) s.lose = true;
      },
      draw(s, p, g2) {
        g2.fillStyle = AR_G[1]; g2.fillRect(Math.round(s.px - 10), 76, 20, 5);
        s.items.forEach((it) => arDrawGlyph(g2, it.bad ? p.bad : p.good, it.x, it.y, 13));
        arText(g2, s.got + '/' + p.need, 143, 10);
      }
    },
    dodge: {
      init(s, p) { s.px = AR_W / 2; s.items = []; s.spawn = 44; /* breath before the rain */ s.lastX = AR_W / 2; },
      tick(s, p, inp) {
        if (inp.left) s.px = Math.max(8, s.px - 2.6);
        if (inp.right) s.px = Math.min(AR_W - 8, s.px + 2.6);
        if (--s.spawn <= 0) {
          s.spawn = Math.max(24, 44 - p.speed * 7);
          // consecutive drops keep ≥44px of daylight — no pincer walls, ever
          let nx = 8 + Math.random() * (AR_W - 16);
          if (Math.abs(nx - s.lastX) < 44) nx = s.lastX + (nx >= s.lastX ? 44 : -44);
          nx = Math.max(8, Math.min(AR_W - 8, nx));
          s.lastX = nx;
          s.items.push({ x: nx, y: -8 });
        }
        s.items.forEach((it) => { it.y += 0.7 + p.speed * 0.4; });
        s.items = s.items.filter((it) => it.y < AR_H + 8);
        if (s.items.some((it) => it.y > 66 && it.y < 84 && Math.abs(it.x - s.px) < 9)) s.lose = true;
        if (s.t >= p.secs * 60) s.win = true;
      },
      draw(s, p, g2) {
        arDrawGlyph(g2, '🟢', s.px, 76, 13);
        s.items.forEach((it) => arDrawGlyph(g2, p.hazard, it.x, it.y, 13));
        arText(g2, Math.max(0, Math.ceil(p.secs - s.t / 60)) + 's', 143, 10);
      }
    },
    flappy: {
      init(s, p) { s.y = 44; s.vy = 0; s.armed = false; s.gates = []; s.passed = 0; let gx = 190; let prev = 30; for (let i = 0; i < p.gates; i++) { const lo = Math.max(14, prev - 24), hi = Math.min(AR_H - 26 - (p.gap || 32), prev + 24); const gy = lo + Math.random() * Math.max(4, hi - lo); s.gates.push({ x: gx, gy }); prev = gy; gx += 62; } },
      tick(s, p, inp) {
        // the world holds its breath until the FIRST flap — the old version
        // dropped you (and marched the walls) the instant the countdown hit 0
        if (!s.armed) { if (!inp.a) { s.t = 0; s.bob = (s.bob || 0) + 1; s.y = 44 + Math.sin(s.bob * 0.08) * 3; return; } s.armed = true; } // held breath ≠ burned clock: the 25s cartridge timeout only starts at launch
        if (inp.a) { s.vy = -2.1; playTone(760, 'square', 0.04, 0, 0.02); } // rise ≈13.8px — always fits the tightest gap
        s.vy += 0.16; s.y += s.vy;
        const v = 0.8 + p.speed * 0.4;
        s.gates.forEach((g) => { g.x -= v; });
        s.gates = s.gates.filter((g) => { if (g.x < 14) { s.passed++; playTone(1040, 'square', 0.05, 0, 0.03); return false; } return true; });
        const hit = s.gates.some((g) => g.x > 12 && g.x < 28 && (s.y < g.gy || s.y > g.gy + (p.gap || 32)));
        if (hit || s.y < 2 || s.y > AR_H - 2) s.lose = true;
        if (s.passed >= p.gates) s.win = true;
      },
      draw(s, p, g2) {
        s.gates.forEach((g) => { g2.fillStyle = AR_G[1]; g2.fillRect(Math.round(g.x), 0, 8, Math.round(g.gy)); g2.fillRect(Math.round(g.x), Math.round(g.gy + (p.gap || 32)), 8, AR_H); });
        arDrawGlyph(g2, p.player, 20, s.y, 13);
        if (!s.armed && (s.bob || 0) % 50 < 32) arText(g2, trT('[A] to launch!!', '[A] pour décoller !!'), 46, 30, 0, 10);
        arText(g2, s.passed + '/' + p.gates, 143, 10);
      }
    },
    mash: {
      init(s, p) { s.n = 0; },
      tick(s, p, inp) {
        if (inp.a) { s.n += Math.min(4, inp.a); playTone(600 + s.n * 22, 'square', 0.03, 0, 0.02); if (s.n >= p.taps) s.win = true; }
        if (s.t > p.secs * 60) s.lose = true;
      },
      draw(s, p, g2) {
        const frac = s.n / p.taps;
        g2.strokeStyle = AR_G[0]; g2.strokeRect(30, 70, 100, 10);
        g2.fillStyle = AR_G[1]; g2.fillRect(31, 71, Math.round(98 * frac), 8);
        arDrawGlyph(g2, p.riser, 80, 58 - frac * 34, 18);
        arText(g2, Math.max(0, (p.secs - s.t / 60)).toFixed(1) + 's', 138, 10);
      }
    },
    memory: {
      init(s, p) { const K = ['L', 'R', 'A']; s.seq = Array.from({ length: p.len || 4 }, () => K[Math.floor(Math.random() * 3)]); s.show = 0; s.at = 0; s.phase = 'show'; },
      tick(s, p, inp) {
        if (s.phase === 'show') {
          if (s.t % 40 === 38) { s.show++; if (s.show >= s.seq.length) s.phase = 'input'; }
          return;
        }
        const press = inp.a ? 'A' : (inp.leftEdge ? 'L' : (inp.rightEdge ? 'R' : null));
        if (!press) return;
        if (press === s.seq[s.at]) { s.at++; playTone(880 + s.at * 100, 'square', 0.05, 0, 0.03); if (s.at >= s.seq.length) s.win = true; }
        else s.lose = true;
      },
      draw(s, p, g2) {
        const GL = { L: '◄', R: '►', A: 'A' };
        if (s.phase === 'show') {
          arText(g2, trT('watch…', 'regarde…'), 12, 30, 1);
          const cur = Math.min(s.show, s.seq.length - 1);
          if (s.t % 40 < 30) arText(g2, GL[s.seq[cur]], 74, 58, 0, 22);
          arText(g2, (cur + 1) + '/' + s.seq.length, 140, 10);
        } else {
          arText(g2, trT('repeat!!', 'répète !!'), 12, 30, 1);
          for (let i = 0; i < s.seq.length; i++) arText(g2, i < s.at ? GL[s.seq[i]] : '·', 40 + i * 16, 58, i < s.at ? 0 : 1, 14);
        }
      }
    },
    whack: {
      init(s, p) { s.hits = 0; s.pop = null; s.next = 30; },
      tick(s, p, inp) {
        if (!s.pop) { if (--s.next <= 0) s.pop = { lane: Math.floor(Math.random() * 3), decoy: p.decoy ? Math.random() < 0.3 : false, ttl: Math.round((p.upMs || 800) / 16.7) }; }
        else if (--s.pop.ttl <= 0) { s.pop = null; s.next = 20 + Math.random() * 30; }
        const press = inp.leftEdge ? 0 : (inp.a ? 1 : (inp.rightEdge ? 2 : null));
        if (press == null || !s.pop) { if (press != null) playTone(160, 'square', 0.05, 0, 0.03); return; }
        if (press === s.pop.lane) {
          if (s.pop.decoy) { s.lose = true; return; }
          s.hits++; playTone(980, 'square', 0.06, 0, 0.03);
          s.pop = null; s.next = 18 + Math.random() * 26;
          if (s.hits >= p.hits) s.win = true;
        }
        if (s.t > 60 * 20) s.lose = true;
      },
      draw(s, p, g2) {
        const lanes = [34, 80, 126];
        lanes.forEach((lx, i) => {
          g2.fillStyle = AR_G[1]; g2.fillRect(lx - 12, 66, 24, 6);
          if (s.pop && s.pop.lane === i) arDrawGlyph(g2, s.pop.decoy ? p.decoy : p.mole, lx, 56, 16);
          arText(g2, i === 0 ? '◄' : i === 1 ? 'A' : '►', lx - 3, 84, 1);
        });
        arText(g2, s.hits + '/' + p.hits, 143, 10);
      }
    },
    snipe: {
      init(s, p) { s.cx = 40; s.cy = 40; s.tx = 110; s.ty = 50; s.hits = 0; s.miss = 0; },
      tick(s, p, inp) {
        const v = 0.9 + p.speed * 0.4;
        s.cx = AR_W / 2 + Math.sin(s.t * 0.031 * v) * 62;
        s.cy = 48 + Math.cos(s.t * 0.047 * v) * 30;
        if (s.t % 90 === 0) { s.tx = 20 + Math.random() * 120; s.ty = 20 + Math.random() * 60; }
        if (inp.a) {
          if (Math.hypot(s.cx - s.tx, s.cy - s.ty) < 11) { s.hits++; playTone(1100, 'square', 0.06, 0, 0.03); s.tx = 20 + Math.random() * 120; s.ty = 20 + Math.random() * 60; if (s.hits >= p.hits) s.win = true; }
          else { s.miss++; playTone(180, 'square', 0.06, 0, 0.04); if (s.miss >= 3) s.lose = true; }
        }
      },
      draw(s, p, g2) {
        arDrawGlyph(g2, p.target, s.tx, s.ty, 14);
        g2.strokeStyle = AR_G[0]; g2.lineWidth = 1;
        g2.strokeRect(Math.round(s.cx - 7), Math.round(s.cy - 7), 14, 14);
        g2.fillRect(Math.round(s.cx - 1), Math.round(s.cy - 10), 2, 6);
        g2.fillRect(Math.round(s.cx - 1), Math.round(s.cy + 4), 2, 6);
        arText(g2, s.hits + '/' + p.hits + '  ✕' + (3 - s.miss), 118, 10);
      }
    },
    redlight: {
      init(s, p) { s.px = 8; s.green = true; s.flip = 90 + Math.random() * 60; s.warn = 0; },
      tick(s, p, inp) {
        if (--s.flip <= 0) {
          s.green = !s.green;
          s.flip = s.green ? 70 + Math.random() * 80 : 45 + Math.random() * 40;
          s.warn = s.green ? 0 : 0; // the turn is instant; the tell is the sound
          playTone(s.green ? 700 : 240, 'square', 0.1, 0, 0.05);
        }
        if (inp.aHeld) {
          if (s.green) s.px += 0.55 + (p.dist ? 0 : 0);
          else { s.lose = true; return; }
        }
        if (s.px >= AR_W - 16) s.win = true;
      },
      draw(s, p, g2) {
        g2.fillStyle = AR_G[1]; g2.fillRect(AR_W - 14, 30, 3, 40);
        arDrawGlyph(g2, '🚩', AR_W - 10, 34, 12);
        arDrawGlyph(g2, p.watcher, AR_W - 12, 60, 14);
        if (!s.green) { g2.fillStyle = AR_G[0]; g2.fillRect(AR_W - 24, 46, 24, 3); }
        arDrawGlyph(g2, '🟢', s.px, 76, 13);
        arText(g2, s.green ? trT('GO (hold A)', 'FONCE (tiens A)') : trT('...FREEZE!!', '...GRRR !!'), 10, 12, s.green ? 1 : 0);
      }
    },
    pong: {
      init(s, p) { s.px = AR_W / 2; s.bx = AR_W / 2; s.by = 30; s.vx = 1.1 + p.speed * 0.3; s.vy = 1.2; s.n = 0; s.hold = 50; },
      tick(s, p, inp) {
        if (inp.left) s.px = Math.max(14, s.px - 2.6);
        if (inp.right) s.px = Math.min(AR_W - 14, s.px + 2.6);
        if (s.hold > 0) { s.hold--; return; } // the serve takes a polite beat
        s.bx += s.vx; s.by += s.vy;
        if (s.bx < 6 || s.bx > AR_W - 6) s.vx *= -1;
        if (s.by < 6) s.vy = Math.abs(s.vy);
        if (s.by > 72 && s.by < 80 && Math.abs(s.bx - s.px) < 14 && s.vy > 0) {
          s.vy = -Math.abs(s.vy) * 1.04; s.vx += (s.bx - s.px) * 0.06; s.n++;
          playTone(880 + s.n * 60, 'square', 0.05, 0, 0.03);
          if (s.n >= p.bounces) s.win = true;
        }
        if (s.by > AR_H + 6) s.lose = true;
      },
      draw(s, p, g2) {
        g2.fillStyle = AR_G[1]; g2.fillRect(Math.round(s.px - 12), 78, 24, 4);
        arDrawGlyph(g2, p.ball, s.bx, s.by, 12);
        arText(g2, s.n + '/' + p.bounces, 143, 10);
      }
    },
    defuse: {
      init(s, p) { s.round = 0; s.timer = 3.0; s.live = true; },
      tick(s, p, inp) {
        if (!s.live) { if (--s.wait <= 0) { s.timer = 3.0 + Math.random() * 0.8; s.live = true; } return; }
        s.timer -= 1 / 60;
        if (s.timer < -(p.window || 0.28)) { s.lose = true; return; }
        if (inp.a) {
          if (Math.abs(s.timer) <= (p.window || 0.28)) {
            s.round++; playTone(1174, 'square', 0.08, 0, 0.04);
            if (s.round >= (p.rounds || 3)) { s.win = true; return; }
            s.live = false; s.wait = 40;
          } else s.lose = true;
        }
      },
      draw(s, p, g2) {
        arDrawGlyph(g2, p.bomb, 80, 34, 20);
        arText(g2, s.live ? Math.max(0, s.timer).toFixed(2) : trT('…breathe…', '…respire…'), 66, 64, 0, 14);
        arText(g2, s.round + '/' + (p.rounds || 3), 143, 10);
      }
    },
    race: {
      init(s, p) { s.y = 0; s.vy = 0; s.obs = []; s.passed = 0; let ox = 235; /* runway: read the field first */ /* ≥70px spacing: landing always beats the next tuft */ for (let i = 0; i < p.obstacles; i++) { s.obs.push({ x: ox }); ox += 70 + Math.random() * 30; } },
      tick(s, p, inp) {
        if (inp.a && s.y === 0) { s.vy = 3.4; playTone(760, 'square', 0.05, 0, 0.03); }
        s.y += s.vy; if (s.y > 0) s.vy -= 0.22; if (s.y <= 0) { s.y = 0; s.vy = 0; }
        const v = 1.1 + p.speed * 0.5;
        s.obs.forEach((o) => { o.x -= v; });
        s.obs = s.obs.filter((o) => { if (o.x < 8) { s.passed++; return false; } return true; });
        if (s.obs.some((o) => o.x > 12 && o.x < 26 && s.y < 10)) s.lose = true;
        if (s.passed >= p.obstacles) s.win = true;
      },
      draw(s, p, g2) {
        g2.fillStyle = AR_G[1]; g2.fillRect(0, 82, AR_W, 2);
        arDrawGlyph(g2, p.runner, 20, 74 - s.y, 14);
        s.obs.forEach((o) => arDrawGlyph(g2, p.obstacle, o.x, 75, 13));
        arText(g2, s.passed + '/' + p.obstacles, 143, 10);
      }
    },
    /* ==== v123: FIVE NEW MECHANICS — the shelf doubles its genres ==== */
    tetris: {
      // the real thing, pocket-sized: 10×12 well, five tetrominoes,
      // [◄][►] move · [A] rotate · gravity does the dropping
      init(s, p) {
        s.W = 10; s.H = 12; s.cell = 6; s.bx = 50; s.by = 10;
        s.grid = Array.from({ length: s.H }, () => new Array(s.W).fill(0));
        s.lines = 0; s.dropF = 0;
        s.SHAPES = [
          [[0, 0], [1, 0], [0, 1], [1, 1]],   // O
          [[-1, 0], [0, 0], [1, 0], [2, 0]],  // I
          [[-1, 0], [0, 0], [1, 0], [0, 1]],  // T
          [[-1, 0], [0, 0], [1, 0], [1, 1]],  // L
          [[0, 0], [1, 0], [-1, 1], [0, 1]]   // S
        ];
        s.spawn = () => {
          const k = Math.floor(Math.random() * s.SHAPES.length);
          s.pc = { k, c: s.SHAPES[k].map((q) => q.slice()), x: 4, y: 0 };
          if (s.pc.c.some(([cx, cy]) => s.grid[cy] && s.grid[cy][s.pc.x + cx])) s.lose = true; // well is full
        };
        s.fits = (cells, px, py) => cells.every(([cx, cy]) => {
          const gx = px + cx, gy = py + cy;
          return gx >= 0 && gx < s.W && gy < s.H && (gy < 0 || !s.grid[gy][gx]);
        });
        s.spawn();
      },
      tick(s, p, inp) {
        if (!s.pc) return;
        // held-move with a gentle repeat = silky steering
        const wantL = inp.leftEdge || (inp.left && s.t % 7 === 0);
        const wantR = inp.rightEdge || (inp.right && s.t % 7 === 0);
        if (wantL && s.fits(s.pc.c, s.pc.x - 1, s.pc.y)) s.pc.x--;
        if (wantR && s.fits(s.pc.c, s.pc.x + 1, s.pc.y)) s.pc.x++;
        if (inp.a && s.pc.k !== 0) { // O doesn't rotate (it tried once. nothing happened.)
          const rot = s.pc.c.map(([cx, cy]) => [-cy, cx]);
          const kick = [0, -1, 1, -2, 2].find((dx) => s.fits(rot, s.pc.x + dx, s.pc.y));
          if (kick != null) { s.pc.c = rot; s.pc.x += kick; playTone(680, 'square', 0.03, 0, 0.02); }
        }
        const gravEvery = Math.max(9, 24 - (p.speed || 2) * 3 - s.lines);
        if (++s.dropF >= gravEvery) {
          s.dropF = 0;
          if (s.fits(s.pc.c, s.pc.x, s.pc.y + 1)) s.pc.y++;
          else { // lock + sweep
            s.pc.c.forEach(([cx, cy]) => { const gy = s.pc.y + cy; if (gy >= 0) s.grid[gy][s.pc.x + cx] = 1; });
            playTone(300, 'square', 0.04, 0, 0.03);
            for (let r = s.H - 1; r >= 0; r--) {
              if (s.grid[r].every(Boolean)) {
                s.grid.splice(r, 1); s.grid.unshift(new Array(s.W).fill(0));
                s.lines++; playTone(1046 + s.lines * 80, 'square', 0.09, 0, 0.05);
                r++; // recheck the row that slid down
              }
            }
            if (s.lines >= (p.lines || 3)) { s.win = true; return; }
            s.spawn();
          }
        }
      },
      draw(s, p, g2) {
        g2.strokeStyle = AR_G[0]; g2.lineWidth = 1;
        g2.strokeRect(s.bx - 2, s.by - 2, s.W * s.cell + 4, s.H * s.cell + 4);
        for (let r = 0; r < s.H; r++) for (let c = 0; c < s.W; c++) {
          if (s.grid[r][c]) { g2.fillStyle = AR_G[1]; g2.fillRect(s.bx + c * s.cell, s.by + r * s.cell, s.cell - 1, s.cell - 1); }
        }
        if (s.pc) s.pc.c.forEach(([cx, cy]) => {
          const gy = s.pc.y + cy; if (gy < 0) return;
          g2.fillStyle = AR_G[0];
          g2.fillRect(s.bx + (s.pc.x + cx) * s.cell, s.by + gy * s.cell, s.cell - 1, s.cell - 1);
        });
        arText(g2, s.lines + '/' + (p.lines || 3), 130, 12);
        arText(g2, trT('lines', 'lignes'), 124, 22, 1, 7);
      }
    },
    snake: {
      // relative steering on two buttons — the classiest of classics.
      // [◄] turn left · [►] turn right (from the snake's point of view)
      init(s, p) {
        s.W = 18; s.H = 10; s.cell = 8; s.bx = 8; s.by = 6;
        s.body = [[5, 5], [4, 5], [3, 5]];
        s.dir = 0; // 0→ 1↓ 2← 3↑
        s.turn = null; s.stepF = 0; s.n = 0;
        s.drop = () => {
          let px, py;
          do { px = Math.floor(Math.random() * s.W); py = Math.floor(Math.random() * s.H); }
          while (s.body.some(([bx2, by2]) => bx2 === px && by2 === py));
          s.pellet = [px, py];
        };
        s.drop();
      },
      tick(s, p, inp) {
        // buffer ONE turn per step — double-taps between steps stay honest
        if (inp.leftEdge) s.turn = 'L';
        else if (inp.rightEdge) s.turn = 'R';
        if (++s.stepF < Math.max(6, (p.stepF || 9) - Math.floor(s.n / 3))) return;
        s.stepF = 0;
        if (s.turn === 'L') s.dir = (s.dir + 3) % 4;
        if (s.turn === 'R') s.dir = (s.dir + 1) % 4;
        s.turn = null;
        const D = [[1, 0], [0, 1], [-1, 0], [0, -1]][s.dir];
        const head = [s.body[0][0] + D[0], s.body[0][1] + D[1]];
        if (head[0] < 0 || head[0] >= s.W || head[1] < 0 || head[1] >= s.H) { s.lose = true; return; }
        if (s.body.some(([bx2, by2]) => bx2 === head[0] && by2 === head[1])) { s.lose = true; return; }
        s.body.unshift(head);
        if (head[0] === s.pellet[0] && head[1] === s.pellet[1]) {
          s.n++; playTone(880 + s.n * 90, 'square', 0.06, 0, 0.03);
          if (s.n >= (p.eats || 6)) { s.win = true; return; }
          s.drop();
        } else s.body.pop();
      },
      draw(s, p, g2) {
        g2.strokeStyle = AR_G[2]; g2.lineWidth = 1;
        g2.strokeRect(s.bx - 2, s.by - 2, s.W * s.cell + 4, s.H * s.cell + 4);
        s.body.forEach(([cx, cy], i) => {
          g2.fillStyle = i === 0 ? AR_G[0] : AR_G[1];
          g2.fillRect(s.bx + cx * s.cell, s.by + cy * s.cell, s.cell - 1, s.cell - 1);
        });
        arDrawGlyph(g2, p.snack, s.bx + s.pellet[0] * s.cell + 4, s.by + s.pellet[1] * s.cell + 4, 9);
        arText(g2, s.n + '/' + (p.eats || 6), 140, 12);
      }
    },
    breakout: {
      // [◄][►] paddle · [A] serves. the ball does the demolition.
      init(s, p) {
        s.px = AR_W / 2; s.bricks = [];
        for (let r = 0; r < 2; r++) for (let c = 0; c < 6; c++) s.bricks.push({ x: 10 + c * 24, y: 14 + r * 10, w: 21, h: 7 });
        s.ball = null; // glued until served
        s.n = 0;
      },
      tick(s, p, inp) {
        if (inp.left) s.px = Math.max(14, s.px - 2.6);
        if (inp.right) s.px = Math.min(AR_W - 14, s.px + 2.6);
        if (!s.ball) {
          if (inp.a || s.t > 150) { s.ball = { x: s.px, y: 78, vx: (Math.random() < 0.5 ? -1 : 1) * (0.9 + (p.speed || 2) * 0.2), vy: -(1.4 + (p.speed || 2) * 0.2) }; playTone(760, 'square', 0.05, 0, 0.03); }
          return;
        }
        const b = s.ball;
        b.x += b.vx; b.y += b.vy;
        if (b.x < 5 || b.x > AR_W - 5) b.vx *= -1;
        if (b.y < 5) b.vy = Math.abs(b.vy);
        if (b.y > 76 && b.y < 84 && Math.abs(b.x - s.px) < 14 && b.vy > 0) {
          b.vy = -Math.abs(b.vy); b.vx += (b.x - s.px) * 0.07;
          b.vx = Math.max(-2.4, Math.min(2.4, b.vx));
          playTone(620, 'square', 0.04, 0, 0.02);
        }
        const hit = s.bricks.findIndex((k) => b.x > k.x - 2 && b.x < k.x + k.w + 2 && b.y > k.y - 2 && b.y < k.y + k.h + 2);
        if (hit >= 0) {
          const k = s.bricks[hit];
          // bounce off the nearer face
          if (b.x < k.x || b.x > k.x + k.w) b.vx *= -1; else b.vy *= -1;
          s.bricks.splice(hit, 1); s.n++;
          b.vy *= 1.02;
          playTone(980 + s.n * 40, 'square', 0.05, 0, 0.03);
          if (!s.bricks.length) { s.win = true; return; }
        }
        if (b.y > AR_H + 6) s.lose = true;
      },
      draw(s, p, g2) {
        s.bricks.forEach((k, i) => { g2.fillStyle = i % 2 ? AR_G[0] : AR_G[1]; g2.fillRect(k.x, k.y, k.w, k.h); });
        g2.fillStyle = AR_G[0]; g2.fillRect(Math.round(s.px - 12), 80, 24, 4);
        if (s.ball) arDrawGlyph(g2, p.ball || '🧱', s.ball.x, s.ball.y, 10);
        else { arDrawGlyph(g2, p.ball || '🧱', s.px, 74, 10); if (s.t % 50 < 32) arText(g2, trT('[A] serve!!', '[A] service !!'), 56, 60, 0, 9); }
        arText(g2, s.n + '/12', 136, 12);
      }
    },
    shooter: {
      // [◄][►] move · [A] pew. the bugs march closer with every bounce.
      init(s, p) {
        s.px = AR_W / 2; s.shots = []; s.inv = [];
        for (let r = 0; r < 2; r++) for (let c = 0; c < 6; c++) s.inv.push({ x: 24 + c * 20, y: 14 + r * 14 });
        s.dx = 0.35 + (p.speed || 2) * 0.08; s.cool = 0; s.n = 0;
      },
      tick(s, p, inp) {
        if (inp.left) s.px = Math.max(8, s.px - 2.4);
        if (inp.right) s.px = Math.min(AR_W - 8, s.px + 2.4);
        if (s.cool > 0) s.cool--;
        if (inp.a && s.cool <= 0 && s.shots.length < 2) {
          s.shots.push({ x: s.px, y: 76 }); s.cool = 13;
          playTone(1240, 'square', 0.04, 0, 0.02);
        }
        s.shots.forEach((sh) => { sh.y -= 2.6; });
        s.shots = s.shots.filter((sh) => sh.y > -6);
        let edge = false;
        s.inv.forEach((v) => { v.x += s.dx; if (v.x < 10 || v.x > AR_W - 10) edge = true; });
        if (edge) { s.dx *= -1; s.inv.forEach((v) => { v.y += 5; }); }
        s.shots = s.shots.filter((sh) => {
          const hit = s.inv.findIndex((v) => Math.abs(v.x - sh.x) < 8 && Math.abs(v.y - sh.y) < 8);
          if (hit >= 0) { s.inv.splice(hit, 1); s.n++; playTone(880 + s.n * 60, 'square', 0.06, 0, 0.03); return false; }
          return true;
        });
        if (!s.inv.length) { s.win = true; return; }
        if (s.inv.some((v) => v.y > 68)) s.lose = true;
      },
      draw(s, p, g2) {
        s.inv.forEach((v) => arDrawGlyph(g2, p.bug, v.x, v.y, 12));
        g2.fillStyle = AR_G[0];
        s.shots.forEach((sh) => g2.fillRect(Math.round(sh.x - 1), Math.round(sh.y - 4), 2, 6));
        g2.fillRect(Math.round(s.px - 6), 80, 12, 4); g2.fillRect(Math.round(s.px - 1), 76, 2, 4);
        arText(g2, s.n + '/12', 136, 12);
      }
    },
    rhythm: {
      // three lanes, one heart: press the lane's button as the note kisses
      // the line. [◄]=left lane · [A]=middle · [►]=right lane
      init(s, p) {
        s.lanes = [44, 80, 116]; s.notes = []; s.spawned = 0; s.hits = 0; s.miss = 0;
        s.nextAt = 30; s.total = (p.notes || 10) + 3;
      },
      tick(s, p, inp) {
        if (s.spawned < s.total && --s.nextAt <= 0) {
          s.nextAt = 32 + Math.random() * ((p.tempo || 2) > 2 ? 8 : 16);
          s.notes.push({ lane: Math.floor(Math.random() * 3), y: -6 });
          s.spawned++;
        }
        const vy = 1.15 + (p.tempo || 2) * 0.18;
        s.notes.forEach((n2) => { n2.y += vy; });
        const press = inp.leftEdge ? 0 : (inp.a ? 1 : (inp.rightEdge ? 2 : null));
        if (press != null) {
          const ix = s.notes.findIndex((n2) => n2.lane === press && Math.abs(n2.y - 70) <= 10);
          if (ix >= 0) {
            s.notes.splice(ix, 1); s.hits++;
            playTone([784, 988, 1175][press], 'square', 0.06, 0, 0.03);
            if (s.hits >= (p.notes || 10)) { s.win = true; return; }
          } else playTone(180, 'square', 0.04, 0, 0.02); // whiff: a shrug, not a penalty
        }
        s.notes = s.notes.filter((n2) => {
          if (n2.y > 84) { s.miss++; playTone(240, 'square', 0.05, 0, 0.03); return false; }
          return true;
        });
        if (s.miss > 3) s.lose = true;
      },
      draw(s, p, g2) {
        g2.fillStyle = AR_G[2];
        s.lanes.forEach((lx) => g2.fillRect(lx - 9, 6, 1, 78));
        g2.fillStyle = AR_G[0]; g2.fillRect(24, 70, 112, 2); // the line
        s.notes.forEach((n2) => arDrawGlyph(g2, p.note || '♥', s.lanes[n2.lane], n2.y, 12));
        s.lanes.forEach((lx, i) => arText(g2, i === 0 ? '◄' : i === 1 ? 'A' : '►', lx - 4, 92, 1));
        arText(g2, s.hits + '/' + (p.notes || 10) + ' ✕' + Math.max(0, 4 - s.miss), 118, 12);
      }
    },
    /* ==== v125: THE CLASSICS CABINET — seven more arcade legends ==== */
    frogger: {
      // three lanes of traffic between you and the far bank.
      // [A] hop forward · [◄][►] sidestep · repeat until legend
      init(s, p) {
        s.lanes = [
          { y: 58, v: 0.55 + (p.speed || 2) * 0.15, gap: 54 },
          { y: 44, v: -(0.7 + (p.speed || 2) * 0.18), gap: 60 },
          { y: 30, v: 0.9 + (p.speed || 2) * 0.2, gap: 66 }
        ];
        s.cars = [];
        s.lanes.forEach((ln, li) => { for (let x = -20; x < AR_W + 40; x += ln.gap) s.cars.push({ li, x: x + li * 17 }); });
        s.px = 80; s.py = 72; s.cross = 0;
      },
      tick(s, p, inp) {
        if (inp.a && s.py > 14) { s.py -= 14; playTone(880, 'square', 0.04, 0, 0.02); }
        if (inp.leftEdge) s.px = Math.max(8, s.px - 14);
        if (inp.rightEdge) s.px = Math.min(AR_W - 8, s.px + 14);
        s.cars.forEach((c) => {
          const ln = s.lanes[c.li];
          c.x += ln.v;
          if (ln.v > 0 && c.x > AR_W + 24) c.x = -24;
          if (ln.v < 0 && c.x < -24) c.x = AR_W + 24;
        });
        if (s.t > 45 && s.cars.some((c) => Math.abs(s.lanes[c.li].y - s.py) < 6 && Math.abs(c.x - s.px) < 12)) { s.lose = true; return; }
        if (s.py <= 16) {
          s.cross++; playTone(1175, 'triangle', 0.1, 0, 0.05);
          if (s.cross >= (p.cross || 3)) { s.win = true; return; }
          s.py = 72; s.px = 80;
        }
      },
      draw(s, p, g2) {
        g2.fillStyle = AR_G[2];
        s.lanes.forEach((ln) => { g2.fillRect(0, ln.y + 7, AR_W, 1); g2.fillRect(0, ln.y - 7, AR_W, 1); });
        g2.fillStyle = AR_G[1]; g2.fillRect(0, 12, AR_W, 2); // the far bank
        s.cars.forEach((c) => { g2.fillStyle = AR_G[c.li % 2 ? 0 : 1]; g2.fillRect(Math.round(c.x - 9), s.lanes[c.li].y - 4, 18, 8); });
        arDrawGlyph(g2, p.hopper || '🐸', s.px, s.py, 12);
        arText(g2, s.cross + '/' + (p.cross || 3), 140, 10);
      }
    },
    lander: {
      // gravity is patient. HOLD [A] to burn, [◄][►] to tilt,
      // and kiss the pad — don't punch it
      init(s, p) {
        s.x = 24; s.y = 16; s.vx = 0.5; s.vy = 0;
        s.padX = 60 + Math.random() * 70; s.padW = 26; s.done = 0;
      },
      tick(s, p, inp) {
        if (inp.aHeld) { s.vy -= 0.085; if (s.t % 4 === 0) playTone(140, 'sawtooth', 0.03, 0, 0.02); }
        if (inp.left) s.vx -= 0.045;
        if (inp.right) s.vx += 0.045;
        s.vy += 0.038;
        s.x += s.vx; s.y += s.vy;
        if (s.x < 6) { s.x = 6; s.vx = Math.abs(s.vx) * 0.4; }
        if (s.x > AR_W - 6) { s.x = AR_W - 6; s.vx = -Math.abs(s.vx) * 0.4; }
        if (s.y < 6) { s.y = 6; s.vy = Math.max(0, s.vy); }
        if (s.y >= 79) {
          const onPad = Math.abs(s.x - (s.padX + s.padW / 2)) < s.padW / 2;
          const gentle = s.vy < (p.soft || 1.05) && Math.abs(s.vx) < 0.85;
          if (onPad && gentle) {
            s.done++; playTone(1046, 'triangle', 0.12, 0, 0.06);
            if (s.done >= (p.landings || 1)) { s.win = true; return; }
            s.x = 24; s.y = 16; s.vx = 0.5; s.vy = 0; s.padX = 40 + Math.random() * 90;
          } else s.lose = true;
        }
      },
      draw(s, p, g2) {
        g2.fillStyle = AR_G[1]; g2.fillRect(0, 84, AR_W, 12); // regolith
        g2.fillStyle = AR_G[0]; g2.fillRect(Math.round(s.padX), 82, s.padW, 3); // THE pad
        arText(g2, '▼', Math.round(s.padX + s.padW / 2 - 3), 80, 0, 8);
        g2.fillStyle = AR_G[0];
        g2.fillRect(Math.round(s.x - 4), Math.round(s.y - 3), 8, 6); // hull
        g2.fillRect(Math.round(s.x - 6), Math.round(s.y + 3), 3, 3); g2.fillRect(Math.round(s.x + 3), Math.round(s.y + 3), 3, 3); // legs
        if (s.t % 6 < 3) { /* flame flickers only while burning */ }
        arText(g2, 'vy ' + s.vy.toFixed(1), 8, 12, s.vy > (p.soft || 1.05) ? 0 : 1, 8);
        arText(g2, s.done + '/' + (p.landings || 1), 140, 10);
      }
    },
    asteroids: {
      // [◄][►] rotate · HOLD [A] thrust · the cannon fires itself.
      // rocks split. space wraps. physics forgives nothing.
      init(s, p) {
        s.x = AR_W / 2; s.y = AR_H / 2; s.vx = 0; s.vy = 0; s.ang = -Math.PI / 2;
        s.shots = []; s.cool = 0; s.kills = 0;
        // speed param = how much grudge the rocks hold (deluxe: more)
        const sp = 0.7 + (p.speed || 2) * 0.15;
        s.rockSp = sp;
        s.rocks = [];
        for (let i = 0; i < 3; i++) {
          const a = Math.random() * 6.28;
          s.rocks.push({ x: (AR_W / 2 + Math.cos(a) * 58 + AR_W) % AR_W, y: (AR_H / 2 + Math.sin(a) * 36 + AR_H) % AR_H, vx: (Math.random() - 0.5) * 0.8 * sp, vy: (Math.random() - 0.5) * 0.6 * sp, r: 9 });
        }
      },
      tick(s, p, inp) {
        if (inp.left) s.ang -= 0.075;
        if (inp.right) s.ang += 0.075;
        if (inp.aHeld) { s.vx += Math.cos(s.ang) * 0.06; s.vy += Math.sin(s.ang) * 0.06; }
        s.vx *= 0.985; s.vy *= 0.985;
        s.x = (s.x + s.vx + AR_W) % AR_W; s.y = (s.y + s.vy + AR_H) % AR_H;
        if (--s.cool <= 0) { s.shots.push({ x: s.x, y: s.y, vx: Math.cos(s.ang) * 2.6, vy: Math.sin(s.ang) * 2.6, ttl: 46 }); s.cool = 22; playTone(1500, 'square', 0.02, 0, 0.015); }
        s.shots.forEach((sh) => { sh.x = (sh.x + sh.vx + AR_W) % AR_W; sh.y = (sh.y + sh.vy + AR_H) % AR_H; sh.ttl--; });
        s.shots = s.shots.filter((sh) => sh.ttl > 0);
        s.rocks.forEach((rk) => { rk.x = (rk.x + rk.vx + AR_W) % AR_W; rk.y = (rk.y + rk.vy + AR_H) % AR_H; });
        s.shots = s.shots.filter((sh) => {
          const i = s.rocks.findIndex((rk) => Math.hypot(rk.x - sh.x, rk.y - sh.y) < rk.r + 2);
          if (i < 0) return true;
          const rk = s.rocks.splice(i, 1)[0];
          s.kills++;
          playTone(300 + Math.random() * 200, 'square', 0.06, 0, 0.04);
          if (rk.r > 6) for (let k = 0; k < 2; k++) s.rocks.push({ x: rk.x, y: rk.y, vx: (Math.random() - 0.5) * 1.4 * (s.rockSp || 1), vy: (Math.random() - 0.5) * 1.1 * (s.rockSp || 1), r: 5 });
          return false;
        });
        if (!s.rocks.length) { s.win = true; return; }
        if (s.t > 60 && s.rocks.some((rk) => Math.hypot(rk.x - s.x, rk.y - s.y) < rk.r + 4)) s.lose = true;
      },
      draw(s, p, g2) {
        g2.strokeStyle = AR_G[0]; g2.lineWidth = 1;
        s.rocks.forEach((rk) => { g2.beginPath(); g2.arc(rk.x, rk.y, rk.r, 0, 6.3); g2.stroke(); });
        g2.fillStyle = AR_G[0];
        s.shots.forEach((sh) => g2.fillRect(Math.round(sh.x - 1), Math.round(sh.y - 1), 2, 2));
        const c = Math.cos(s.ang), n = Math.sin(s.ang);
        g2.beginPath();
        g2.moveTo(s.x + c * 6, s.y + n * 6);
        g2.lineTo(s.x - c * 4 - n * 4, s.y - n * 4 + c * 4);
        g2.lineTo(s.x - c * 4 + n * 4, s.y - n * 4 - c * 4);
        g2.closePath(); g2.stroke();
        arText(g2, s.kills + '/9', 140, 10);
      }
    },
    missile: {
      // they are falling on the meadow. [◄][►] aim · [A] pop the umbrella
      init(s, p) {
        s.cx = AR_W / 2;
        s.bases = [30, 80, 130].map((x) => ({ x, alive: true }));
        s.miss = []; s.booms = []; s.down = 0; s.spawn = 60;
      },
      tick(s, p, inp) {
        if (inp.left) s.cx = Math.max(10, s.cx - 2.4);
        if (inp.right) s.cx = Math.min(AR_W - 10, s.cx + 2.4);
        if (inp.a) { s.booms.push({ x: s.cx, y: 38, r: 2 }); playTone(220, 'sawtooth', 0.1, 0, 0.05); }
        if (--s.spawn <= 0) {
          s.spawn = Math.max(46, 92 - (p.speed || 2) * 12 - s.down * 2);
          const alive = s.bases.filter((b) => b.alive);
          if (alive.length) {
            const tgt = alive[Math.floor(Math.random() * alive.length)];
            const sx = 10 + Math.random() * (AR_W - 20);
            s.miss.push({ sx, sy: 0, x: sx, y: 0, tx: tgt.x, ty: 80, v: 0.34 + (p.speed || 2) * 0.1 });
          }
        }
        s.miss.forEach((m) => {
          const d = Math.hypot(m.tx - m.x, m.ty - m.y) || 1;
          m.x += (m.tx - m.x) / d * m.v; m.y += (m.ty - m.y) / d * m.v;
        });
        s.booms.forEach((b) => { b.r += 0.9; });
        s.booms = s.booms.filter((b) => b.r < 15);
        s.miss = s.miss.filter((m) => {
          if (s.booms.some((b) => Math.hypot(b.x - m.x, b.y - m.y) < b.r + 2)) {
            s.down++; playTone(980, 'square', 0.05, 0, 0.03);
            if (s.down >= (p.down || 8)) s.win = true;
            return false;
          }
          if (m.y >= 78) {
            const base = s.bases.find((bb) => bb.alive && Math.abs(bb.x - m.tx) < 6);
            if (base) { base.alive = false; playTone(120, 'sawtooth', 0.3, 0, 0.09); if (!s.bases.some((bb) => bb.alive)) s.lose = true; }
            return false;
          }
          return true;
        });
      },
      draw(s, p, g2) {
        g2.strokeStyle = AR_G[2]; g2.lineWidth = 1;
        s.miss.forEach((m) => { g2.beginPath(); g2.moveTo(m.sx, m.sy); g2.lineTo(m.x, m.y); g2.stroke(); });
        g2.fillStyle = AR_G[0];
        s.miss.forEach((m) => g2.fillRect(Math.round(m.x - 1), Math.round(m.y - 1), 3, 3));
        g2.strokeStyle = AR_G[0];
        s.booms.forEach((b) => { g2.beginPath(); g2.arc(b.x, b.y, b.r, 0, 6.3); g2.stroke(); });
        s.bases.forEach((b) => arDrawGlyph(g2, b.alive ? (p.base || '🌱') : '·', b.x, 84, 12));
        g2.strokeRect(Math.round(s.cx - 4), 34, 8, 8);
        g2.fillRect(Math.round(s.cx - 1), 30, 2, 4); g2.fillRect(Math.round(s.cx - 1), 44, 2, 4);
        arText(g2, s.down + '/' + (p.down || 8), 140, 10);
      }
    },
    centipede: {
      // the worm serpentines DOWN. [◄][►] move · HOLD [A] to spray
      init(s, p) {
        s.px = AR_W / 2; s.shots = []; s.cool = 0; s.kills = 0;
        s.segs = []; for (let i = 0; i < 10; i++) s.segs.push({ x: -i * 9, y: 12, dir: 1 });
      },
      tick(s, p, inp) {
        if (inp.left) s.px = Math.max(8, s.px - 2.5);
        if (inp.right) s.px = Math.min(AR_W - 8, s.px + 2.5);
        if (s.cool > 0) s.cool--;
        if (inp.aHeld && s.cool <= 0) { s.shots.push({ x: s.px, y: 78 }); s.cool = 12; playTone(1300, 'square', 0.03, 0, 0.02); }
        s.shots.forEach((sh) => { sh.y -= 2.8; });
        s.shots = s.shots.filter((sh) => sh.y > -4);
        const v = 0.75 + (p.speed || 2) * 0.2;
        s.segs.forEach((sg) => {
          sg.x += sg.dir * v;
          if (sg.x > AR_W - 6 && sg.dir > 0) { sg.dir = -1; sg.y += 9; sg.x = AR_W - 6; }
          else if (sg.x < 6 && sg.dir < 0) { sg.dir = 1; sg.y += 9; sg.x = 6; }
        });
        s.shots = s.shots.filter((sh) => {
          const i = s.segs.findIndex((sg) => Math.abs(sg.x - sh.x) < 6 && Math.abs(sg.y - sh.y) < 6);
          if (i < 0) return true;
          s.segs.splice(i, 1); s.kills++;
          playTone(700 + s.kills * 40, 'square', 0.05, 0, 0.03);
          return false;
        });
        if (!s.segs.length) { s.win = true; return; }
        if (s.segs.some((sg) => sg.y > 70)) s.lose = true;
      },
      draw(s, p, g2) {
        s.segs.forEach((sg, i) => {
          g2.fillStyle = i === 0 ? AR_G[0] : AR_G[1];
          g2.fillRect(Math.round(sg.x - 4), Math.round(sg.y - 4), 8, 8);
        });
        g2.fillStyle = AR_G[0];
        s.shots.forEach((sh) => g2.fillRect(Math.round(sh.x - 1), Math.round(sh.y - 4), 2, 6));
        g2.fillRect(Math.round(s.px - 6), 80, 12, 4); g2.fillRect(Math.round(s.px - 1), 76, 2, 4);
        arText(g2, s.kills + '/10', 136, 10);
      }
    },
    pongvs: {
      // an actual OPPONENT. [◄][►] paddle · first to 3 · no mercy (some mercy)
      init(s, p) {
        s.px = AR_W / 2; s.cx = AR_W / 2; s.you = 0; s.cpu = 0; s.hold = 40;
        s.bx = AR_W / 2; s.by = AR_H / 2; s.vx = 0.9; s.vy = 1.15 + (p.speed || 2) * 0.15;
      },
      tick(s, p, inp) {
        if (inp.left) s.px = Math.max(14, s.px - 2.6);
        if (inp.right) s.px = Math.min(AR_W - 14, s.px + 2.6);
        const cv = 1.1 + (p.speed || 2) * 0.12;
        if (s.cx < s.bx - 3) s.cx = Math.min(s.cx + cv, AR_W - 14);
        else if (s.cx > s.bx + 3) s.cx = Math.max(s.cx - cv, 14);
        if (s.hold > 0) { s.hold--; return; }
        s.bx += s.vx; s.by += s.vy;
        if (s.bx < 5 || s.bx > AR_W - 5) s.vx *= -1;
        if (s.by > 74 && s.by < 82 && Math.abs(s.bx - s.px) < 13 && s.vy > 0) { s.vy = -Math.abs(s.vy) * 1.03; s.vx += (s.bx - s.px) * 0.06; playTone(880, 'square', 0.04, 0, 0.02); }
        if (s.by < 20 && s.by > 12 && Math.abs(s.bx - s.cx) < 13 && s.vy < 0) { s.vy = Math.abs(s.vy) * 1.02; s.vx += (s.bx - s.cx) * 0.05; playTone(520, 'square', 0.04, 0, 0.02); }
        s.vx = Math.max(-2.2, Math.min(2.2, s.vx));
        const reset = (dir) => { s.bx = AR_W / 2; s.by = AR_H / 2; s.vx = (Math.random() < 0.5 ? -1 : 1) * 0.9; s.vy = dir * (1.15 + (p.speed || 2) * 0.15); s.hold = 45; };
        if (s.by > AR_H + 4) { s.cpu++; playTone(200, 'square', 0.1, 0, 0.05); if (s.cpu >= (p.goals || 3)) { s.lose = true; return; } reset(-1); }
        if (s.by < -4) { s.you++; playTone(1175, 'triangle', 0.1, 0, 0.05); if (s.you >= (p.goals || 3)) { s.win = true; return; } reset(1); }
      },
      draw(s, p, g2) {
        g2.fillStyle = AR_G[2];
        for (let x = 4; x < AR_W; x += 12) g2.fillRect(x, AR_H / 2, 6, 1);
        g2.fillStyle = AR_G[1]; g2.fillRect(Math.round(s.cx - 12), 14, 24, 4);
        g2.fillStyle = AR_G[0]; g2.fillRect(Math.round(s.px - 12), 78, 24, 4);
        arDrawGlyph(g2, p.ball || '🟢', s.bx, s.by, 10);
        arText(g2, trT('you', 'toi') + ' ' + s.you + ' — ' + s.cpu + ' cpu', 54, 10);
      }
    },
    tapper: {
      // thirsty customers shuffle toward the bar. send boba down their
      // lane before anyone reaches the counter: [◄]=top [A]=mid [►]=low
      init(s, p) {
        s.lanes = [26, 48, 70];
        s.cust = []; s.drinks = []; s.served = 0; s.spawn = 70;
      },
      tick(s, p, inp) {
        if (--s.spawn <= 0) {
          s.spawn = Math.max(40, 95 - (p.speed || 2) * 12 - s.served * 3);
          s.cust.push({ lane: Math.floor(Math.random() * 3), x: AR_W + 8, v: 0.3 + (p.speed || 2) * 0.08 + Math.random() * 0.15 });
        }
        const press = inp.leftEdge ? 0 : (inp.a ? 1 : (inp.rightEdge ? 2 : null));
        if (press != null) { s.drinks.push({ lane: press, x: 20 }); playTone(760, 'square', 0.05, 0, 0.03); }
        s.cust.forEach((c) => { c.x -= c.v; });
        s.drinks.forEach((d) => { d.x += 2.4; });
        s.drinks = s.drinks.filter((d) => {
          const c = s.cust.find((cc) => cc.lane === d.lane && Math.abs(cc.x - d.x) < 8);
          if (c) {
            s.cust.splice(s.cust.indexOf(c), 1); s.served++;
            playTone(1046, 'triangle', 0.07, 0, 0.04);
            if (s.served >= (p.serves || 8)) s.win = true;
            return false;
          }
          return d.x < AR_W + 10;
        });
        if (s.cust.some((c) => c.x < 16)) s.lose = true;
      },
      draw(s, p, g2) {
        g2.fillStyle = AR_G[1]; g2.fillRect(8, 16, 5, 62); // the bar
        g2.fillStyle = AR_G[2];
        s.lanes.forEach((ly) => g2.fillRect(13, ly + 7, AR_W - 18, 1));
        s.cust.forEach((c) => arDrawGlyph(g2, p.thirsty || '🥺', c.x, s.lanes[c.lane], 12));
        s.drinks.forEach((d) => arDrawGlyph(g2, p.drink || '🧋', d.x, s.lanes[d.lane], 11));
        s.lanes.forEach((ly, i) => arText(g2, i === 0 ? '◄' : i === 1 ? 'A' : '►', 1, ly + 3, 1));
        arText(g2, s.served + '/' + (p.serves || 8), 136, 10);
      }
    }
  };

