  function geoCrewExit() {
    if (!dreamWorld) return;
    const gf = dreamWorld.flags.geoFix;
    const par = gf && gf.par;
    if (!par || !document.body.contains(par)) return;
    if (REDUCED_MOTION) { try { par.remove(); } catch (e) {} return; }
    const x0 = parseFloat(par.style.left) || 18, t0 = Date.now(), DUR = 18000; // they leave the way they work: unhurried
    const W = par.getBoundingClientRect().width + 80;
    const iv = dI(() => {
      const p = Math.min(1, (Date.now() - t0) / DUR);
      par.style.left = (x0 - (x0 + W) * p) + 'px';
      if (p >= 1) { clearInterval(iv); try { par.remove(); } catch (e) { /* already in the van */ } }
    }, 60);
  }
  // undo the outage (cones + wrecked interiors); contract effects stay until wake
  function geoFixRestore() {
    // v179: undo the REAL damage first — text back, listeners unblocked,
    // hidden children re-shown
    const gR = dreamWorld && dreamWorld.flags.geoFix;
    if (gR && gR.realWrecks) {
      Object.keys(gR.realWrecks).forEach((k) => { try { gR.realWrecks[k](); } catch (e) { /* best effort */ } });
      gR.realWrecks = {};
    }
    document.querySelectorAll('.geo-broken-cone').forEach((n) => { try { n.remove(); } catch (e) { /* pocketed */ } });
    document.querySelectorAll('.geo-broken').forEach((el) => { el.classList.remove('geo-broken'); try { delete el.__geoBrokenSeen; } catch (e) { /* sticky note stays */ } });
    document.querySelectorAll('.geo-wreck-loading').forEach((n) => { try { n.remove(); } catch (e) { /* dissolved */ } });
    document.querySelectorAll('.geo-wreck-host').forEach((el) => {
      el.className = el.className.replace(/\bgeo-wreck-[a-z]+\b/g, ' ').replace(/\s+/g, ' ').trim();
    });
  }
  // full wake teardown: outage undone AND every lingering "repair" stripped
  function geoFixTeardown() {
    geoFixRestore();
    document.documentElement.classList.remove('geo-fix-sat', 'ds-blink');
    document.querySelectorAll('.geo-fix-tilt').forEach((el) => el.classList.remove('geo-fix-tilt'));
  }

  /* v98: bsod's signature beat used to replay the same error dialog
     every 48s — a nag, not a crash. now it's the ERROR CASCADE: the
     reporter crashes, the reports about the report crash, everything
     merges into one big feeling. plays ONCE per dream; every later
     beat falls through to small ambient bits instead. */
  function dwBeatErrorReport() {
    if (!dreamWorld) return;
    if (!dreamWorld.flags.bsodCascade) {
      if (document.querySelector('.dream-dlg')) return; // wait for a clear stage; retries in 48s
      dreamWorld.flags.bsodCascade = 1;
      dwBsodCascade();
      return;
    }
    dwBsodAmbient();
  }

