  /* ---- the narrator: countdown bubbles from the habitat, as ordered ---- */
  const DREAM_TICK_LINES = [
    ["zzz… ⏳ {m} min left in this dream… it's a good one…", "zzz… ⏳ encore {m} min de rêve… il est réussi celui-là…"],
    ["*snore* …dream holding steady… {m} min of magic left… do not wake…", "*ronfle* …rêve stable… {m} min de magie restantes… ne pas réveiller…"],
    ["zzz… the dream says {m} more minutes… the dream is very persuasive…", "zzz… le rêve dit encore {m} minutes… le rêve est très persuasif…"]
  ];
  function dreamNarrator(resumed) {
    if (!dreamWorld) return;
    const w = dreamWorld.w;
    dT(() => {
      if (!dreamWorld) return;
      dreamSay([
        '💭 dreaming of ' + w.name[0] + '!! the whole site came WITH me… ⏳ ~' + dreamMinLeft() + ' min — knock on my screen to pop it early ♡',
        '💭 je rêve de ' + w.name[1] + ' !! tout le site est venu AVEC moi… ⏳ ~' + dreamMinLeft() + ' min — toque sur mon écran pour le faire éclater ♡'
      ], 7800);
    }, resumed ? 2500 : 6500);
    dreamWorld.flags.lastTick = Date.now();
    dI(() => {
      if (!dreamWorld) return;
      const left = dreamWorld.until - Date.now();
      const now = Date.now();
      if (left <= 15000) {
        if (!dreamWorld.flags.saidFinal) {
          dreamWorld.flags.saidFinal = true;
          dreamSay(["zzz… 3… 2… 1½… (dream math)…", "zzz… 3… 2… 1½… (maths de rêve)…"], 5000);
        }
        return;
      }
      if (left <= 70000) {
        if (!dreamWorld.flags.saidMinute) {
          dreamWorld.flags.saidMinute = true;
          dreamSay(["zzz… ⏳ last minute of the dream… quick, look at everything again…", "zzz… ⏳ dernière minute du rêve… vite, re-regarde tout…"], 5200);
        }
        return;
      }
      if (now - dreamWorld.flags.lastTick < 58000) return;
      dreamWorld.flags.lastTick = now;
      const m = dreamMinLeft();
      if (Math.random() < 0.5 && w.flavor.length) {
        const f = w.flavor[Math.floor(Math.random() * w.flavor.length)];
        dreamSay([f[0] + ' (⏳ ' + m + ' min)', f[1] + ' (⏳ ' + m + ' min)'], 4600);
      } else {
        const tpl = DREAM_TICK_LINES[Math.floor(Math.random() * DREAM_TICK_LINES.length)];
        dreamSay([tpl[0].replace('{m}', m), tpl[1].replace('{m}', m)], 4600);
      }
      playTone(262, 'sine', 0.3, 0, 0.02);
    }, 8000);
  }

  function dreamEnd(reason) {
    if (!dreamWorld || dreamEnding) return;
    // v6.5: natural endings get a 1.4s COLLAPSE first — reality wobbles,
    // one last cameo dashes through, and THEN the dream lets go
    if (reason === 'timer' && !REDUCED_MOTION && !dreamWorld.flags.collapsing) {
      dreamWorld.flags.collapsing = true;
      document.documentElement.classList.add('dream-collapse');
      playGlitchSound();
      try { dwCrossover(); } catch (e) { /* the cameo missed its cue */ }
      setTimeout(() => { document.documentElement.classList.remove('dream-collapse'); dreamEnd('timer'); }, 1400);
      return;
    }
    dreamEnding = true;
    document.documentElement.classList.remove('dream-collapse');
    const w = dreamWorld.w;
    // some worlds pick their wake line from what actually happened (geo:
    // no claiming a guestbook signature nobody made) — decided while the
    // flags still exist, spoken after teardown
    let wakeLine = w.wake;
    try { if (typeof w.wakePick === 'function') wakeLine = w.wakePick(dreamWorld.flags) || w.wake; } catch (e) { /* the memory blurred */ }
    (dreamWorld.flags.removers || []).forEach((fn) => { try { fn(); } catch (e) { /* already unplugged */ } });
    try { dreamAdaptOff(); } catch (e) { /* the theme leaves anyway */ }
    dreamWorld.timers.forEach((t) => { clearTimeout(t); clearInterval(t); });
    if (w.exit) { try { w.exit(); } catch (e) { /* the dream keeps its secrets */ } }
    // fold the card table properly: node teardown alone leaves dwcState
    // dangling, and the hearts fidget intervals idle forever against it
    try { if (typeof dwcClose === 'function') dwcClose(); } catch (e) { /* already folded */ }
    try { fwDreamDress(null); } catch (e) { /* the wall wakes on its own */ }
    dreamWorld.nodes.forEach((n) => { try { n.remove(); } catch (e) { /* already gone */ } });
    document.querySelectorAll('.dream-dlg, .scp-lock, .dream-geo-tape, .dream-slippy, .dream-gb-tetro, .dream-amber-slip, .geo-fix-sign, .geo-crew-parade, .geo-fix-follower, .geo-crew-porter, .geo-broken-cone').forEach((n) => n.remove());
    // the dream journal exists only inside dreams — it closes with the world
    try {
      const dlWin = document.getElementById('win-dreamlog');
      if (dlWin && !dlWin.classList.contains('window-closed')) closeWindow(dlWin);
    } catch (e) { /* the journal tucked itself in */ }
    document.querySelectorAll('.scp-locked-body').forEach((n) => n.classList.remove('scp-locked-body'));
    document.documentElement.classList.remove('dreaming', w.cls);
    try { gSyncDreamSkin(); } catch (e) { /* the arcade wakes later */ }
    store.set('yos-dream', null);
    store.set('yos-dream-cd', Date.now() + 6 * 60000); // one reality bend per while
    dreamWorld = null;
    // re-dress AFTER dreamWorld is nulled — wardrobePool() keys off it, and
    // the old order woke the slime still wearing the dream world's rack
    try { rotateOutfit(false); } catch (e) { /* home rack, whenever it's ready */ }
    if (reason === 'timer') {
      cheatFall(['💭', '✦', '♡'], 16);
      playStartupChime();
      ghostAppear(0, false);
      showBubble(trT(...wakeLine), 6800);
      try {
        const r = slimeBody.getBoundingClientRect();
        swProp(r.left + r.width / 2 - 66, Math.max(8, r.top - 46), trT('DREAM — COMPLETE 💭', 'RÊVE — TERMINÉ 💭'), true);
      } catch (e) { /* the feeling stands */ }
    } else if (reason === 'wake' || reason === 'redpill') {
      playDreamPop();
      if (!REDUCED_MOTION) {
        const f = document.createElement('div');
        f.className = 'dream-flash dream-pop-flash';
        document.body.appendChild(f);
        setTimeout(() => f.remove(), 900);
      }
      achvUnlock('dreamwake');
      ghostAppear(0, false);
      showBubble(reason === 'redpill'
        ? trT('🔴 *gasp* how deep does the pixel-hole go— oh. bedroom. it goes to my bedroom ♡', '🔴 *sursaut* jusqu\'où va le terrier de pixels— ah. la chambre. il va jusqu\'à ma chambre ♡')
        : trT('HUH?! who— what— …you POPPED my dream?! …fair. it was getting weird in there ♡', 'HEIN ?! qui— quoi— …tu as ÉCLATÉ mon rêve ?! …ok, juste. ça devenait bizarre là-dedans ♡'), 6200);
      burstAtSlime(['💭', '💥', '♡'], 7);
    } else {
      // quiet teardown (sunrise, theme flip): dreams evaporate politely
      showToast(trT('☀ the dream evaporated', '☀ le rêve s\'est évaporé'));
    }
    dreamEnding = false;
    dreamArmCooldown(); // the next dream world earns its slot in active time
    // gremlin hour resumes its parade the moment the stage is clear
    if (swTricksterOn() && resolvedTheme() === 'dark') {
      if (sleepwalkTimer) clearTimeout(sleepwalkTimer);
      sleepwalkTimer = setTimeout(() => { if (ghostHidden()) startSleepwalk(); }, 30000);
    }
  }

  function dreamArmCooldown() {
    // owner decree v126: fifteen minutes of ACTIVE time between dreams
    // (was a full hour — too long). parked tabs still don't serve time:
    // the ledger only ticks while the visitor is actually here.
    dreamAcdLeft = 15 * 60 * 1000;
    store.set('yos-dream-acd', dreamAcdLeft);
  }
  function dreamResume() {
    if (dreamWorld || sleepwalkActive) return; // never hijack a dream ritual in progress
    const saved = store.get('yos-dream', null);
    if (!saved || !saved.id) return;
    const remain = saved.until - Date.now();
    const w = DREAM_WORLDS.find((x) => x.id === saved.id);
    if (!w || remain < 30000 || document.body.classList.contains('terminal-only')) {
      store.set('yos-dream', null);
      return;
    }
    dreamBegin(w, remain, true);
  }

  /* ---- gremlin merch: crayon graffiti (click to clean, if you must) ---- */
  var swGraffitiAt = 0;
  function swGraffiti(target) {
    if (Date.now() - swGraffitiAt < 90000 || document.querySelector('.sw-graffiti')) return;
    swGraffitiAt = Date.now();
    const r = target.getBoundingClientRect();
    const w = 130, h = 72;
    const el = document.createElement('div');
    el.className = 'sw-graffiti';
    let d = 'M 8 ' + (18 + Math.random() * 34).toFixed(0);
    let px2 = 8;
    while (px2 < w - 14) {
      px2 += 14 + Math.random() * 14;
      d += ' Q ' + (px2 - 9).toFixed(0) + ' ' + (Math.random() * h).toFixed(0) + ', ' + px2.toFixed(0) + ' ' + (10 + Math.random() * (h - 20)).toFixed(0);
    }
    el.innerHTML = '<svg width="' + w + '" height="' + h + '" viewBox="0 0 ' + w + ' ' + h + '"><path d="' + d + '" fill="none" stroke="#ff8fc7" stroke-width="5" stroke-linecap="round" stroke-linejoin="round"/><path d="' + d + '" fill="none" stroke="#ffd23f" stroke-width="2" stroke-linecap="round" stroke-dasharray="3 7"/></svg><small>' + trT('art. do not remove ♡', 'de l\'art. ne pas retirer ♡') + '</small>';
    el.style.left = Math.max(8, Math.min(window.innerWidth - w - 12, r.left + r.width / 2 - w / 2 + (Math.random() - 0.5) * 60)) + 'px';
    el.style.top = Math.max(70, Math.min(window.innerHeight - h - 90, r.top + 30)) + 'px';
    el.addEventListener('click', () => {
      el.classList.add('sw-graffiti-fade');
      playDreamPop();
      gainFollowers(1);
      showToast(trT('🧽 art removed. the artist will hear about this.', '🧽 œuvre retirée. l\'artiste en sera informé.'));
      setTimeout(() => el.remove(), 1000);
    }, { once: true });
    document.body.appendChild(el);
    setTimeout(() => { if (el.isConnected) { el.classList.add('sw-graffiti-fade'); setTimeout(() => el.remove(), 1200); } }, 120000);
  }

  /* ---- gremlin merch: the sticky note (peelable, signed, dated) ---- */
  var swStickyAt = 0;
  function swStickyNote(target) {
    if (Date.now() - swStickyAt < 60000) return; // one note a minute; glue is precious
    if (document.querySelector('.sw-sticky')) return;
    swStickyAt = Date.now();
    const r = target.getBoundingClientRect();
    const n = document.createElement('button');
    n.type = 'button';
    n.className = 'sw-sticky';
    const msg = swScenePick([
      ['zzz was here ♡', 'zzz est passé ici ♡'],
      ['do NOT read this note. (you did. hi ♡)', 'ne lis PAS ce mot. (tu l\'as lu. coucou ♡)'],
      ['inspected. certified cute. —the dream', 'inspecté. certifié mignon. —le rêve'],
      ['TODO: dream about this again', 'TODO : re-rêver de ça']
    ]);
    n.innerHTML = '<span>' + trT(...msg) + '</span><small>— 💤 gremlin dept.</small>';
    n.style.left = Math.max(8, Math.min(window.innerWidth - 150, r.left + r.width / 2 + 20)) + 'px';
    n.style.top = Math.max(60, Math.min(window.innerHeight - 140, r.top + 8)) + 'px';
    n.style.setProperty('--peel-rot', (Math.random() * 10 - 5).toFixed(1) + 'deg');
    n.addEventListener('click', () => {
      n.classList.add('sw-sticky-peel');
      playDreamPop();
      gainFollowers(1);
      setTimeout(() => n.remove(), 700);
    }, { once: true });
    document.body.appendChild(n);
    setTimeout(() => { if (n.isConnected) { n.classList.add('sw-sticky-fade'); setTimeout(() => n.remove(), 1200); } }, 100000);
  }

  var nightFirstTimer = null;

  var nightExpressTimer = null;
  var nightExpressArmed = false; // fires once per nightfall, not once per sync
  function syncGhostMode() {
    if (!slimeBody) return;
    if (resolvedTheme() === 'dark') {
      // house rule: bedtime is announced within 5 seconds of nightfall
      if (nightFirstTimer) clearTimeout(nightFirstTimer);
      nightFirstTimer = setTimeout(nightRetireNow, 2100);
      nightLoop();
      // v5.2: if a dream curfew is pending (or expired while the lights
      // were on), nightfall is when the lift ceremony gets its audience
      swScheduleLift();
      // v6.0: a dream world interrupted by a reload picks itself back up
      dreamResume();
      // v84: THE NIGHT EXPRESS — a visitor who has already played skips
      // every queue: nightfall goes STRAIGHT into the seven dream worlds.
      // no curfew gate, no arcade funnel (swGameChance is 0 for them too).
      if (!nightExpressArmed && store.get('yos-played', null)
        && window.innerWidth >= 560 && !document.body.classList.contains('terminal-only')) {
        nightExpressArmed = true;
        if (nightExpressTimer) clearTimeout(nightExpressTimer);
        nightExpressTimer = setTimeout(() => {
          nightExpressTimer = null;
          if (resolvedTheme() !== 'dark' || dreamActive() || document.body.classList.contains('terminal-only')) return;
          store.set('yos-dream-cd', 0); // veterans don't wait for cooldowns
          const w = DREAM_WORLDS[Math.floor(Math.random() * DREAM_WORLDS.length)];
          if (slimeBody) slimeBody.classList.add('is-ghost-hidden');
          try { startDreamWalk(w); } catch (e) { /* the express slipped on a rail */ }
        }, 8000); // bedtime ceremony first (2.1s), then straight to dreamland
      }
    } else {
      // sunrise: dream worlds evaporate before the lights come on
      if (dreamActive()) dreamEnd('quiet');
      if (nightLoopTimer) clearTimeout(nightLoopTimer);
      if (nightRetireTimer) clearTimeout(nightRetireTimer);
      if (nightFirstTimer) clearTimeout(nightFirstTimer);
      if (nightExpressTimer) { clearTimeout(nightExpressTimer); nightExpressTimer = null; }
      nightExpressArmed = false; // next nightfall gets a fresh express
      cancelSleepwalk();
      slimeBody.classList.remove('is-ghost-hidden');
    }
  }

  // knocking on the habitat wakes the sleeping slime — and knocking
  // during a dream world pops the whole bubble (the documented exit)
  if (slimeHabitat) {
    slimeHabitat.addEventListener('click', (e) => {
      if (e.target.closest('.slime-pet')) return; // petting is always petting (even entity forms)
      if (dreamActive()) { dreamEnd('wake'); gainFollowers(1); return; }
      if (!ghostHidden()) return;
      ghostAppear(0, awayLine('wake'));
      gainFollowers(1);
    });
  }

  function setThemePref(pref) {
    themePref = pref;
    store.set('yos-theme', pref);
    applyTheme();
    scheduleSkyFlips(); // auto mode books its 21:00 / 08:00 theatre slots
  }

  /* =====================================================
     v6.1 — THE 9PM CEREMONY 🌙 (and the 8AM goose)
     in auto mode the clock flips the lights at 21:00 and
     08:00 — and a flip deserves THEATRE. at dusk the slime
     shuffles in, reads yongshan's quiet-hours decree, and
     pulls the BIG SWITCH; at dawn a goose handles the
     honking. hidden cheats `sunset` / `sunrise` replay
     them on demand (and flip the theme for real).
     ===================================================== */
  var skyFlipTimers = [];
  var skyCineBusy = false;

  function scheduleSkyFlips() {
    skyFlipTimers.forEach(clearTimeout);
    skyFlipTimers = [];
    if (themePref !== 'auto') return;
    const now = new Date();
    const msTo = (h) => {
      const d = new Date(now);
      d.setHours(h, 0, 2, 0); // :02 — land firmly inside the new hour
      if (d <= now) d.setDate(d.getDate() + 1);
      return d.getTime() - now.getTime();
    };
    skyFlipTimers.push(setTimeout(() => skyFlipNow(true), msTo(21)));
    skyFlipTimers.push(setTimeout(() => skyFlipNow(false), msTo(8)));
  }

  function skyFlipNow(toDark) {
    scheduleSkyFlips(); // re-book tomorrow FIRST — theatre may misbehave
    if (themePref !== 'auto') return;
    const want = toDark ? 'dark' : 'light';
    if (resolvedTheme() !== want) return; // the clock knows best
    const have = document.documentElement.getAttribute('data-theme') === 'dark' ? 'dark' : 'light';
    if (have === want) return; // a visibility handler already flipped it
    if (document.hidden || document.body.classList.contains('terminal-only') || REDUCED_MOTION || skyCineBusy) {
      applyTheme(); // no audience / no motion budget: flip quietly
      return;
    }
    if (toDark) duskCeremony(false);
    else dawnCeremony(false);
  }

  function cineEl(cls, parent, text) {
    const el = document.createElement('div');
    el.className = cls;
    if (text != null) el.textContent = text;
    (parent || document.body).appendChild(el);
    return el;
  }

  const DUSK_DECREES = [
    ["*yawn* 9PM!! quiet-hours decree, signed yongshan: LIGHTS OUT ♡", "*bâille* 21h !! décret des heures calmes, signé yongshan : EXTINCTION DES FEUX ♡"],
    ["it's 9PM… my legally mandated bedtime… the sun has been dismissed 📜", "il est 21h… mon coucher légalement obligatoire… le soleil est congédié 📜"],
    ["9PM sharp. yongshan's rule: night mode = cozy mode. objections? too late ♡", "21h pile. règle de yongshan : mode nuit = mode cocon. des objections ? trop tard ♡"]
  ];
  const DUSK_GOODNIGHTS = [
    ["goodnight!! the site is MINE n— zzz ♡", "bonne nuit !! le site est à MOI mainten— zzz ♡"],
    ["*tucks self in* wake me if the wifi has nightmares ♡", "*se borde tout seul* réveillez-moi si le wifi fait des cauchemars ♡"]
  ];

  function duskCeremony(force) {
    if (skyCineBusy) return;
    if (REDUCED_MOTION) { if (force) setThemePref('dark'); else applyTheme(); return; }
    skyCineBusy = true;
    const cine = cineEl('sky-cine dusk-cine');
    const sky = cineEl('dusk-sky', cine);
    const sun = cineEl('dusk-sun', cine);
    // the big switch: a wall plate with one very important lever
    const sw = cineEl('dusk-switch', cine);
    sw.innerHTML = '<span class="dusk-switch-label">DAY</span><span class="dusk-switch-lever"></span><span class="dusk-switch-label">NITE</span>';
    // the officiant, in its little nightcap
    const slime = cineEl('dusk-slime', cine);
    const simg = document.createElement('img');
    simg.src = (OUTFIT_FRAMES && typeof OUTFIT_FRAMES.sleep === 'string' && OUTFIT_FRAMES.sleep) || 'assets/slime_night_sleep.png';
    simg.alt = '';
    slime.appendChild(simg);
    const bub = cineEl('dusk-bubble', slime);
    const say = (pair, ms) => { bub.textContent = trT(...pair); bub.classList.add('is-on'); playTone(523, 'sine', 0.1, 0, 0.03); if (ms) setTimeout(() => bub.classList.remove('is-on'), ms); };
    playTone(392, 'sine', 0.5, 0, 0.04); // dusk settles in E-flat-ish calm
    // the decree stays up long enough to actually READ (4.6s), and the
    // officiant honours a full 2s beat after it before touching anything
    setTimeout(() => say(DUSK_DECREES[Math.floor(Math.random() * DUSK_DECREES.length)], 4600), 600);
    // 5.2s: decree read, pause respected — the officiant reaches the switch and PULLS
    setTimeout(() => {
      slime.classList.add('dusk-slime-pull');
      sw.classList.add('is-off');
      playTone(180, 'square', 0.06, 0, 0.08);
      playTone(90, 'square', 0.09, 0.06, 0.08); // CLICK. (a load-bearing click)
      const wipe = cineEl('dusk-wipe', cine);
      const r = sw.getBoundingClientRect();
      wipe.style.setProperty('--wx', (r.left + r.width / 2) + 'px');
      wipe.style.setProperty('--wy', (r.top + r.height / 2) + 'px');
      // the wipe covers the screen — swap reality underneath it
      setTimeout(() => {
        if (force) setThemePref('dark'); else applyTheme();
        [784, 659, 523, 392].forEach((f, i) => playTone(f, 'sine', 0.4, i * 0.16, 0.035)); // a 4-note lullaby
      }, 480);
      // stars clock in one by one, each with its little plink
      for (let i = 0; i < 5; i++) {
        setTimeout(() => {
          const st = cineEl('dusk-star', cine, i === 4 ? '🌙' : '✦');
          st.style.left = (12 + Math.random() * 76) + '%';
          st.style.top = (6 + Math.random() * 30) + '%';
          playTone(1046 + i * 120, 'triangle', 0.12, 0, 0.03);
        }, 900 + i * 260);
      }
    }, 5200);
    setTimeout(() => say(DUSK_GOODNIGHTS[Math.floor(Math.random() * DUSK_GOODNIGHTS.length)], 2400), 7600);
    setTimeout(() => { cine.classList.add('sky-cine-out'); }, 9400);
    setTimeout(() => { cine.remove(); skyCineBusy = false; }, 10300);
  }

  function dawnCeremony(force) {
    if (skyCineBusy) return;
    if (REDUCED_MOTION) { if (force) setThemePref('light'); else applyTheme(); return; }
    skyCineBusy = true;
    const cine = cineEl('sky-cine dawn-cine');
    const slime = cineEl('dusk-slime dawn-slime', cine);
    const simg = document.createElement('img');
    simg.src = (OUTFIT_FRAMES && typeof OUTFIT_FRAMES.sleep === 'string' && OUTFIT_FRAMES.sleep) || 'assets/slime_night_sleep.png';
    simg.alt = '';
    slime.appendChild(simg);
    const bub = cineEl('dusk-bubble', slime);
    // 0.5s: the alarm clock (it has feathers and zero mercy)
    setTimeout(() => {
      const goose = cineEl('dawn-goose', cine, '🪿');
      playTone(392, 'sawtooth', 0.16, 0, 0.07);
      playTone(311, 'sawtooth', 0.22, 0.16, 0.07); // HONK. HONK.
      setTimeout(() => goose.remove(), 2600);
    }, 500);
    setTimeout(() => {
      slime.classList.add('dawn-jolt');
      simg.src = 'assets/slime_pet_cutout.png';
      bub.textContent = trT('HONK?! …morning. lights ON — daylight is yongshan\'s productivity law ☀ (I\'ll nap anyway)', 'HONK ?! …le matin. lumières ALLUMÉES — la lumière du jour, c\'est la loi productivité de yongshan ☀ (je referai la sieste quand même)');
      bub.classList.add('is-on');
    }, 1400);
    setTimeout(() => {
      const wipe = cineEl('dawn-wipe', cine);
      wipe.style.setProperty('--wx', '50vw');
      wipe.style.setProperty('--wy', '18vh');
      setTimeout(() => {
        if (force) setThemePref('light'); else applyTheme();
        playStartupChime();
      }, 420);
      const sun = cineEl('dawn-sun', cine);
      sun.textContent = '☀';
    }, 2600);
    setTimeout(() => { cine.classList.add('sky-cine-out'); }, 5000);
    setTimeout(() => { cine.remove(); skyCineBusy = false; }, 5900);
  }

  scheduleSkyFlips(); // boot: book tonight's show

  const themeToggleBtn = document.getElementById('btn-theme-toggle');
  if (themeToggleBtn) {
    themeToggleBtn.addEventListener('click', () => {
      playSparkleSound();
      // v6.2: a 3-WAY cycle so AUTO is always reachable again. the old
      // 2-way toggle locked you into dark/light forever — one accidental
      // tap and the site could never follow the clock again (that's why
      // it stayed dark all afternoon). order: light → dark → auto → …
      const next = themePref === 'light' ? 'dark' : themePref === 'dark' ? 'auto' : 'light';
      setThemePref(next);
      const nowDark = resolvedTheme() === 'dark';
      if (next === 'auto') {
        showToast(trT('🌗 theme: AUTO — the site now follows the slime\'s (very healthy) sleep schedule: bright all day, lights out at 9pm sharp, up at 8 ♡', '🌗 thème : AUTO — le site suit désormais le rythme de sommeil (très sain) du slime : lumineux le jour, extinction à 21h pile, debout à 8h ♡'));
        if (!pet.sleeping && !pet.busy) showBubble(trT('auto mode!! the whole SITE sleeps when I sleep now. 9pm lights out, 8am stretch. dermatologist-recommended ♡', 'mode auto !! le SITE entier dort quand je dors maintenant. 21h extinction, 8h étirements. recommandé par les dermatologues ♡'), 3200);
      } else {
        showToast(t(next === 'dark' ? 'toast.dark' : 'toast.light'));
        if (!pet.sleeping && !pet.busy) {
          showBubble(nowDark ? (yosLang === 'fr' ? 'mode minuit !! les néons ♡' : 'midnight mode!! neon time ♡') : (yosLang === 'fr' ? 'le soleil ! mes pixels bronzent' : 'sunlight! my pixels are tanning'), 2200);
        }
      }
    });
    // long-press / right-click jumps straight back to AUTO — the escape hatch
    themeToggleBtn.addEventListener('contextmenu', (e) => {
      e.preventDefault();
      e.stopPropagation(); // the document-level handler would ALSO open the Y2K context menu on this gesture
      setThemePref('auto');
      playSparkleSound();
      showToast(trT('🌗 theme: AUTO — back on the clock ♡', '🌗 thème : AUTO — de retour sur l\'horloge ♡'));
    });
  }

  // follow the OS when the user hasn't forced a theme
  const onSystemThemeChange = () => { if (themePref === 'auto') applyTheme(); };
  if (darkMQ.addEventListener) darkMQ.addEventListener('change', onSystemThemeChange);
  else if (darkMQ.addListener) darkMQ.addListener(onSystemThemeChange);

  // midnight starfield (stars + occasional shooting star; the moon is retired)
  function buildNightSky() {
    // owner decrees, reconciled: the moon stays retired (v121), the STARS
    // twinkle, and the shooting stars are BACK by popular demand (v123)
    if (nightSkyBuilt) return;
    nightSkyBuilt = true;
    const sky = document.getElementById('night-sky');
    if (!sky) return;

    for (let i = 0; i < 26; i++) {
      const star = document.createElement('span');
      const roll = Math.random();
      star.className = 'ns-star' + (roll < 0.33 ? ' ns-pink' : roll < 0.6 ? ' ns-blue' : '');
      star.textContent = Math.random() < 0.5 ? '✦' : '·';
      star.style.left = `${Math.random() * 100}%`;
      star.style.top = `${Math.random() * 68}%`;
      star.style.fontSize = `${7 + Math.random() * 9}px`;
      star.style.animationDelay = `${Math.random() * 3}s`;
      sky.appendChild(star);
    }
    nsShootStart();
  }
  // shooting stars only tick while it's actually night — light mode
  // clears the interval instead of idling forever
  var nsShootTimer = null;
  function nsShootStart() {
    if (nsShootTimer || REDUCED_MOTION) return;
    const sky = document.getElementById('night-sky');
    if (!sky) return;
    nsShootTimer = setInterval(() => {
      if (document.documentElement.getAttribute('data-theme') !== 'dark') return;
      // a hidden sky (dreams, terminal door) mints no meteors — display:none
      // never fires animationend, so they'd pile up and all replay at once
      if (!sky.getClientRects().length) return;
      if (Math.random() < 0.45) return;
      const shoot = document.createElement('span');
      shoot.className = 'ns-shoot';
      shoot.style.left = `${40 + Math.random() * 55}%`;
      shoot.style.top = `${5 + Math.random() * 40}%`;
      sky.appendChild(shoot);
      shoot.addEventListener('animationend', () => shoot.remove());
    }, 7000);
  }
  function nsShootStop() {
    if (nsShootTimer) { clearInterval(nsShootTimer); nsShootTimer = null; }
  }

  /* =====================================================
     v3.0 — REAL BROWSER NAVIGATION (back / forward / reload
     + editable address bar with internal routing)
     ===================================================== */
  const WIN_URLS = {
    'win-career': 'career_quest.exe',
    'win-skills': 'inventory.sav',
    'win-chat': 'stream_chat.log',
    'win-ama': 'ask_me.chat',
    'win-terminal': 'terminal.exe',
    'win-search': 'search',
    'win-game': 'slime_run.exe',
    'win-live': 'slime_live.exe',
    'win-leaderboard': 'hall_of_slime.exe',
    'win-pikdex': 'pikdex.exe',
    'win-interview': 'interview_scheduler.exe',
    'win-education': 'education_awards.txt',
    'win-start-here': 'start_here.txt'
  };
  const ADDR_ALIASES = {
    career: 'win-career', quest: 'win-career', skills: 'win-skills', inventory: 'win-skills',
    chat: 'win-chat', stream: 'win-chat', ama: 'win-ama', ask: 'win-ama',
    terminal: 'win-terminal', term: 'win-terminal', search: 'win-search',
    game: 'win-game', run: 'win-game', play: 'win-game',
    live: 'win-live',
    pikdex: 'win-pikdex', pikmin: 'win-pikdex', dex: 'win-pikdex',
    hiscore: 'win-leaderboard', top: 'win-leaderboard', leaderboard: 'win-leaderboard', hall: 'win-leaderboard',
    interview: 'win-interview', hire: 'win-interview',
    edu: 'win-education', education: 'win-education',
    about: 'win-ama', start: 'win-start-here', help: 'win-start-here'
  };
  const HOME_URL = 'https://yongshan.dev';

  var webNav = { stack: [{ type: 'home', url: HOME_URL }], idx: 0 };

  const addrInput = document.getElementById('address-input');
  const addrForm = document.getElementById('address-form');
  const navBackBtn = document.getElementById('nav-back');
  const navFwdBtn = document.getElementById('nav-forward');
  const navReloadBtn = document.getElementById('nav-reload');

  function navCurrent() { return webNav.stack[webNav.idx]; }

  function updateAddressBar() {
    if (addrInput && document.activeElement !== addrInput) addrInput.value = navCurrent().url;
    if (navBackBtn) navBackBtn.disabled = webNav.idx <= 0;
    if (navFwdBtn) navFwdBtn.disabled = webNav.idx >= webNav.stack.length - 1;
  }

  function pushNavEntry(entry) {
    if (navCurrent() && navCurrent().url === entry.url) { updateAddressBar(); return; }
    webNav.stack = webNav.stack.slice(0, webNav.idx + 1);
    webNav.stack.push(entry);
    webNav.idx++;
    updateAddressBar();
  }

  function yosPushNav(winId) {
    pushNavEntry({ type: 'win', id: winId, url: `${HOME_URL}/${WIN_URLS[winId] || winId}` });
  }

  function execNavEntry(entry) {
    if (entry.type === 'win') {
      openWindow(entry.id, { fromHistory: true });
    } else if (entry.type === 'search') {
      renderSearch(entry.q);
      openWindow('win-search', { fromHistory: true });
    }
    updateAddressBar();
  }

  if (navBackBtn) {
    navBackBtn.addEventListener('click', () => {
      if (webNav.idx <= 0) return;
      playCloseSound();
      webNav.idx--;
      execNavEntry(navCurrent());
    });
  }
  if (navFwdBtn) {
    navFwdBtn.addEventListener('click', () => {
      if (webNav.idx >= webNav.stack.length - 1) return;
      playClickSound();
      webNav.idx++;
      execNavEntry(navCurrent());
    });
  }
  if (navReloadBtn) {
    navReloadBtn.addEventListener('click', () => {
      playClickSound();
      navReloadBtn.classList.add('reload-spin');
      const frame = document.querySelector('.browser-frame');
      if (frame) frame.classList.add('crt-flash');
      setTimeout(() => window.location.reload(), 430);
    });
  }

  /* =====================================================
     S2 EXTRAS — the traffic lights are REAL buttons now
     🔴 pink screen of death · 🟡 boss key · 🟢 fullscreen
     ===================================================== */
  var dotTuckedAway = null; // the yellow dot remembers who it tucked in
  var addrCheatTax = {};    // per-session greed ledger for address-bar cheats

  function bsodShow() {
    if (document.getElementById('yos-bsod')) return;
    const ov = document.createElement('div');
    ov.id = 'yos-bsod';
    ov.className = 'yos-bsod' + (REDUCED_MOTION ? ' bsod-still' : '');
    ov.setAttribute('role', 'alertdialog');
    ov.setAttribute('aria-label', 'SLIME_SCREEN_OF_DEATH — harmless easter egg');
    const face = document.createElement('div');
    face.className = 'bsod-face';
    face.textContent = ':(';
    const h = document.createElement('div');
    h.className = 'bsod-title';
    h.textContent = 'SLIME_SCREEN_OF_DEATH ♡';
    const body = document.createElement('div');
    body.className = 'bsod-body';
    [
      trT('your OS ran into a problem it kind of enjoys: CUTE_OVERFLOW at 0xFFB3DD', 'votre OS a rencontré un problème qui lui plaît un peu : CUTE_OVERFLOW à 0xFFB3DD'),
      trT('collecting error info… 100% (it was hearts. it was always hearts.)', 'collecte des infos d\'erreur… 100 % (c\'était des cœurs. depuis le début.)'),
      trT('press any key (or tap) to un-crash ♡', 'appuyez sur n\'importe quelle touche (ou tapotez) pour déplanter ♡')
    ].forEach((line) => {
      const p = document.createElement('p');
      p.textContent = line;
      body.appendChild(p);
    });
    ov.append(face, h, body);
    document.body.appendChild(ov);
    playTone(196, 'square', 0.22, 0, 0.06);
    playTone(147, 'square', 0.22, 0.18, 0.06);
    achvUnlock('bsod');
    const unCrash = (e) => {
      if (e && e.stopPropagation) { e.stopPropagation(); e.preventDefault(); }
      document.removeEventListener('keydown', unCrash, true);
      if (REDUCED_MOTION) { ov.remove(); return; }
      ov.classList.add('bsod-out'); // one CRT blink on the way back to life
      setTimeout(() => ov.remove(), 420);
    };
    ov.addEventListener('click', unCrash);
    document.addEventListener('keydown', unCrash, true);
  }

  function dotTuckToggle() {
    const open = [...document.querySelectorAll('.window')].filter((w) =>
      !w.classList.contains('window-closed') && !w.classList.contains('window-minimized'));
    if (open.length) {
      dotTuckedAway = open;
      open.forEach((w) => minimizeWindow(w));
      showToast(trT('everything tucked in ♡', 'tout le monde est bordé ♡'));
    } else if (dotTuckedAway && dotTuckedAway.length) {
      const batch = dotTuckedAway.filter((w) => !w.classList.contains('window-closed'));
      dotTuckedAway = null;
      batch.forEach((w) => {
        w.classList.remove('window-minimized');
        if (w.id === 'win-live' && typeof liveEnter === 'function') setTimeout(liveEnter, 120);
      });
      if (batch.length) focusWindow(batch[batch.length - 1]);
      if (typeof updateTaskbarAppButtons === 'function') updateTaskbarAppButtons();
      showToast(trT('rise and shine!! ♡', 'debout tout le monde !! ♡'));
    } else {
      showToast(trT('nothing to tuck in — the desktop is already dreaming ♡', 'rien à border — le bureau rêve déjà ♡'));
    }
  }

  function dotFullscreen() {
    const saidNo = () => showToast(trT('your browser said no… respect ♡', 'ton navigateur a dit non… respect ♡'));
    if (document.fullscreenElement) {
      if (document.exitFullscreen) document.exitFullscreen().catch(() => {});
      return;
    }
    if (!document.documentElement.requestFullscreen) { saidNo(); return; }
    const req = document.documentElement.requestFullscreen();
    if (req && req.catch) req.catch(saidNo);
  }

  const dotRed = document.querySelector('.browser-dots .dot.red');
  const dotYellow = document.querySelector('.browser-dots .dot.yellow');
