  function gSoftHit() {
    GAME.lives -= 1;
    if (GAME.lives <= 0) {
      if (GAME.fateGate) { GAME.lives = 1; return; } // fate stings, never kills at the gate
      GAME.lives = 0; gGameOver(); return;
    }
    fxInvincible(1.8);
    playGlitchSound();
  }

  function gApplyOutcome(pool, salt) {
    const o = gPick(pool, salt);
    o.fx();
    return o.t;
  }

