    const CRITTER = ['🦆', '🐛', '🐱', '🐶', '🦄', '🐸', '🐢', '🐰', '🐝', '🦋', '🐙', '🐹', '🐧', '🦩', '🐌'];
    const SPARKLE = ['💖', '💘', '💐', '🌸', '🌷', '🎀', '⭐', '✨', '🫧', '🌙', '🍀', '🎆', '🌹'];
    if (e === '🎂') return giftActCake;
    if (e === '👑') return giftActCrown;
    if (e === '🪩') return giftActDisco;
