    { run(e) { fxBanner('404: chill not found'); fxZoom(e); fxFirework('✦', 2); },
      react: ['ERROR 404: my chill?? gone. HYPED!!', 'ERREUR 404 : mon calme ?? disparu. HYPE !!'], action: 'alert' }
