  /* ---------- the living boot screen ----------
     dresses the loader from the visitor's save: their slime (boopable),
     their exact squad (colours, species hats, growth stages) marching
     underneath — plus fifty rotating boot jokes on the marquee ♡ */
  function loaderDecorate() {
    const slimeBtn = document.getElementById('loader-slime');
    if (slimeBtn && !slimeBtn._wired) {
      slimeBtn._wired = true;
      let stalls = 0;
      slimeBtn.addEventListener('click', () => {
        slimeBtn.classList.remove('is-booped');
        void slimeBtn.offsetWidth;
        slimeBtn.classList.add('is-booped');
        playTone(880 + stalls * 70, 'square', 0.06, 0, 0.03);
        if (stalls < 5) { stalls++; window.__loaderHideAt = Math.max(window.__loaderHideAt || 0, Date.now()) + 800; }
        const heart = document.createElement('span');
        heart.className = 'loader-boop-heart';
        heart.textContent = '♥';
        heart.style.left = (25 + Math.random() * 50) + '%';
        slimeBtn.appendChild(heart);
        setTimeout(() => heart.remove(), 950);
      });
    }
    const row = document.getElementById('loader-squad');
    const roster = store.get('yos-pik-roster', []);
    if (row && Array.isArray(roster) && roster.length) {
      row.innerHTML = ''; // rebuilt from the save, sprites only
      roster.slice(0, PIK_MAX).forEach((r, i) => {
        const sp = r.sp ? pikSpecies(r.sp) : null;
        const holder = document.createElement('span');
        const ldForm = (typeof pikFormOf === 'function') ? pikFormOf(r) : 1;
        holder.className = 'loader-pik' + (ldForm >= 2 ? ' pik-form' + ldForm : '');
        holder.style.animationDelay = (i * 0.13) + 's';
        const img = document.createElement('img');
        img.src = pikSprite(sp ? sp.body : ((r.h != null) ? hueColor(r.h) : (PIK_COLORS[r.c] || PIK_COLORS[0])), r.s || 0, r.sp || null, false, ldForm, typeof pikKindKey === 'function' ? pikKindKey(r) : '');
        img.alt = '';
        holder.appendChild(img);
        if (sp) {
          const hat = document.createElement('span');
          hat.className = 'loader-pik-hat';
          hat.textContent = sp.hat;
          holder.appendChild(hat);
        }
        holder.addEventListener('click', () => pikChirp());
        row.appendChild(holder);
      });
      window.__loaderHideAt = Math.max(window.__loaderHideAt || 0, Date.now() + 2400); // a beat longer to admire the crew
    }
    // the subtext is a comedy marquee: one random boot joke, rotating
    const sub = document.querySelector('#loader .loader-subtext');
    if (sub) {
      sub.removeAttribute('data-i18n'); // the jokes outrank the dictionary
      let jokeIx = Math.floor(Math.random() * LOADER_JOKES.length);
      const tellOne = () => {
        const j = LOADER_JOKES[jokeIx % LOADER_JOKES.length];
        sub.textContent = trT(j[0], j[1]);
        jokeIx++;
      };
      tellOne();
      const jokeTimer = setInterval(() => {
        const l = document.getElementById('loader');
        if (!l || l.style.display === 'none' || l.classList.contains('fade-out')) { clearInterval(jokeTimer); return; }
        tellOne();
      }, 1600);
    }
  }

  /* ---------- PIK PARADE — special commands are performed by YOUR squad ----------
     no faceless emoji rain: the visitor's own pikmin march across the
     screen. no pikmin yet? the agency dispatches LOANERS — guaranteed
     hidden species (or the chameleon), yours for exactly 5 minutes ♡ */
  const PIK_LOAN_MS = 5 * 60 * 1000;
  function pikLoanSweep() {
    const dex = pikdexGet();
    const now = Date.now();
    const keep = dex.filter((p) => !p.loan || p.loan > now);
    if (keep.length === dex.length) return;
    pikdexSave(keep);
    pikdexRosterProject();
    if (typeof deskPikResync === 'function') deskPikResync();
    renderPikdexSoon();
    showToast(trT('the loaner pikmin went home — the agency says hi ♡', 'les pikmin de prêt sont rentrés — l\'agence vous salue ♡'));
  }
  setInterval(pikLoanSweep, 30000);
  function pikEnsureCast() {
    const dex = pikdexGet();
    if (dex.length) {
      const actives = pikdexActives(dex);
      return actives.length ? actives : dex.slice(0, PIK_MAX);
    }
    // empty deck → summon 3 loaners, 100% hidden species / chameleon
    const pool = HIDDEN_SPECIES.slice();
    const picks = [];
    for (let i = 0; i < 3; i++) {
      if (i === 2 && Math.random() < 0.34) {
        picks.push({ h: 5 + Math.floor(Math.random() * 355), ch: 1, s: 2, k: PIK_SKILLS[Math.floor(Math.random() * PIK_SKILLS.length)].id, a: 1, t: Date.now(), loan: Date.now() + PIK_LOAN_MS });
        continue;
      }
      const sp = pool.splice(Math.floor(Math.random() * pool.length), 1)[0];
      picks.push({ h: 5 + Math.floor(Math.random() * 355), ch: 0, s: 2, k: PIK_SKILLS[Math.floor(Math.random() * PIK_SKILLS.length)].id, sp: sp.id, a: 1, t: Date.now(), loan: Date.now() + PIK_LOAN_MS });
    }
    pikdexSave(picks);
    pikdexRosterProject();
    if (typeof deskPikResync === 'function') deskPikResync();
    renderPikdexSoon();
    showToast(trT('no squad?! the agency dispatched 3 RARE loaners — yours for 5 minutes ♡', 'pas d\'escouade ?! l\'agence dépêche 3 prêts RARES — à vous pour 5 minutes ♡'));
    return picks;
  }
  function pikParade() {
    const cast = pikEnsureCast();
    playFanfare();
    if (REDUCED_MOTION) return cast; // the fanfare + rewards still land
    const n = Math.max(4, Math.min(9, cast.length * 2));
    for (let i = 0; i < n; i++) {
      const p = cast[i % cast.length];
      const sp = p.sp ? pikSpecies(p.sp) : null;
      const pform = typeof pikFormOf === 'function' ? pikFormOf(p) : 1;
      const el = document.createElement('div');
      el.className = 'pik-parade' + (sp && sp.fx ? ' pikfx-' + sp.fx : '') + (p.ch ? ' pikfx-rgbcycle' : '') + (pform >= 2 ? ' pik-form' + pform : '');
      const img = document.createElement('img');
      img.src = pikSprite(pikEntryColor(p), p.s || 0, p.sp || null, false, pform, pikKindKey(p));
      img.alt = '';
      el.appendChild(img);
      if (sp) {
        const hat = document.createElement('span');
        hat.className = 'pik-hat';
        hat.textContent = sp.hat;
        el.appendChild(hat);
      }
      el.style.top = (16 + Math.random() * 58) + 'vh';
      el.style.animationDelay = (i * 0.32) + 's';
      el.style.animationDuration = (4.6 + Math.random() * 2.2) + 's';
      document.body.appendChild(el);
      setTimeout(() => el.remove(), 9500);
    }
    return cast;
  }

  /* a hidden-species pull: rarer than candy, cheaper than a GPU */
  function pikHiddenCelebrate(species) {
    playFanfare();
    showToast(trT(`${species.hat}✨ HIDDEN SPECIES!! ${species.n[0]} joined the deck!!`, `${species.hat}✨ ESPÈCE CACHÉE !! ${species.n[1]} rejoint le deck !!`));
    if (!pet.sleeping) showBubble(trT(`${species.hat} a ${species.n[0]}?! check its file in pikdex.exe!!`, `${species.hat} un ${species.n[1]} ?! regarde sa fiche dans pikdex.exe !!`), 3400);
    if (REDUCED_MOTION) return;
    for (let i = 0; i < 18; i++) {
      const f = document.createElement('span');
      f.className = 'cham-burst pik-hidden-burst';
      f.textContent = species.hat;
      f.style.left = (Math.random() * 100) + 'vw';
      f.style.fontSize = (14 + Math.random() * 14) + 'px';
      f.style.animationDelay = (Math.random() * 0.9) + 's';
      f.style.animationDuration = (2.2 + Math.random() * 1.6) + 's';
      document.body.appendChild(f);
      setTimeout(() => f.remove(), 5200);
    }
  }

  function pikdexSetActive(ix, on) {
    const dex = pikdexGet();
    if (!dex[ix]) return;
    if (on && pikdexActives(dex).length >= PIK_MAX) {
      showToast(trT('squad is full (6) — rest someone first ♡', 'escouade pleine (6) — repose quelqu\'un d\'abord ♡'));
      return;
    }
    dex[ix].a = on ? 1 : 0;
    pikdexSave(dex);
    pikdexRosterProject();
    deskPikResync();
    gardenResync();
    applyPikFloat();
    // a mid-run swap marches straight into slime_run.exe, no restart needed
    try {
      if (typeof GAME !== 'undefined' && GAME && GAME.state === 'run' && typeof gAttachPiks === 'function') gAttachPiks(true);
    } catch (e) { /* game not booted yet */ }
    pikChirp();
    showToast(on
      ? trT(`⭐ ${pikNameOf(dex, ix)} joins the squad!!`, `⭐ ${pikNameOf(dex, ix)} rejoint l'escouade !!`)
      : trT(`💤 ${pikNameOf(dex, ix)} is resting in the deck`, `💤 ${pikNameOf(dex, ix)} se repose dans le deck`));
    if (typeof cloudQueueSync === 'function') cloudQueueSync();
    renderPikdex();
  }

  /* ---------- pikdex.exe rendering: hue wheel + deck grid + dossier ---------- */
  var pikLbCache = null, pikLbCacheAt = 0;
  const PIKLB_TIER_NAMES = [
    ['🌱 Sprout Scout', '🌱 Éclaireur de Pousses'],
    ['🌼 Meadow Regular', '🌼 Habitué de la Prairie'],
    ['🌈 TRUE COLOR', '🌈 TRUE COLOR'],
    ['🌿 Overgrower', '🌿 Sur-Cultivateur'],
    ['🌺 Evolution Engine', '🌺 Moteur d\'Évolution'],
    ['👑 Apex Rancher', '👑 Éleveur Apex'],
    ['✨ Meadow Deity', '✨ Divinité de la Prairie']
  ];
  function pikLbDetail(counts) {
    const wrap = document.createElement('div');
    wrap.id = 'pikdex-lb-detail';
    wrap.className = 'piklb-ladder';
    const head = document.createElement('div');
    head.className = 'piklb-head';
    head.textContent = trT('🌍 WORLDWIDE MEADOW STANDINGS — gardeners who reached each rank', '🌍 CLASSEMENT MONDIAL DE LA PRAIRIE — jardiniers ayant atteint chaque rang');
    wrap.appendChild(head);
    const myTier = pikLbTier(pikCountTotal());
    const maxC = Math.max(1, counts[1] || 0);
    for (let i = PIKLB_TIERS.length; i >= 1; i--) {
      const row = document.createElement('div');
      row.className = 'piklb-row' + (myTier === i ? ' is-you' : '');
      const name = document.createElement('span');
      name.className = 'piklb-name';
      name.textContent = trT(PIKLB_TIER_NAMES[i - 1][0], PIKLB_TIER_NAMES[i - 1][1]) + ' · ' + PIKLB_TIERS[i - 1] + '+';
      const bar = document.createElement('span');
      bar.className = 'piklb-bar';
      const fill = document.createElement('i');
      fill.style.width = Math.max(3, Math.round(((counts[i] || 0) / maxC) * 100)) + '%';
      bar.appendChild(fill);
      const n = document.createElement('span');
      n.className = 'piklb-n';
      n.textContent = String(counts[i] || 0) + (myTier === i ? trT(' ◀ YOU', ' ◀ TOI') : '');
      row.append(name, bar, n);
      wrap.appendChild(row);
    }
    const foot = document.createElement('div');
    foot.className = 'piklb-foot';
    foot.textContent = myTier >= 1
      ? trT('anonymous census — each gardener is counted once per rank reached ♡', 'recensement anonyme — chaque jardinier compte une fois par rang atteint ♡')
      : trT(`pluck ${PIKLB_TIERS[0] - pikCountTotal()} more to enter the standings ♡`, `cueille encore ${PIKLB_TIERS[0] - pikCountTotal()} pour entrer au classement ♡`);
    wrap.appendChild(foot);
    return wrap;
  }
  function pikLbRender(el) {
    if (!el._wired) {
      el._wired = 1;
      el.setAttribute('role', 'button');
      el.setAttribute('tabindex', '0');
      el.title = trT('click: worldwide standings', 'clic : classement mondial');
      const toggle = () => {
        const old = document.getElementById('pikdex-lb-detail');
        if (old) { old.remove(); return; }
        const paintDetail = (counts) => { if (counts) el.parentNode.insertBefore(pikLbDetail(counts), el.nextSibling); };
        if (pikLbCache) { paintDetail(pikLbCache); return; }
        pikLbRender(el); // triggers the fetch; try again once it lands
        setTimeout(() => { if (pikLbCache && !document.getElementById('pikdex-lb-detail')) paintDetail(pikLbCache); }, 1500);
      };
      el.addEventListener('click', toggle);
      el.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggle(); } });
    }
    const total = pikCountTotal();
    const mine = trT(`🧺 your lifetime plucks: ${total}`, `🧺 tes cueillettes : ${total}`);
    const paint = (counts) => {
      const reached1 = counts[1] || 0;
      if (!reached1) {
        el.textContent = mine + ' · ' + trT('🌍 the worldwide meadow is brand new — plant the flag!!', '🌍 la prairie mondiale est toute neuve — plante le drapeau !!');
        return;
      }
      const myTier = pikLbTier(total);
      const atOrAbove = myTier >= 1 ? (counts[myTier] || 0) : reached1;
      const topPct = Math.max(1, Math.min(100, Math.round((atOrAbove / reached1) * 100)));
      el.textContent = mine + ' · ' + trT(
        `🌍 ${reached1} gardeners worldwide — your meadow sits around the top ${topPct}%`,
        `🌍 ${reached1} jardiniers dans le monde — ta prairie est dans le top ${topPct}% environ`
      );
    };
    if (pikLbCache && Date.now() - pikLbCacheAt < 600000) { paint(pikLbCache); return; }
    // offline: say so — the old order wedged the label on "contacting…"
    // with no fetch ever coming to resolve it
    if (!navigator.onLine) { el.textContent = mine + ' · ' + trT('🌍 the worldwide meadow needs internet ♡', '🌍 la prairie mondiale a besoin d\'internet ♡'); return; }
    el.textContent = mine + ' · ' + trT('🌍 contacting the worldwide meadow…', '🌍 contact de la prairie mondiale…');
    Promise.all(Array.from({ length: PIKLB_TIERS.length + 1 }, (_, i) =>
      fetch(`${ACHV_API}/get/${ACHV_NS}/piklb-t${i}`).then((r) => (r.ok ? r.json() : { value: 0 })).then((d) => Math.max(0, Number(d.value) || 0)).catch(() => 0)
    )).then((counts) => { pikLbCache = counts; pikLbCacheAt = Date.now(); paint(counts); })
      .catch(() => { el.textContent = mine; });
  }
  function renderPikdex() {
    const grid = document.getElementById('pikdex-grid');
    if (!grid) return;
    const dex = pikdexGet();
    const dark = document.documentElement.getAttribute('data-theme') === 'dark';
    // hue wheel donut — 24 crisp wedges, collected ones glow in their hue
    const cv = document.getElementById('pikdex-wheel');
    if (cv && cv.getContext) {
      const ctx = cv.getContext('2d');
      const segsSet = pikdexWheelSegs(dex);
      const cx = 60, cy = 60, R = 56, r0 = 27;
      ctx.clearRect(0, 0, 120, 120);
      for (let i = 0; i < WHEEL_SEGS; i++) {
        const a0 = ((i * WHEEL_STEP) - 90) * Math.PI / 180;
        const a1 = (((i + 1) * WHEEL_STEP) - 90) * Math.PI / 180;
        ctx.beginPath();
        ctx.arc(cx, cy, R, a0, a1);
        ctx.arc(cx, cy, r0, a1, a0, true);
        ctx.closePath();
        ctx.fillStyle = segsSet.has(i) ? `hsl(${i * WHEEL_STEP + WHEEL_STEP / 2}, 78%, ${dark ? 60 : 68}%)` : (dark ? '#3a2452' : '#efe3f6');
        ctx.fill();
        ctx.strokeStyle = dark ? '#1c0f2e' : '#5a3d6e';
        ctx.lineWidth = 1;
        ctx.stroke();
      }
      ctx.beginPath();
      ctx.arc(cx, cy, r0 - 4, 0, 6.2832);
      ctx.fillStyle = dark ? '#2a1440' : '#fff6fb';
      ctx.fill();
      ctx.strokeStyle = dark ? '#b79af0' : '#5a3d6e';
      ctx.stroke();
    }
    const hasCh = dex.some((p) => p.ch);
    const center = document.getElementById('pikdex-wheel-center');
    if (center) {
      center.textContent = hasCh ? '🦎' : '♡';
      center.title = hasCh ? trT('the chameleon sits in the middle, above such choices', 'le caméléon trône au centre, au-dessus de ces choix') : '';
    }
    const segs = pikdexWheelCount(dex);
    const pctEl = document.getElementById('pikdex-pct');
    if (pctEl) pctEl.textContent = pikdexWheelPct(dex) + '%';
    const note = document.getElementById('pikdex-wheel-note');
    if (note) {
      note.textContent = trT(
        `${segs}/50 hue segments collected (2% each) — the full wheel = TRUE COLOR (all fifty shades of hue)`,
        `${segs}/50 segments de teinte (2 % chacun) — la roue complète = TRUE COLOR (les cinquante nuances)`
      );
    }
    let lbLine = document.getElementById('pikdex-lb-line');
    if (!lbLine && note && note.parentNode) {
      lbLine = document.createElement('div');
      lbLine.id = 'pikdex-lb-line';
      lbLine.className = 'pikdex-lb-line';
      note.parentNode.insertBefore(lbLine, note.nextSibling);
    }
    if (lbLine && typeof pikLbRender === 'function') pikLbRender(lbLine);
    const squad = document.getElementById('pikdex-squadline');
    if (squad) {
      const nonChN = pikdexKindCount(dex);
      const chTag = dex.some((p) => p.ch) ? ' · 🦎' : '';
      const lbTotal = pikCountTotal();
      squad.textContent = trT(
        `⭐ on duty: ${pikdexActives(dex).length}/${PIK_MAX} · deck: ${nonChN}/${PIKDEX_CAP}${chTag} · 🧺 lifetime plucks: ${lbTotal}`,
        `⭐ en service : ${pikdexActives(dex).length}/${PIK_MAX} · deck : ${nonChN}/${PIKDEX_CAP}${chTag} · 🧺 cueillettes : ${lbTotal}`
      );
    }
    // v157 (owner decree): the ACTIVE SQUAD gets its own front row — every
    // on-duty pik as a tappable chip that opens its dossier, where the
    // "send to rest" button already lives. no more hunting the big grid
    let squadRow = document.getElementById('pikdex-squadrow');
    if (!squadRow && squad && squad.parentNode) {
      squadRow = document.createElement('div');
      squadRow.id = 'pikdex-squadrow';
      squadRow.className = 'pikdex-squadrow';
      squad.parentNode.insertBefore(squadRow, squad.nextSibling);
    }
    if (squadRow) {
      squadRow.innerHTML = ''; // rebuilt below — every string goes through textContent
      const rowTitle = document.createElement('div');
      rowTitle.className = 'pikdex-squadrow-title';
      rowTitle.textContent = trT('⭐ ACTIVE_SQUAD.SYS — tap a member for its dossier', '⭐ ESCOUADE_ACTIVE.SYS — touche un membre pour son dossier');
      squadRow.appendChild(rowTitle);
      const chipsWrap = document.createElement('div');
      chipsWrap.className = 'pikdex-squadrow-chips';
      squadRow.appendChild(chipsWrap);
      dex.forEach((p, ix) => {
        if (!p.a) return;
        const chip = document.createElement('button');
        chip.type = 'button';
        const chipForm = typeof pikFormOf === 'function' ? pikFormOf(p) : 1;
        chip.className = 'pikdex-squad-chip' + (p.ch ? ' is-chameleon' : '') + (chipForm >= 2 ? ' pik-form' + chipForm : '');
        const nm = pikNameOf(dex, ix);
        chip.title = nm + ' — ' + trT('open dossier', 'ouvrir le dossier');
        const star = document.createElement('span');
        star.className = 'pikdex-squad-star';
        star.textContent = '⭐';
        chip.appendChild(star);
        const im = document.createElement('img');
        im.src = pikSprite(p.sp ? pikEntryColor(p) : hueColor(pikHueOf(p)), p.s || 0, p.sp || null, false, chipForm, pikKindKey(p));
        im.alt = '';
        chip.appendChild(im);
        if (p.sp) {
          const sp = pikSpecies(p.sp);
          if (sp) { const hat = document.createElement('span'); hat.className = 'pikdex-squad-hat'; hat.textContent = sp.hat; chip.appendChild(hat); }
        }
        const tag = document.createElement('span');
        tag.className = 'pikdex-squad-name';
        tag.textContent = nm;
        chip.appendChild(tag);
        chip.addEventListener('click', () => pikProfileShow(ix));
        chipsWrap.appendChild(chip);
      });
      for (let i = pikdexActives(dex).length; i < PIK_MAX; i++) {
        const slot = document.createElement('div');
        slot.className = 'pikdex-squad-chip pikdex-squad-empty';
        slot.title = trT('empty slot — open any deck pik and hit "join the squad"', 'place libre — ouvre un pik du deck et « rejoindre l\'escouade »');
        const z = document.createElement('span');
        z.className = 'pikdex-squad-zz';
        z.textContent = '💤';
        slot.appendChild(z);
        const zt = document.createElement('span');
        zt.className = 'pikdex-squad-name';
        zt.textContent = trT('(open)', '(libre)');
        slot.appendChild(zt);
        chipsWrap.appendChild(slot);
      }
    }
    // float-mode picker: exactly how high the squad hovers over the OS
    const floatBox = document.getElementById('pikdex-float');
    if (floatBox) {
      floatBox.innerHTML = ''; // rebuilt below, textContent only
      const lab = document.createElement('span');
      lab.className = 'pikdex-float-label';
      lab.textContent = trT('FLOAT MODE', 'FLOTTAISON');
      floatBox.appendChild(lab);
      const current = pikFloatMode();
      PIK_FLOAT_OPTS.forEach((o) => {
        const b = document.createElement('button');
        b.type = 'button';
        b.className = 'pikdex-float-btn' + (current === o.id ? ' is-picked' : '');
        b.textContent = `${o.icon} ${trT(o.name[0], o.name[1])}`;
        b.title = trT(o.d[0], o.d[1]);
        b.setAttribute('aria-pressed', current === o.id ? 'true' : 'false');
        b.addEventListener('click', () => {
          store.set('yos-pik-float', o.id);
          applyPikFloat();
          pikChirp();
          renderPikdex();
        });
        floatBox.appendChild(b);
      });
      const desc = document.createElement('span');
      desc.className = 'pikdex-float-desc';
      const cur = PIK_FLOAT_OPTS.find((o) => o.id === current);
      desc.textContent = trT(cur.d[0], cur.d[1]) + trT(' · (live room & game always tuck them away — the squad is in there)', ' · (le salon live & le jeu les rangent toujours — l\'escouade y est déjà)');
      floatBox.appendChild(desc);
    }
    // the chameleon lives in the wheel hub — click it to open its dossier
    if (center) {
      const chIx = dex.findIndex((p) => p.ch);
      center.classList.toggle('is-clickable', chIx >= 0);
      center.onclick = chIx >= 0 ? () => pikProfileShow(chIx) : null;
      center.style.pointerEvents = chIx >= 0 ? 'auto' : 'none';
    }
    /* THE 72 FIXED SLOTS — a real dex: 50 hue slots (sorted around the
       wheel) + 22 hidden-species slots. empty slots tease what's coming. */
    grid.innerHTML = ''; // rebuilt below — every string goes through textContent
    function makeCell(dexIx, extraCls) {
      const p = dex[dexIx];
      const cell = document.createElement('button');
      cell.type = 'button';
      const cellForm = typeof pikFormOf === 'function' ? pikFormOf(p) : 1;
      cell.className = 'pikdex-cell' + (p.a ? ' is-on-duty' : '') + (p.ch ? ' is-chameleon' : '') + (cellForm >= 2 ? ' pik-form' + cellForm : '') + (extraCls || '');
      cell.setAttribute('role', 'listitem');
      const name = pikNameOf(dex, dexIx);
      cell.title = name;
      const img = document.createElement('img');
      img.src = pikSprite(p.sp ? pikEntryColor(p) : hueColor(pikHueOf(p)), p.s || 0, p.sp || null, false, cellForm, pikKindKey(p));
      img.alt = '';
      const nm = document.createElement('span');
      nm.className = 'pikdex-cell-name';
      nm.textContent = name;
      if (p.a) {
        const star = document.createElement('span');
        star.className = 'pikdex-cell-star';
        star.textContent = '⭐';
        star.setAttribute('aria-label', trT('on the squad', 'dans l\'escouade'));
        cell.appendChild(star);
      }
      // lifetime count rides a star badge in the TOP-RIGHT corner (never over the name);
      // apex kinds get the royal gold glow instead of a separate 👑
      const kk2 = pikKindKey(p);
      const kn2 = pikCounts()[kk2] || 1;
      if (!p.loan && kn2 >= 2) {
        const cb = document.createElement('span');
        cb.className = 'pikdex-cell-count' + (pikFormOf(p) === 3 ? ' is-apex' : '');
        cb.setAttribute('aria-label', trT(`collected ×${kn2}`, `récolté ×${kn2}`));
        const num = document.createElement('i');
        num.textContent = kn2 > 99 ? '99' : String(kn2);
        cb.appendChild(num);
        cell.appendChild(cb);
      }
      if (p.sp) {
        const sp = pikSpecies(p.sp);
        if (sp) {
          const hat = document.createElement('span');
          hat.className = 'pikdex-cell-hat';
          hat.textContent = sp.hat;
          cell.appendChild(hat);
          if (sp.fx) cell.classList.add('pikfx-' + sp.fx);
        }
      }
      cell.append(img, nm);
      cell.addEventListener('click', () => pikProfileShow(dexIx));
      return cell;
    }
    // slot owners: first catch of each wheel segment / each species
    const segOwner = {}, spOwner = {};
    dex.forEach((p, ix) => {
      if (p.ch) return;
      if (p.sp) { if (spOwner[p.sp] == null) spOwner[p.sp] = ix; return; }
      const seg = Math.floor(pikHueOf(p) / WHEEL_STEP) % WHEEL_SEGS;
      if (segOwner[seg] == null) segOwner[seg] = ix;
    });
    for (let seg = 0; seg < WHEEL_SEGS; seg++) {
      if (segOwner[seg] != null) {
        grid.appendChild(makeCell(segOwner[seg]));
      } else {
        const empty = document.createElement('div');
        empty.className = 'pikdex-cell pikdex-cell-empty';
        empty.title = trT(`a colour is missing here (hue ~${Math.round(seg * WHEEL_STEP + WHEEL_STEP / 2)}°) — the meadow is already growing it ♡`, `une couleur manque ici (teinte ~${Math.round(seg * WHEEL_STEP + WHEEL_STEP / 2)}°) — la prairie la fait déjà pousser ♡`);
        empty.style.setProperty('--slot-hue', String(Math.round(seg * WHEEL_STEP + WHEEL_STEP / 2)));
        empty.textContent = '?';
        grid.appendChild(empty);
      }
    }
    // hidden-species shelf: 22 slots, riddles included — know what to hope for
    const hiddenHead = document.createElement('div');
    hiddenHead.className = 'pikdex-hidden-head';
    const gotSp = Object.keys(spOwner).length;
    hiddenHead.textContent = trT(
      `✨ HIDDEN SPECIES ${gotSp}/22 — about 1 sprout in 10 mutates into a computer-born creature: own hat, own colours, own walk cycle ♡`,
      `✨ ESPÈCES CACHÉES ${gotSp}/22 — environ 1 pousse sur 10 mute en créature née de l'ordinateur : chapeau, couleurs et démarche à elle ♡`
    );
    grid.appendChild(hiddenHead);
    HIDDEN_SPECIES.forEach((sp) => {
      if (spOwner[sp.id] != null) {
        grid.appendChild(makeCell(spOwner[sp.id], ' is-hidden-owned'));
      } else {
        const mys = document.createElement('div');
        mys.className = 'pikdex-cell pikdex-cell-empty pikdex-cell-mystery';
        mys.title = trT(sp.t[0], sp.t[1]); // the riddle — something to hope for
        const shadow = document.createElement('img');
        shadow.className = 'pikdex-shadow-pik'; // an unplucked silhouette, house-made
        shadow.src = pikSprite({ body: '#8f81a8', dark: '#5c4f75' }, 0, sp.id, true);
        shadow.alt = '';
        const nm = document.createElement('span');
        nm.className = 'pikdex-cell-name';
        nm.textContent = '???';
        mys.append(shadow, nm);
        grid.appendChild(mys);
      }
    });
    const hint = document.getElementById('pikdex-hint');
    if (hint) {
      if (pikdexKindCount(dex) >= PIKDEX_CAP) {
        hint.textContent = trT('PIKDEX COMPLETE — 72/72!! the meadow now grows DUPLICATES: same kind × enough = EVOLUTION (3 forms each) ♡', 'PIKDEX COMPLET — 72/72 !! la prairie fait pousser des DOUBLONS : même espèce × assez = ÉVOLUTION (3 formes) ♡');
      } else if (dex.length) {
        hint.textContent = trT('tap a cell for the personnel file ♡ — 50 hues + 22 hidden species = a perfect 72. hidden sprouts ✨glitter✨, pluck them fast!!', 'touche une case pour le dossier ♡ — 50 teintes + 22 espèces cachées = un 72 parfait. les pousses cachées ✨scintillent✨, cueille-les vite !!');
      } else {
        hint.textContent = trT('no pikmin yet!! sprouts pop out of the desktop wallpaper (and the live garden) — pluck one ♡', 'aucun pikmin !! des pousses sortent du fond d\'écran (et du jardin live) — cueilles-en une ♡');
      }
    }
  }
  var pikProfileTimer = null;
  function pikProfileHide() {
    const ov = document.getElementById('pikdex-profile');
    if (ov) { ov.hidden = true; ov.innerHTML = ''; }
    if (pikProfileTimer) { clearInterval(pikProfileTimer); pikProfileTimer = null; }
  }
  function pikProfileShow(ix) {
    const ov = document.getElementById('pikdex-profile');
    if (!ov) return;
    const dex = pikdexGet();
    const p = dex[ix];
    if (!p) return;
    pikProfileHide();
    ov.hidden = false;
    const card = document.createElement('div');
    card.className = 'pik-card';
    const head = document.createElement('div');
    head.className = 'pik-card-head';
    const title = document.createElement('strong');
    title.textContent = pikNameOf(dex, ix) + '.pik';
    const close = document.createElement('button');
    close.type = 'button';
    close.className = 'pik-card-close';
    close.setAttribute('aria-label', trT('Close profile', 'Fermer le dossier'));
    close.textContent = '♥';
    close.addEventListener('click', pikProfileHide);
    head.append(title, close);
    const body = document.createElement('div');
    body.className = 'pik-card-body';
    const port = document.createElement('div');
    const portForm = typeof pikFormOf === 'function' ? pikFormOf(p) : 1;
    port.className = 'pik-card-portrait' + (portForm >= 2 ? ' pik-form' + portForm : '');
    const big = document.createElement('img');
    big.alt = '';
    big.src = pikSprite(pikEntryColor(p), p.s || 0, p.sp || null, false, portForm, pikKindKey(p));
    port.appendChild(big);
    const pSpecies = p.sp ? pikSpecies(p.sp) : null;
    if (pSpecies) {
      const bigHat = document.createElement('span');
      bigHat.className = 'pik-card-hat';
      bigHat.textContent = pSpecies.hat;
      port.appendChild(bigHat);
      if (pSpecies.fx) port.classList.add('pikfx-' + pSpecies.fx);
    }
    if (p.ch) {
      let hh = pikHueOf(p);
      pikProfileTimer = setInterval(() => { hh = (hh + 24) % 360; big.src = pikSprite(hueColor(hh), p.s || 0, null, false, typeof pikFormOfKind === 'function' ? pikFormOfKind('ch') : 1, 'ch'); }, 300);
    }
    const info = document.createElement('div');
    info.className = 'pik-card-info';
    function line(label, value) {
      const el = document.createElement('div');
      el.className = 'pik-card-line';
      const b = document.createElement('span');
      b.className = 'pik-card-label';
      b.textContent = label;
      const v = document.createElement('span');
      v.textContent = value;
      el.append(b, v);
      info.appendChild(el);
    }
    const h = pikHueOf(p);
    line(trT('HUE', 'TEINTE'), p.ch
      ? trT('ALL OF THEM (it refuses to choose)', 'TOUTES (il refuse de choisir)')
      : (pSpecies
        ? trT('CLASSIFIED — hidden species ✨', 'CLASSIFIÉ — espèce cachée ✨')
        : `${h}° · ${PIK_SWATCH[Math.floor(h / 15) % PIK_SWATCH.length]}`));
    if (pSpecies) line(trT('ORIGIN', 'ORIGINE'), trT(pSpecies.lore[0], pSpecies.lore[1]));
    const stages = [trT('🌱 sprout', '🌱 pousse'), trT('🌿 bud', '🌿 bourgeon'), trT('🌸 bloom', '🌸 floraison')];
    line(trT('STAGE', 'STADE'), stages[Math.min(p.s || 0, 2)]);
    const kk = pikKindKey(p);
    const kCnt = pikCounts()[kk] || 1;
    const kTh = pikThresholds(kk);
    const kForm = pikFormOfCount(kCnt, kk);
    line(trT('FORM', 'FORME'), kForm === 3
      ? `★★★ ${pikEvoLore(kk, 3)} · ×${kCnt}`
      : kForm === 2
        ? `★★ ${pikEvoLore(kk, 2)} · ${kCnt}/${kTh[1]}` + trT(' to APEX (dupes count!)', ' vers APEX (les doublons comptent !)')
        : trT(`★ base · ${kCnt}/${kTh[0]} to evolve (dupes count!)`, `★ base · ${kCnt}/${kTh[0]} pour évoluer (les doublons comptent !)`));
    line('UPTIME', pikAgeOf(p));
    line(trT('DUTY', 'SERVICE'), p.a
      ? trT('⭐ on the squad — desktop patrol + slime_run.exe combat', '⭐ dans l\'escouade — patrouille bureau + combat slime_run.exe')
      : trT('💤 resting in the deck', '💤 au repos dans le deck'));
    const meta = PIK_SKILL_META[p.k] || { icon: '✨', name: '???', en: 'undocumented technique. scholars are looking into it.', fr: 'technique non documentée. les chercheurs enquêtent.' };
    const sk = document.createElement('div');
    sk.className = 'pik-card-skill';
    const skName = document.createElement('div');
    skName.className = 'pik-card-skill-name';
    skName.textContent = `${meta.icon} ${meta.name}`;
    const skDesc = document.createElement('div');
    skDesc.className = 'pik-card-skill-desc';
    skDesc.textContent = trT(meta.en, meta.fr);
    const skHint = document.createElement('div');
    skHint.className = 'pik-card-skill-hint';
    skHint.textContent = (p.s || 0) === 2
      ? trT('equipped — fires automatically in slime_run.exe', 'équipée — se déclenche automatiquement dans slime_run.exe')
      : trT('activates in-game at 🌸 bloom stage (it\'s still studying)', 's\'active en jeu au stade 🌸 (il révise encore)');
    sk.append(skName, skDesc, skHint);
    const stats = document.createElement('div');
    stats.className = 'pik-card-stats';
    function statRow(label, val, hintText) {
      const row = document.createElement('div');
      row.className = 'stat-row';
      const name = document.createElement('span');
      name.className = 'stat-name';
      name.textContent = label;
      if (hintText) name.title = hintText;
      const barEl = document.createElement('div');
      barEl.className = 'stat-bar';
      const fill = document.createElement('div');
      fill.className = 'stat-fill' + (val == null ? ' pik-stat-mystery' : '');
      fill.style.setProperty('--v', (val == null ? 100 : val) + '%');
      barEl.appendChild(fill);
      const num = document.createElement('span');
      num.className = 'stat-num';
      num.textContent = val == null ? '??' : val;
      row.append(name, barEl, num);
      stats.appendChild(row);
    }
    const st = pikStatsOf(p);
    if (st) {
      statRow('CPU', st.cpu, trT('cuteness processing unit', 'unité de traitement de mignonnerie'));
      statRow('RAM', st.ram, trT('remembers all meals', 'retient tous les repas'));
      statRow('FPS', st.fps, trT('flowers per second', 'fleurs par seconde'));
      statRow('PING', st.ping, trT('ms to answer a pet', 'ms pour répondre à une caresse'));
    } else {
      statRow('CPU', null); statRow('RAM', null); statRow('FPS', null); statRow('PING', null);
      const chNote = document.createElement('div');
      chNote.className = 'pik-card-chnote';
      chNote.textContent = trT('benchmarks refuse to settle. the chameleon is beyond measurement ♡', 'les benchmarks refusent de se stabiliser. le caméléon dépasse la mesure ♡');
      stats.appendChild(chNote);
    }
    const bio = document.createElement('div');
    bio.className = 'pik-card-bio';
    const bx = (h * 31 + ix) % PIK_BIOS.length;
    bio.textContent = '“' + trT(PIK_BIOS[bx], PIK_BIOS_FR[bx]) + '”';
    // v161: the appearance picker — evolution is progress, the LOOK is a
    // choice. lock any earned form; the counters keep climbing underneath
    let formPick = null;
    {
      const natural = pikFormOfCount(pikCounts()[pikKindKey(p)] || 1, pikKindKey(p));
      if (natural >= 2) {
        const kkP = pikKindKey(p);
        formPick = document.createElement('div');
        formPick.className = 'pik-card-formpick';
        const lab = document.createElement('span');
        lab.className = 'pik-card-formpick-label';
        lab.textContent = trT('APPEARS AS', 'APPARAÎT EN');
        formPick.appendChild(lab);
        const showing = pikFormApplyLock(kkP, natural);
        [1, 2, 3].forEach((f) => {
          if (f > natural) return; // not earned yet — no spoilers
          const b = document.createElement('button');
          b.type = 'button';
          b.className = 'pikdex-float-btn' + (showing === f ? ' is-picked' : '');
          b.textContent = f === 1 ? trT('★ classic', '★ classique') : f === 2 ? '★★' : '★★★';
          b.setAttribute('aria-pressed', showing === f ? 'true' : 'false');
          b.addEventListener('click', () => {
            if (f === showing) return;
            pikFormLockSet(kkP, f >= natural ? null : f);
            playSparkleSound();
            const nmT = pikNameOf(dex, ix);
            showToast(f < natural
              ? trT(`💾 ${nmT} keeps the ${f === 1 ? 'classic' : '★★'} look — evolution is a state of mind ♡`, `💾 ${nmT} garde le look ${f === 1 ? 'classique' : '★★'} — l'évolution est un état d'esprit ♡`)
              : trT(`⚡ ${nmT} returns to FULL POWER`, `⚡ ${nmT} retrouve sa PLEINE PUISSANCE`));
            try { deskPikResync(); } catch (e) { /* re-dresses on respawn */ }
            try { gardenResync(); } catch (e) { /* the stage catches up */ }
            try { renderPikdex(); } catch (e) { /* dex repaints on open */ }
            pikProfileShow(ix);
          });
          formPick.appendChild(b);
        });
        const hint = document.createElement('span');
        hint.className = 'pik-card-formpick-hint';
        hint.textContent = trT('(cosmetic — progress keeps counting)', '(cosmétique — la progression continue)');
        formPick.appendChild(hint);
      }
    }
    const actions = document.createElement('div');
    actions.className = 'pik-card-actions';
    const swap = document.createElement('button');
    swap.type = 'button';
    swap.className = 'pik-card-btn';
    if (p.a) {
      swap.textContent = trT('💤 send to rest', '💤 mettre au repos');
      swap.addEventListener('click', () => { pikdexSetActive(ix, false); pikProfileHide(); });
    } else {
      const room = pikdexActives(dex).length < PIK_MAX;
      if (room) {
        swap.textContent = trT('⭐ join the squad', '⭐ rejoindre l\'escouade');
        swap.addEventListener('click', () => { pikdexSetActive(ix, true); pikProfileHide(); });
      } else {
        // v185: full squad is no longer a dead end — the button OPENS a
        // picker of the six on duty; tap one to swap it out for this pik
        swap.textContent = trT('⭐ squad full (6) — swap someone out', '⭐ escouade pleine (6) — échange quelqu\'un');
        swap.addEventListener('click', () => {
          const had = card.querySelector('.pik-swap-pick');
          if (had) { had.remove(); return; } // second tap folds it back up
          const pick = document.createElement('div');
          pick.className = 'pik-swap-pick';
          const tt = document.createElement('div');
          tt.className = 'pik-swap-pick-title';
          tt.textContent = trT('who rests? tap a member ↓', 'qui se repose ? touche un membre ↓');
          pick.appendChild(tt);
          const rowP = document.createElement('div');
          rowP.className = 'pik-swap-pick-row';
          pick.appendChild(rowP);
          dex.forEach((q, qi) => {
            if (!q.a) return;
            const c = document.createElement('button');
            c.type = 'button';
            c.className = 'pik-swap-chip';
            const qForm = typeof pikFormOf === 'function' ? pikFormOf(q) : 1;
            const im = document.createElement('img');
            try { im.src = pikSprite(q.sp ? pikEntryColor(q) : hueColor(pikHueOf(q)), q.s || 0, q.sp || null, false, qForm, pikKindKey(q)); } catch (e) { /* sprite shy */ }
            im.alt = '';
            c.appendChild(im);
            const nmq = document.createElement('span');
            nmq.textContent = pikNameOf(dex, qi);
            c.appendChild(nmq);
            c.addEventListener('click', () => {
              pikdexSetActive(qi, false);
              pikdexSetActive(ix, true); // ONE tap: they rest, THIS pik joins
              playSparkleSound();
              showToast('⭐ ' + trT(pikNameOf(dex, ix) + ' joins — ' + pikNameOf(dex, qi) + ' naps in the deck ♡', pikNameOf(dex, ix) + ' rejoint — ' + pikNameOf(dex, qi) + ' fait la sieste ♡'));
              pikProfileHide();
              // make the arrival unmissable: the new member's chip flashes gold
              const nmNew = pikNameOf(dex, ix);
              const chip = [...document.querySelectorAll('#pikdex-squadrow .pikdex-squad-chip')].find((ch) => (ch.textContent || '').includes(nmNew));
              if (chip) {
                chip.classList.add('pik-chip-newjoin');
                setTimeout(() => { try { chip.classList.remove('pik-chip-newjoin'); } catch (e) { /* row re-rendered */ } }, 2800);
              }
            });
            rowP.appendChild(c);
          });
          card.appendChild(pick);
          try { pick.scrollIntoView({ block: 'nearest' }); } catch (e) { /* short card */ }
        });
      }
    }
    actions.appendChild(swap);
    body.append(port, info);
    if (formPick) card.append(head, body, sk, stats, bio, formPick, actions);
    else card.append(head, body, sk, stats, bio, actions);
    ov.appendChild(card);
    ov.addEventListener('click', function bg(e) {
      if (e.target === ov) { pikProfileHide(); ov.removeEventListener('click', bg); }
    });
    playTone(980, 'square', 0.05, 0, 0.02);
  }

  function deskSprout() {
    if (!DESK_PIK.layer) return;
    if (DESK_PIK.layer.querySelector('.desk-sprout')) return;
    const roll = pikRollSprout(); // chameleon → hidden species → missing hue
    if (!roll) return;            // deck complete — the meadow rests ♡
    const chameleon = roll.type === 'chameleon';
    const species = roll.type === 'hidden' ? roll.sp : null;
    const hue = roll.type === 'normal' ? roll.hue : 5 + Math.floor(Math.random() * 355);
    const color = species ? species.body : hueColor(hue);
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'pik-sprout desk-sprout' + (species ? ' pik-sprout-hidden' : '');
    btn.setAttribute('aria-label', t('live.pluck'));
    const img = document.createElement('img');
    img.src = pikSprite(color, 0, species ? species.id : null);
    img.alt = '';
    img.style.width = '33px';
    img.style.clipPath = 'inset(0 0 58% 0)';
    btn.appendChild(img);
    if (species) { // a hidden sprout glitters — you can tell something is up
      const tease = document.createElement('span');
      tease.className = 'pik-sprout-tease';
      tease.textContent = '✨';
      btn.appendChild(tease);
    }
    const r = DESK_PIK.layer.getBoundingClientRect();
    btn.style.left = (60 + Math.random() * Math.max(100, r.width - 200)) + 'px';
    btn.style.top = (r.height * 0.4 + Math.random() * (r.height * 0.45)) + 'px';
    if (chameleon) { // even the sprout can't hold a colour
      btn._hueTimer = setInterval(() => { img.src = pikSprite(hueColor(hue + Date.now() / 14 % 360), 0); }, 420);
    }
    btn.addEventListener('click', () => {
      if (btn._hueTimer) clearInterval(btn._hueTimer);
      const entry = { h: hue, ch: chameleon ? 1 : 0, s: 0, k: PIK_SKILLS[Math.floor(Math.random() * PIK_SKILLS.length)].id, sp: species ? species.id : null };
      const verdict = pikdexAdd(entry); // archived forever, squad if there's room
      if (verdict === 'dup') {
        btn.remove();
        playSparkleSound(); pikChirp();
        const kk = pikKindKey(entry);
        const cnt = pikCounts()[kk] || 1;
        const th = pikThresholds(kk);
        const nxt = cnt >= th[1] ? null : (cnt >= th[0] ? th[1] : th[0]);
        achvBump('plucks');
        if (!pikEvolveCelebrate(kk, cnt) && !pet.sleeping) showBubble(nxt
          ? trT(`+1 of that kind!! ${cnt}/${nxt} toward its next form ♡`, `+1 de cette espèce !! ${cnt}/${nxt} vers sa prochaine forme ♡`)
          : trT('+1 for an APEX legend — pure leaderboard fuel ♡', '+1 pour une légende APEX — pur carburant de classement ♡'), 2600);
        return;
      }
      store.set('yos-pik-plucked', true);
      if (typeof updateLiveTab === 'function') updateLiveTab();
      playSparkleSound(); pikChirp(); pikChirp();
      if (verdict === 'active') {
        const w = deskPikSpawn(species ? 5 : hue, 0, chameleon, species ? species.id : null);
        w.x = parseFloat(btn.style.left); w.y = parseFloat(btn.style.top);
        w.tx = w.x; w.ty = w.y;
        w.el.style.left = w.x + 'px'; w.el.style.top = w.y + 'px';
        deskPikSay(w, chameleon ? 'p̷i̷k̷?̷!̷ ♡' : (species ? 'p1k?!' : 'pik!!'));
      }
      btn.remove();
      achvBump('plucks');
      if (chameleon) {
        achvUnlock('chameleon');
        chameleonCelebrate(); // 1% pull — the whole desktop rains rainbow blooms
        if (!pet.sleeping) showBubble(trT('WAIT. that one keeps CHANGING COLOURS?! a hidden chameleon!! (1% pull!!)', 'ATTENDS. il n\'arrête pas de CHANGER DE COULEUR ?! un caméléon caché !! (tirage à 1 % !!)'), 3600);
      } else if (species) {
        pikHiddenCelebrate(species);
      } else if (verdict === 'deck' && !pet.sleeping) {
        showBubble(trT('squad\'s full — the new buddy is filed in pikdex.exe, awaiting promotion ♡', 'escouade pleine — le nouveau copain est classé dans pikdex.exe, en attente de promotion ♡'), 3000);
      } else if (!pet.sleeping) {
        showBubble(trT('a wild buddy joined the DESKTOP crew ♡', 'un copain sauvage rejoint l\'équipe du BUREAU ♡'), 2400);
      }
    });
    DESK_PIK.layer.appendChild(btn);
  }
  function deskPikTick() {
    // while the desktop twins are curtained off (live room / game open /
    // shy mode), time FREEZES for them: no walking, no sprouting, no trails —
    // the curtain lifts on the exact scene it fell on
    if (DESK_PIK.layer && DESK_PIK.layer.classList.contains('pik-float-hidden')) return;
    const now = Date.now();
    if (now > DESK_PIK.sproutAt) {
      DESK_PIK.sproutAt = now + 16000 + Math.random() * 16000; // brisk regrowth (16-32s)
      deskSprout();
    }
    DESK_PIK.walkers.forEach((w) => {
      // the chameleon never settles on a colour — cycles the wheel
      if (w.chameleon && now > w.hueAt) {
        w.hueAt = now + 480;
        w.hue = ((w.hue || 5) + 30) % 360 || 5;
        w.img.src = pikSprite(hueColor(w.hue), w.stage, null, false, pikFormOfLive(w), pikKindOfLive(w));
      }
      // evolved Cron Job: every REAL minute, on the minute, it RINGS —
      // shakes like an alarm clock, two-tone bell, very smug about it
      if (w.cronRing) {
        const nowMin = new Date().getMinutes();
        if (w.lastMin < 0) w.lastMin = nowMin;
        else if (nowMin !== w.lastMin) {
          w.lastMin = nowMin;
          w.el.classList.add('pik-ringing');
          setTimeout(() => { try { w.el.classList.remove('pik-ringing'); } catch (e) { /* snoozed */ } }, 1200);
          playTone(1320, 'square', 0.06, 0, 0.02);
          playTone(1320, 'square', 0.06, 0.15, 0.02);
          playTone(1760, 'square', 0.07, 0.3, 0.02);
          deskPikSay(w, '⏰ ' + ['RING!!', 'pik o\'clock!!', 'ON SCHEDULE ✓'][Math.floor(Math.random() * 3)]);
        }
      }
      // framed sprites (y2kbug confetti / cronjob clock hand): re-roll
      // the image whenever the 0.9s frame clock turns over
      if (w.framedSp && w.sp && now > (w.confAt || 0)) {
        w.confAt = now + 300;
        const nf = Math.floor(now / 900) % 4;
        if (nf !== w.confFrame) {
          w.confFrame = nf;
          w.img.src = pikSprite(w.sp.body, w.stage, w.sp.id, false, pikFormOfLive(w), pikKindOfLive(w));
        }
      }
      // evolved Y2K Bug never stops partying: confetti bits float off it
      if (!docHidden && w.party && now > w.partyAt) {
        w.partyAt = now + 260 + Math.random() * 260;
        const cf = document.createElement('span');
        cf.className = 'pik-party-bit';
        cf.style.background = PIK_PARTY_COLORS[Math.floor(Math.random() * PIK_PARTY_COLORS.length)];
        cf.style.left = (w.x + 4 + Math.random() * 26) + 'px';
        cf.style.top = (w.y - 6 + Math.random() * 32) + 'px';
        DESK_PIK.layer.appendChild(cf);
        cf.addEventListener('animationend', () => cf.remove());
      }
      // the pointer family: the pink baby follows, stalls, and gets fetched
      if (w.babyEl) {
        const bTx = w.x - 30, bTy = w.y + 12; // trail BEHIND the parent, not on it
        const stalled = now < w.babyStallUntil;
        if (stalled) w.babyEl.classList.add('is-stalled');
        else {
          w.babyEl.classList.remove('is-stalled');
          if (!w.fetching && Math.random() < 0.004 && Math.hypot(bTx - w.babyX, bTy - w.babyY) < 26) {
            w.babyStallUntil = now + 2600 + Math.random() * 2400; // it found something. it MUST look at it
          } else {
            w.babyX += (bTx - w.babyX) * 0.07;
            w.babyY += (bTy - w.babyY) * 0.07;
          }
        }
        // personal space: the baby NEVER overlaps the parent — if the
        // centers get closer than 36px it is nudged back out
        const pcx = w.x + 22, pcy = w.y + 20, bcx = w.babyX + 9, bcy = w.babyY + 9;
        const cd = Math.hypot(bcx - pcx, bcy - pcy);
        if (cd < 36 && cd > 0.01) {
          const push = (36 - cd) / cd;
          w.babyX += (bcx - pcx) * push;
          w.babyY += (bcy - pcy) * push;
        }
        const babyDist = Math.hypot(w.x - w.babyX, w.y - w.babyY);
        if (!stalled && babyDist > 70 && !w.fetching) w.fetching = true; // it fell behind — go back for it
        if (w.fetching) {
          w.tx = w.babyX + 16; w.ty = Math.max(8, w.babyY - 8);
          if (babyDist < 52) {
            w.fetching = false;
            w.babyStallUntil = 0;
            const hb = document.createElement('span'); // the reunion heart
            hb.className = 'pik-party-bit';
            hb.style.background = '#ff8fc7';
            hb.style.left = (w.babyX + 8) + 'px';
            hb.style.top = (w.babyY - 4) + 'px';
            DESK_PIK.layer.appendChild(hb);
            hb.addEventListener('animationend', () => hb.remove());
          }
        }
        w.babyEl.style.left = w.babyX + 'px';
        w.babyEl.style.top = w.babyY + 'px';
        if (!docHidden && !stalled && now > w.babyStarAt && Math.hypot(bTx - w.babyX, bTy - w.babyY) > 3) {
          w.babyStarAt = now + 260 + Math.random() * 220; // the baby's own GLOWING stardust wake
          const bsi = Math.floor(Math.random() * 18);
          const bs = document.createElement('img');
          bs.className = 'pik-baby-star';
          bs.src = trailStarSprite(bsi);
          bs.alt = '';
          bs.style.setProperty('--star-glow', trailStarGlow(bsi));
          bs.style.left = (w.babyX + 5) + 'px';
          bs.style.top = (w.babyY + 9) + 'px';
          DESK_PIK.layer.appendChild(bs);
          setTimeout(() => { try { bs.remove(); } catch (e) { /* twinkled out */ } }, 1500);
        }
      }
      // Not A Robot (v164): the disguise ACTIVATES. ★★: now and then it
      // morphs into a pixel animal, holds a few seconds, then POP — pink
      // confetti — back to robot, wondering aloud if anything seemed off.
      // ★★★: it cycles the whole zoo and only sometimes blows its cover.
      // every creature keeps the antenna flower (continuity is important)
      if (w.disguiser && now > w.disguiseAt && now > (w.revealUntil || 0)) {
        // the ✅ hat swaps for a scrolling site-style banner announcing
        // (with full CAPTCHA confidence) what the creature definitely is
        const disgBanner = () => {
          const a = PIK_DISGUISES[w.disguised];
          if (!w.disgBannerEl) {
            const bn = document.createElement('span');
            bn.className = 'pik-disg-banner';
            bn.appendChild(document.createElement('span'));
            w.el.appendChild(bn);
            w.disgBannerEl = bn;
          }
          w.disgBannerEl.firstChild.textContent = trT('this is ' + a.n[0] + ' \u2713 ', 'ceci est ' + a.n[1] + ' \u2713 ');
          const hat = w.el.querySelector('.pik-hat');
          if (hat) hat.style.display = 'none';
        };
        if (w.disguised < 0) { // currently a robot: put on a costume
          if (!w.trueSrc) w.trueSrc = w.img.src;
          w.disguised = Math.floor(Math.random() * PIK_DISGUISES.length);
          w.img.src = pikDisguiseSprite(w.disguised);
          w.disguiseCls = ['pik-form2', 'pik-form3'].filter((cl) => w.el.classList.contains(cl));
          w.disguiseCls.forEach((cl) => w.el.classList.remove(cl));
          w.el.classList.add('is-disguised'); // CSS belt-and-suspenders for the hat
          disgBanner();
          w.disguiseAt = now + 3800 + Math.random() * 3200;
        } else if (w.disguiseDeep && Math.random() < 0.68) { // APEX: next costume, cover intact (v182: blows it ~1 in 3 beats — 0.62 was too often, 0.82 too rare)
          let nx;
          do { nx = Math.floor(Math.random() * PIK_DISGUISES.length); } while (nx === w.disguised);
          w.disguised = nx;
          w.img.src = pikDisguiseSprite(nx);
          disgBanner();
          w.disguiseAt = now + 3800 + Math.random() * 3600;
        } else { // the cover is BLOWN: pink pop, back to robot, play it cool
          w.disguised = -1;
          w.img.src = w.trueSrc;
          w.el.classList.remove('is-disguised');
          if (w.disguiseCls) { w.disguiseCls.forEach((cl) => w.el.classList.add(cl)); w.disguiseCls = null; }
          if (w.disgBannerEl) { w.disgBannerEl.remove(); w.disgBannerEl = null; }
          const hatBack = w.el.querySelector('.pik-hat');
          if (hatBack) hatBack.style.display = '';
          // THE POP, grander (v168): a pink flash ring, then TWO waves of
          // chunky confetti — 24 all-colors, and 16 pure pinks a beat later
          const bx0 = w.x, by0 = w.y;
          const fl = document.createElement('span');
          fl.className = 'pik-burst-flash';
          fl.style.left = (bx0 + 10) + 'px';
          fl.style.top = (by0 + 8) + 'px';
          DESK_PIK.layer.appendChild(fl);
          fl.addEventListener('animationend', () => fl.remove());
          const burstWave = (n, dMin, dMax, cols, delay) => setTimeout(() => {
            for (let k = 0; k < n; k++) {
              const b = document.createElement('span');
              b.className = 'pik-burst-bit';
              b.style.background = cols[k % cols.length];
              const sz = 5 + Math.floor(Math.random() * 5);
              b.style.width = sz + 'px';
              b.style.height = sz + 'px';
              const ang = (k / n) * 6.283 + Math.random() * 0.5;
              const dist = dMin + Math.random() * (dMax - dMin);
              b.style.setProperty('--bx', (Math.cos(ang) * dist).toFixed(1) + 'px');
              b.style.setProperty('--by', (Math.sin(ang) * dist * 0.8 - 10).toFixed(1) + 'px');
              b.style.setProperty('--br', Math.floor(Math.random() * 300 - 150) + 'deg');
              b.style.left = (bx0 + 19) + 'px';
              b.style.top = (by0 + 16) + 'px';
              DESK_PIK.layer.appendChild(b);
              b.addEventListener('animationend', () => b.remove());
            }
          }, delay);
          burstWave(24, 30, 64, PIK_PARTY_COLORS, 0);
          burstWave(16, 16, 44, ['#ff2fae', '#ff8fc7', '#ffb3dd', '#ff5fa8'], 150);
          w.restUntil = now + 3600; w.tx = w.x; w.ty = w.y; // ROOTED to the spot
          w.revealUntil = now + 4400; // the reveal scene is SACRED — no costume may cut it
          w.el.classList.remove('poked'); void w.el.offsetWidth; w.el.classList.add('poked');
          pikChirp();
          // then: two full seconds of SHIFTY EYES (left... right... left...)
          // before it dares to say anything. eyes live at template (3,5) and
          // (5,5) -> padded canvas (6,8)/(8,8); frames swap the pixels over
          if (!w.shiftyFrames && w.trueSrc) {
            const sim = new Image();
            sim.onload = () => {
              const mk = (dx) => {
                const sc = document.createElement('canvas');
                sc.width = sim.width; sc.height = sim.height;
                const sx = sc.getContext('2d');
                sx.drawImage(sim, 0, 0);
                const bg = sx.getImageData(7, 8, 1, 1).data;
                sx.fillStyle = 'rgb(' + bg[0] + ',' + bg[1] + ',' + bg[2] + ')';
                sx.fillRect(6, 8, 1, 1); sx.fillRect(8, 8, 1, 1);
                sx.fillStyle = '#14020e';
                sx.fillRect(6 + dx, 8, 1, 1); sx.fillRect(8 + dx, 8, 1, 1);
                return sc.toDataURL();
              };
              w.shiftyFrames = [mk(-1), mk(1)];
            };
            sim.src = w.trueSrc;
          }
          for (let g = 0; g < 6; g++) {
            setTimeout(() => {
              try { if (w.shiftyFrames && w.disguised < 0) w.img.src = w.shiftyFrames[g % 2]; } catch (e) { /* blinked */ }
            }, 480 + g * 330);
          }
          setTimeout(() => {
            try {
              if (w.disguised >= 0) return; // a costume never delivers the robot's line
              w.img.src = w.trueSrc; // eyes front
              const L = [
                trT('...did something feel different just now?', '...quelque chose était différent à l\'instant, non ?'),
                trT('I have ALWAYS been a robot', 'j\'ai TOUJOURS été un robot'),
                trT('you saw nothing ♡', 'tu n\'as rien vu ♡'),
                trT('that was a bug. probably', 'c\'était un bug. sûrement')
              ];
              deskPikSay(w, L[Math.floor(Math.random() * L.length)]);
            } catch (e) { /* it played it TOO cool */ }
          }, 2680);
          w.disguiseAt = now + (w.disguiseDeep ? 6500 + Math.random() * 6500 : 13000 + Math.random() * 12000);
        }
      }
      // bit flip APEX: every few seconds the bit ACTUALLY flips — a glitch
      // stutter that mirrors the whole creature for a heartbeat
      if (w.glitchy && now > w.glitchAt) {
        w.glitchAt = now + 4000 + Math.random() * 4500;
        w.el.classList.add('pik-glitch');
        setTimeout(() => { try { w.el.classList.remove('pik-glitch'); } catch (e) { /* deglitched */ } }, 440);
      }
      // cumulus weather: ★★ = a personal drizzle. APEX = a full weather
      // station cycling every 8-15s through rain / storm / snow / sunshine
      if (w.weather) {
        if (w.apexWeather && now > (w.wxModeAt || 0)) {
          const MODES = ['rain', 'storm', 'snow', 'sunny'];
          let nm;
          do { nm = MODES[Math.floor(Math.random() * MODES.length)]; } while (nm === w.wxMode);
          w.wxMode = nm;
          w.wxModeAt = now + 8000 + Math.random() * 7000;
        }
        const wx = w.apexWeather ? (w.wxMode || 'rain') : 'rain';
        if (!docHidden && now > w.rainAt) {
          if (wx === 'rain' || wx === 'storm') {
            const rd = document.createElement('span');
            rd.className = 'pik-rain-bit';
            rd.style.left = (w.x + 6 + Math.random() * 20) + 'px';
            rd.style.top = (w.y + 30) + 'px';
            DESK_PIK.layer.appendChild(rd);
            rd.addEventListener('animationend', () => rd.remove());
            w.rainAt = now + (wx === 'storm' ? 170 + Math.random() * 160 : 380 + Math.random() * 420);
          } else if (wx === 'snow') {
            const sf = document.createElement('span');
            sf.className = 'pik-snow-bit';
            sf.style.left = (w.x + 4 + Math.random() * 24) + 'px';
            sf.style.top = (w.y + 28) + 'px';
            DESK_PIK.layer.appendChild(sf);
            sf.addEventListener('animationend', () => sf.remove());
            w.rainAt = now + 460 + Math.random() * 420;
          } else { // sunny: golden warmth rises off the cloud
            const su = document.createElement('span');
            su.className = 'pik-party-bit';
            su.style.background = Math.random() < 0.5 ? '#ffd400' : '#fff6c9';
            su.style.left = (w.x + 4 + Math.random() * 24) + 'px';
            su.style.top = (w.y + Math.random() * 20) + 'px';
            DESK_PIK.layer.appendChild(su);
            su.addEventListener('animationend', () => su.remove());
            w.rainAt = now + 420 + Math.random() * 380;
          }
        }
        if (!docHidden && wx === 'storm' && now > w.boltAt) {
          w.boltAt = now + 2200 + Math.random() * 1600;
          const bl = document.createElement('span');
          bl.className = 'pik-bolt-bit';
          bl.textContent = '⚡';
          bl.style.left = (w.x + 8 + Math.random() * 16) + 'px';
          bl.style.top = (w.y + 26) + 'px';
          DESK_PIK.layer.appendChild(bl);
          bl.addEventListener('animationend', () => bl.remove());
          w.el.classList.add('pik-flash');
          setTimeout(() => { try { w.el.classList.remove('pik-flash'); } catch (e) { /* thundered off */ } }, 320);
        }
      }
      if (now < w.restUntil) return;
      const dx = w.tx - w.x, dy = w.ty - w.y;
      const d = Math.hypot(dx, dy);
      if (d < 4) {
        w.el.classList.remove('walking');
        w.restUntil = now + 1800 + Math.random() * 4200;
        if (Math.random() < 0.3) pikChirp();
        if (Math.random() < 0.3) deskPikSay(w, PIK_LINES[Math.floor(Math.random() * PIK_LINES.length)]);
        const anchors = deskAnchorPoints();
        const r = DESK_PIK.layer.getBoundingClientRect();
        const p = (anchors.length && Math.random() < 0.45)
          ? anchors[Math.floor(Math.random() * anchors.length)]
          : { x: 30 + Math.random() * Math.max(120, r.width - 140), y: r.height * 0.3 + Math.random() * (r.height * 0.55) };
        w.tx = Math.max(6, p.x);
        w.ty = Math.max(60, p.y);
      } else {
        // Latency walks in 300ms packets; everyone else walks in realtime
        if (w.sp && w.sp.choppy) {
          if (now < w.stepAt) return;
          w.stepAt = now + 320;
          const hopLen = Math.min(d, 14);
          w.x += (dx / d) * hopLen;
          w.y += (dy / d) * hopLen;
        } else {
          const sp = 1.6 * (w.spd || 1);
          w.x += (dx / d) * sp;
          w.y += (dy / d) * sp;
        }
        w.el.classList.add('walking');
        const facingLeft = dx < 0;
        // 'Feature' walks backwards on purpose — sprite faces away from travel
        w.img.style.transform = ((w.sp && w.sp.flip) ? !facingLeft : facingLeft) ? 'scaleX(-1)' : '';
        w.el.style.left = w.x + 'px';
        w.el.style.top = w.y + 'px';
        // footprint blooms: RAINBOW confetti-flowers, 1-10 per step —
        // 3+ cluster into a round posy. Always UNDER the walker's feet,
        // never on its body; the whole patch melts away in 7 seconds.
        if (!docHidden && now > (w.trailAt || 0)) {
          w.trailAt = now + 750 + Math.random() * 450; // airier cadence
          const n = 1 + Math.floor(Math.random() * 10);
          const cx = w.x + 14, cy = w.y + 34; // strictly below the sprite
          if (w.starTrail) { // the pointer family walks on GLOWING stardust —
            // nine nebula colorways, two star shapes, each twinkling on its
            // own clock. APEX adds big stars + soft pixel nebula puffs (v162)
            const deep = w.starNebula;
            w.trailAt = now + 700 + Math.random() * 450; // dense, but paint-friendly (v187)
            for (let k = 0; k < (deep ? 2 : 1) + Math.floor(Math.random() * 2); k++) {
              const si = Math.floor(Math.random() * 18);
              const s = document.createElement('img');
              s.className = 'pik-trail pik-star-trail';
              s.src = trailStarSprite(si);
              s.alt = '';
              const sz = (deep && Math.random() < 0.22) ? 17 + Math.random() * 7 : 8 + Math.random() * 8;
              s.style.width = sz + 'px';
              s.style.setProperty('--star-glow', trailStarGlow(si));
              s.style.setProperty('--tw', (1.1 + Math.random() * 1.6).toFixed(2) + 's');
              s.style.setProperty('--twd', (-Math.random() * 2).toFixed(2) + 's');
              s.style.left = (cx + Math.random() * 28 - 14 - sz / 2) + 'px';
              s.style.top = (cy + Math.random() * 8) + 'px';
              DESK_PIK.layer.appendChild(s);
              setTimeout(() => s.classList.add('fading'), 6500);
              setTimeout(() => s.remove(), 8000);
            }
            // stardust: tiny glowing motes scattered between the stars
            for (let k = 0; k < 1 + Math.floor(Math.random() * (deep ? 2 : 1)); k++) {
              const gi = Math.floor(Math.random() * 9);
              const d = document.createElement('span');
              d.className = 'pik-trail pik-star-dust';
              d.style.background = trailStarGlow(gi);
              d.style.setProperty('--star-glow', trailStarGlow(gi));
              d.style.setProperty('--tw', (0.9 + Math.random() * 1.4).toFixed(2) + 's');
              d.style.setProperty('--twd', (-Math.random() * 2).toFixed(2) + 's');
              d.style.left = (cx + Math.random() * 36 - 18) + 'px';
              d.style.top = (cy - 2 + Math.random() * 12) + 'px';
              DESK_PIK.layer.appendChild(d);
              setTimeout(() => d.classList.add('fading'), 9000);
              setTimeout(() => d.remove(), 8000);
            }
            // APEX only: soft pixel nebula puffs — the "cloud" in star-cloud
            if (deep && Math.random() < 0.5) {
              const p = document.createElement('img');
              p.className = 'pik-trail pik-neb-puff';
              p.src = trailNebPuffSprite(Math.floor(Math.random() * 3));
              p.alt = '';
              const pw = 22 + Math.random() * 14;
              p.style.width = pw + 'px';
              p.style.setProperty('--star-glow', ['#c9a7f5', '#ff8fc7', '#41e0ff'][Math.floor(Math.random() * 3)]);
              p.style.left = (cx + Math.random() * 30 - 15 - pw / 2) + 'px';
              p.style.top = (cy - 2 + Math.random() * 10) + 'px';
              DESK_PIK.layer.appendChild(p);
              setTimeout(() => p.classList.add('fading'), 7000);
              setTimeout(() => p.remove(), 8600);
            }
            const trailsS = DESK_PIK.layer.querySelectorAll('.pik-trail');
            for (let k = 0; k < trailsS.length - 70; k++) trailsS[k].remove();
            return;
          }
          if (w.sp && w.sp.id === 'captcha' && w.disguised >= 0 && PIK_DISGUISES[w.disguised]) {
            // in costume, the trail commits to the bit: whatever THAT
            // creature would leave — paw prints, bird feet, slime, wisps
            const a = PIK_DISGUISES[w.disguised];
            const tr = a.tr || ['paw', '#c8b8a8'];
            if (tr[0] === 'slime') w.trailAt = now + 340 + Math.random() * 200; // snails do not do gaps
            if (tr[0] === 'spark') { // the unicorn leaves stardust. obviously.
              for (let k = 0; k < 2; k++) {
                const si = Math.floor(Math.random() * 18);
                const s = document.createElement('img');
                s.className = 'pik-trail pik-star-trail';
                s.src = trailStarSprite(si);
                s.alt = '';
                s.style.width = (8 + Math.random() * 7) + 'px';
                s.style.setProperty('--star-glow', trailStarGlow(si));
                s.style.left = (cx + Math.random() * 22 - 11) + 'px';
                s.style.top = (cy + Math.random() * 8) + 'px';
                DESK_PIK.layer.appendChild(s);
                setTimeout(() => s.classList.add('fading'), 6500);
                setTimeout(() => s.remove(), 8000);
              }
            } else {
              w.trackFlip = !w.trackFlip; // left paw, right paw, left paw
              const s = document.createElement('img');
              const wet = tr[0] === 'drop' || tr[0] === 'slime' || tr[0] === 'wisp';
              s.className = 'pik-trail pik-track' + (wet ? ' pik-track-wet' : '') + (tr[0] === 'daisy' ? ' pik-track-daisy' : '');
              if (wet) s.style.setProperty('--track-glow', tr[1]);
              if (tr[0] === 'daisy') { // every daisy spins at its own pace
                s.style.animationDuration = (2.4 + Math.random() * 2).toFixed(2) + 's';
                s.style.animationDirection = w.trackFlip ? 'reverse' : 'normal';
              }
              s.src = pikTrackSprite(tr[0], tr[1]);
              s.alt = '';
              s.style.width = ({ paw: 10, bird: 10, drop: 8, wisp: 12, dash: 13, slime: 9, daisy: 13 })[tr[0]] + 'px';
              s.style.left = (cx + (w.trackFlip ? -6 : 2)) + 'px';
              s.style.top = (cy + Math.random() * 6) + 'px';
              DESK_PIK.layer.appendChild(s);
              const life = tr[0] === 'wisp' ? 2600 : 6500; // ectoplasm evaporates
              setTimeout(() => s.classList.add('fading'), life);
              setTimeout(() => s.remove(), life + 1500);
            }
            const trailsT = DESK_PIK.layer.querySelectorAll('.pik-trail');
            for (let k = 0; k < trailsT.length - 70; k++) trailsT[k].remove();
            return;
          }
          if (w.partyMax) { // the APEX celebration walks WITH it: a confetti wake
            for (let k = 0; k < 2 + Math.floor(Math.random() * 4); k++) {
              const s = document.createElement('span');
              s.className = 'pik-trail pik-party-trail';
              s.style.background = PIK_PARTY_COLORS[Math.floor(Math.random() * PIK_PARTY_COLORS.length)];
              s.style.left = (cx + Math.random() * 26 - 13) + 'px';
              s.style.top = (cy + Math.random() * 10) + 'px';
              s.style.transform = 'rotate(' + Math.floor(Math.random() * 90) + 'deg)';
              DESK_PIK.layer.appendChild(s);
              setTimeout(() => s.classList.add('fading'), 6500);
              setTimeout(() => s.remove(), 8000);
            }
            const trailsP = DESK_PIK.layer.querySelectorAll('.pik-trail');
            for (let k = 0; k < trailsP.length - 70; k++) trailsP[k].remove();
            return;
          }
          const posyR = n > 2 ? 15 + n * 3 : 0; // roomy, breathable posies
          for (let k = 0; k < n; k++) {
            const f = document.createElement('img');
            f.className = 'pik-trail';
            f.src = trailBloomSprite(Math.floor(Math.random() * 6));
            f.alt = '';
            const size = 12 + Math.random() * 18; // 12-30px — generous blooms
            f.style.width = size + 'px';
            let ox = Math.random() * 26 - 13;
            let oy = Math.random() * 10;
            if (n > 2) { // round posy, loosely fanned below the feet
              const ang = (k / n) * 6.283 + Math.random() * 0.5;
              const rr = posyR * (0.45 + Math.random() * 0.55);
              ox = Math.cos(ang) * rr;
              oy = Math.abs(Math.sin(ang)) * rr * 0.9;
            }
            f.style.left = (cx + ox - size / 2) + 'px';
            f.style.top = (cy + oy) + 'px';
            DESK_PIK.layer.appendChild(f);
            setTimeout(() => f.classList.add('fading'), 6500);
            setTimeout(() => f.remove(), 8000);
          }
          const trails = DESK_PIK.layer.querySelectorAll('.pik-trail');
          for (let k = 0; k < trails.length - 70; k++) trails[k].remove(); // tidy meadow
        }
      }
    });
  }

