    let heroAt = cageMs + 500 + 3200;
    for (let bi = 0; bi < VILLAIN.length - 1; bi++) heroAt += estType(VILLAIN[bi], BEAT_MS[bi]) + HOLD;
    // …THE HERO ARRIVES — equally huge, from above, in a column of light ------
