      setTimeout(() => flash.remove(), 700);
      document.body.classList.add('rescue-quake');
      setTimeout(() => document.body.classList.remove('rescue-quake'), 600);
      playFanfare();
      // ✦✦✦ THE ULTIMATE — SLIME-GOD OVERDRIVE: chained, never rushed —
